const express = require('express');
const path = require('path');
const cors = require('cors');

const app = express();
const PORT = process.env.PORT || 3000;

// Enable CORS for all origins
app.use(cors({
  origin: '*',
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization', 'Accept'],
  credentials: false
}));

// Parse JSON bodies
app.use(express.json());

// Serve static files from dist/public with proper MIME types
app.use(express.static(path.join(__dirname, 'dist/public'), {
  setHeaders: (res, filePath) => {
    if (filePath.endsWith('.css')) {
      res.setHeader('Content-Type', 'text/css');
    } else if (filePath.endsWith('.js')) {
      res.setHeader('Content-Type', 'application/javascript');
    } else if (filePath.endsWith('.png')) {
      res.setHeader('Content-Type', 'image/png');
    } else if (filePath.endsWith('.jpg') || filePath.endsWith('.jpeg')) {
      res.setHeader('Content-Type', 'image/jpeg');
    }
    res.setHeader('Cache-Control', 'public, max-age=31536000');
  }
}));

// Simple OTP storage for production deployment
const otpStore = new Map();

// API Routes
app.post('/api/auth/send-otp', async (req, res) => {
  try {
    const { phone } = req.body;
    console.log('📱 Send OTP request for phone:', phone);

    if (!phone) {
      return res.status(400).json({
        success: false,
        message: 'Phone number is required'
      });
    }

    // Generate OTP
    const otp = Math.floor(100000 + Math.random() * 900000).toString();
    const expiresAt = Date.now() + 5 * 60 * 1000; // 5 minutes

    // Store OTP
    otpStore.set(phone, { otp, expiresAt });

    console.log(`📱 Generated OTP for ${phone}: ${otp}`);

    res.json({
      success: true,
      message: `OTP sent successfully to ${phone}. For development: ${otp}`,
      data: { phone }
    });
  } catch (error) {
    console.error('Send OTP error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to send OTP'
    });
  }
});

app.post('/api/auth/verify-otp', async (req, res) => {
  try {
    const { phone, otp } = req.body;
    console.log('🔐 Verify OTP request:', { phone, otp });

    if (!phone || !otp) {
      return res.status(400).json({
        success: false,
        message: 'Phone number and OTP are required'
      });
    }

    const storedOtp = otpStore.get(phone);
    if (!storedOtp) {
      return res.status(400).json({
        success: false,
        message: 'OTP not found or expired'
      });
    }

    if (Date.now() > storedOtp.expiresAt) {
      otpStore.delete(phone);
      return res.status(400).json({
        success: false,
        message: 'OTP expired'
      });
    }

    if (storedOtp.otp !== otp) {
      return res.status(400).json({
        success: false,
        message: 'Invalid OTP'
      });
    }

    // Remove used OTP
    otpStore.delete(phone);

    // Generate mock tokens
    const accessToken = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.' + 
                       Buffer.from(JSON.stringify({
                         id: `user_${Date.now()}`,
                         phone: phone,
                         userType: 'customer',
                         exp: Math.floor(Date.now() / 1000) + (24 * 60 * 60) // 24 hours
                       })).toString('base64') + '.signature';

    const refreshToken = 'refresh_' + Date.now();

    console.log('✅ OTP verified successfully for:', phone);

    res.json({
      success: true,
      message: 'Login successful',
      user: {
        id: `user_${Date.now()}`,
        phone: phone,
        userType: 'customer',
        isVerified: true,
        firstName: null,
        lastName: null
      },
      tokens: {
        accessToken,
        refreshToken
      }
    });
  } catch (error) {
    console.error('Verify OTP error:', error);
    res.status(500).json({
      success: false,
      message: 'OTP verification failed'
    });
  }
});

// Mock user endpoint for authentication check
app.get('/api/auth/user', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      success: false,
      message: 'No token provided'
    });
  }

  const token = authHeader.split(' ')[1];
  try {
    // Simple token validation (in production, use proper JWT verification)
    const payload = JSON.parse(Buffer.from(token.split('.')[1], 'base64').toString());

    res.json({
      success: true,
      user: {
        id: payload.id,
        phone: payload.phone,
        userType: payload.userType,
        isVerified: true,
        firstName: null,
        lastName: null
      }
    });
  } catch (error) {
    res.status(401).json({
      success: false,
      message: 'Invalid token'
    });
  }
});

// Handle all other routes - serve index.html for SPA routing
app.get('*', (req, res) => {
  if (req.path.startsWith('/api/')) {
    return res.status(404).json({
      success: false,
      message: 'API endpoint not found'
    });
  }

  res.sendFile(path.join(__dirname, 'dist/public/index.html'), (err) => {
    if (err) {
      console.error('Error serving index.html:', err);
      res.status(500).send('Error loading application');
    }
  });
});

// Error handling middleware
app.use((error, req, res, next) => {
  console.error('Server error:', error);
  res.status(500).json({
    success: false,
    message: 'Internal server error'
  });
});

app.listen(PORT, '0.0.0.0', () => {
  console.log('🚀 DOOODHWALA Production Server running on port', PORT);
  console.log('📱 Ready to handle authentication and serve static assets');
});

