#!/usr/bin/env node

import express from 'express';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';

// ES module setup
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

console.log('🚀 DOOODHWALA Production Deployment Server');
console.log('📦 Optimized for Replit deployment with proper asset serving');

const app = express();
const PORT = process.env.PORT || 5000;

// Production static file serving
const publicPath = path.resolve(__dirname, 'dist', 'public');
console.log(`📁 Static files: ${publicPath}`);

if (!fs.existsSync(publicPath)) {
  console.error('❌ Build files not found. Run: npm run build');
  process.exit(1);
}

// List available assets
const assetsPath = path.join(publicPath, 'assets');
if (fs.existsSync(assetsPath)) {
  const assets = fs.readdirSync(assetsPath);
  console.log(`📦 Assets: ${assets.join(', ')}`);
}

// PRIORITY: Asset serving with correct MIME types
app.get('/assets/:filename', (req, res) => {
  const { filename } = req.params;
  const filePath = path.join(assetsPath, filename);

  if (!fs.existsSync(filePath)) {
    return res.status(404).json({ error: `Asset ${filename} not found` });
  }

  const ext = path.extname(filename);

  // Explicit MIME type mapping
  const mimeTypes = {
    '.js': 'application/javascript; charset=utf-8',
    '.css': 'text/css; charset=utf-8',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.svg': 'image/svg+xml',
    '.woff': 'font/woff',
    '.woff2': 'font/woff2'
  };

  const mimeType = mimeTypes[ext] || 'application/octet-stream';

  res.setHeader('Content-Type', mimeType);
  res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');

  console.log(`✅ ${filename} -> ${mimeType}`);

  res.sendFile(filePath);
});

// Health check
app.get('/health', (req, res) => {
  res.json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    server: 'production-deploy-server',
    assets: fs.existsSync(assetsPath) ? fs.readdirSync(assetsPath).length : 0
  });
});

// Static files (favicon, etc.)
app.use(express.static(publicPath, { index: false }));

// SPA fallback
app.get('*', (req, res) => {
  const indexPath = path.join(publicPath, 'index.html');

  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.setHeader('Cache-Control', 'no-cache');

  res.sendFile(indexPath);
});

app.listen(PORT, '0.0.0.0', () => {
  console.log(`🌐 Server running: http://localhost:${PORT}`);
  console.log(`💚 Health check: http://localhost:${PORT}/health`);
  console.log('🎯 Ready for deployment!');
});

