// Deployment Verification Script for DOOODHWALA
const LOCAL_BUILD_FILE = 'index-NYG_17Ci.js';
const DEPLOYMENT_URL = 'https://dairy-connect-siddhantsancheti.replit.app';

console.log('🔍 Checking DOOODHWALA deployment status...');

// Check deployment HTML
fetch(DEPLOYMENT_URL)
  .then(response => response.text())
  .then(html => {
    const jsMatch = html.match(/assets\/(index-[a-zA-Z0-9_-]+\.js)/);
    const deployedFile = jsMatch ? jsMatch[1] : 'Not found';

    console.log(`📂 Local build: ${LOCAL_BUILD_FILE}`);
    console.log(`🌐 Deployed file: ${deployedFile}`);

    if (deployedFile === LOCAL_BUILD_FILE) {
      console.log('✅ Deployment is up to date!');

      // Test if new file works
      return fetch(`${DEPLOYMENT_URL}/assets/${deployedFile}`)
        .then(response => {
          if (response.ok) {
            console.log('✅ New build file accessible');
            console.log('🎉 White page issue should be resolved!');

            // Test Firebase integration
            return response.text().then(jsContent => {
              if (jsContent.includes('Firebase') && jsContent.includes('analytics')) {
                console.log('✅ Firebase Analytics integrated');
              }
              if (jsContent.includes('DOODHWALA')) {
                console.log('✅ Debug logging active');
              }
            });
          } else {
            console.log('❌ New build file not accessible');
          }
        });
    } else {
      console.log('⚠️ Deployment cache needs refresh');
      console.log('   Click Deploy button to update deployment');
    }
  })
  .catch(error => {
    console.log('❌ Error checking deployment:', error.message);
  });

