#!/usr/bin/env node

// DOOODHWALA Complete Production Server
// Serves both frontend assets AND backend API routes

import express from 'express';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

console.log('🚀 DOOODHWALA Full Production Server Starting...');
console.log('🔧 Environment: PRODUCTION');

const app = express();
const PORT = process.env.PORT || 5000;

// Set production environment
process.env.NODE_ENV = 'production';
app.set('trust proxy', 1);

// Production paths - when running from dist/index.js, we're already in the right place
const publicPath = path.resolve(__dirname, 'public');
const assetsPath = path.join(publicPath, 'assets');
const backendScript = path.resolve(__dirname, 'index-original.js');

console.log(`📁 Frontend: ${publicPath}`);
console.log(`📦 Assets: ${assetsPath}`);
console.log(`⚙️  Backend: ${backendScript}`);

// Verify paths exist
const checks = {
  frontend: fs.existsSync(publicPath),
  assets: fs.existsSync(assetsPath),
  backend: fs.existsSync(backendScript)
};

console.log('✅ Path checks:', checks);

if (checks.assets) {
  const assets = fs.readdirSync(assetsPath);
  console.log(`📦 Assets available (${assets.length}):`, assets.slice(0, 3).join(', ') + (assets.length > 3 ? '...' : ''));
}

// STEP 1: Serve static assets with correct MIME types
app.use('/assets', express.static(assetsPath, {
  maxAge: '1y',
  immutable: true,
  setHeaders: (res, filePath) => {
    const ext = path.extname(filePath).toLowerCase();
    const mimeTypes = {
      '.js': 'application/javascript; charset=utf-8',
      '.css': 'text/css; charset=utf-8',
      '.png': 'image/png',
      '.jpg': 'image/jpeg',
      '.svg': 'image/svg+xml',
      '.woff2': 'font/woff2',
    };

    if (mimeTypes[ext]) {
      res.setHeader('Content-Type', mimeTypes[ext]);
      console.log(`📦 Served asset: ${path.basename(filePath)} as ${mimeTypes[ext]}`);
    }
  }
}));

// STEP 2: Try to load and run the backend API
let backendLoaded = false;

if (checks.backend) {
  try {
    console.log('⚙️  Loading backend API...');

    // Dynamic import of the compiled backend
    const startBackend = async () => {
      try {
        await import('./dist/index.js');
        backendLoaded = true;
        console.log('✅ Backend API loaded successfully');
      } catch (error) {
        console.error('❌ Backend loading failed:', error.message);
        setupFallbackRoutes();
      }
    };

    startBackend();

  } catch (error) {
    console.error('❌ Backend import failed:', error.message);
    setupFallbackRoutes();
  }
} else {
  console.log('⚠️  Backend not found, setting up fallback');
  setupFallbackRoutes();
}

// STEP 3: Fallback routes if backend doesn't load
function setupFallbackRoutes() {
  // Health check
  app.get('/health', (req, res) => {
    res.json({
      status: 'partial',
      timestamp: new Date().toISOString(),
      mode: 'frontend-only',
      backend: backendLoaded ? 'loaded' : 'unavailable'
    });
  });

  // API fallback
  app.use('/api/*', (req, res) => {
    res.status(503).json({
      error: 'Backend API temporarily unavailable',
      message: 'Services are initializing'
    });
  });

  console.log('⚠️  Fallback API routes configured');
}

// STEP 4: Serve the React SPA
app.use(express.static(publicPath, { index: false }));

app.get('*', (req, res) => {
  // Skip API routes
  if (req.path.startsWith('/api/') || req.path.startsWith('/assets/')) {
    return res.status(404).json({ error: 'Not found' });
  }

  const indexPath = path.join(publicPath, 'index.html');
  res.sendFile(indexPath);
});

// STEP 5: Start the server
const server = app.listen(PORT, '0.0.0.0', () => {
  console.log(`🌐 DOOODHWALA Production: http://localhost:${PORT}`);
  console.log(`💚 Health check: http://localhost:${PORT}/health`);
  console.log('✅ Production server ready!');
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('👋 Shutting down gracefully...');
  server.close(() => {
    console.log('✅ Server closed');
    process.exit(0);
  });
});

