#!/usr/bin/env node

// Full-stack production deployment server
// Combines backend API with optimized static asset serving

import express from 'express';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';

// ES module setup
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

console.log('🚀 DOOODHWALA Full Production Server');
console.log('📦 Loading backend API + static assets...');

const app = express();
const PORT = process.env.PORT || 5000;

// Set production environment
process.env.NODE_ENV = 'production';

// Trust proxy for Replit
app.set('trust proxy', 1);

// Production paths
const publicPath = path.resolve(__dirname, 'dist', 'public');
const assetsPath = path.join(publicPath, 'assets');

console.log(`📁 Static assets path: ${assetsPath}`);
console.log(`✓ Assets available: ${fs.existsSync(assetsPath)}`);

if (fs.existsSync(assetsPath)) {
  const assets = fs.readdirSync(assetsPath);
  console.log(`📦 Asset files (${assets.length}):`, assets.join(', '));
}

// PRIORITY 1: Static asset serving with proper MIME types
app.get('/assets/:filename', (req, res) => {
  const { filename } = req.params;
  const filePath = path.join(assetsPath, filename);

  console.log(`🎯 Asset: /assets/${filename}`);

  if (!fs.existsSync(filePath)) {
    console.log(`❌ Asset not found: ${filename}`);
    return res.status(404).json({ error: 'Asset not found' });
  }

  const ext = path.extname(filename).toLowerCase();
  const mimeTypes = {
    '.js': 'application/javascript; charset=utf-8',
    '.css': 'text/css; charset=utf-8',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.svg': 'image/svg+xml'
  };

  const mimeType = mimeTypes[ext] || 'application/octet-stream';
  res.setHeader('Content-Type', mimeType);
  res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');

  console.log(`✅ Serving ${filename} as ${mimeType}`);
  res.sendFile(filePath);
});

// PRIORITY 2: Import and run the compiled backend with API routes
console.log('📡 Loading API routes from compiled backend...');

try {
  // Import the compiled backend
  const { default: compiledBackend } = await import('./dist/index.js');
  console.log('✅ Backend API loaded successfully');
} catch (error) {
  console.error('❌ Failed to load backend API:', error.message);

  // Fallback: Basic health check if backend fails
  app.get('/health', (req, res) => {
    res.json({
      status: 'partial',
      timestamp: new Date().toISOString(),
      mode: 'static-only',
      message: 'Frontend assets available, backend API unavailable'
    });
  });

  // Fallback: Serve static files and SPA
  app.use(express.static(publicPath, { index: false }));

  app.get('*', (req, res) => {
    if (req.path.startsWith('/api/')) {
      return res.status(503).json({ 
        error: 'API temporarily unavailable',
        message: 'Backend services are initializing'
      });
    }

    const indexPath = path.join(publicPath, 'index.html');
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.sendFile(indexPath);
  });

  console.log('⚠️  Running in static-only fallback mode');
}

// Start server
app.listen(PORT, '0.0.0.0', () => {
  console.log(`🌐 Production server running: http://localhost:${PORT}`);
  console.log(`💚 Health check: http://localhost:${PORT}/health`);
  console.log('✅ Full-stack deployment ready!');
});

