#!/usr/bin/env node

import express from 'express';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';

// ES module setup
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = process.env.PORT || 5000;

console.log('🚀 DOOODHWALA Production Server Starting...');
console.log('📦 Environment: PRODUCTION');
console.log(`🌐 Port: ${PORT}`);

// Production build path
const publicPath = path.resolve(__dirname, 'dist', 'public');
const assetsPath = path.join(publicPath, 'assets');

console.log(`📁 Public path: ${publicPath}`);
console.log(`📦 Assets path: ${assetsPath}`);
console.log(`✓ Public exists: ${fs.existsSync(publicPath)}`);
console.log(`✓ Assets exists: ${fs.existsSync(assetsPath)}`);

// Check if build exists
if (!fs.existsSync(publicPath)) {
  console.error('❌ Production build not found at:', publicPath);
  console.error('👉 Run: npm run build');
  process.exit(1);
}

// List available assets for debugging
if (fs.existsSync(assetsPath)) {
  const assets = fs.readdirSync(assetsPath);
  console.log(`📦 Available assets (${assets.length}):`, assets.join(', '));
} else {
  console.warn('⚠️  No assets directory found');
}

// Trust proxy for Replit
app.set('trust proxy', 1);

// PRIORITY 1: Asset serving with explicit MIME types
app.get('/assets/:filename', (req, res) => {
  const { filename } = req.params;
  const filePath = path.join(assetsPath, filename);

  console.log(`🎯 Asset request: /assets/${filename}`);
  console.log(`🔍 Looking for: ${filePath}`);

  if (!fs.existsSync(filePath)) {
    console.log(`❌ Asset not found: ${filename}`);
    return res.status(404).json({ error: `Asset ${filename} not found` });
  }

  const ext = path.extname(filename).toLowerCase();

  // Explicit MIME type mapping
  const mimeTypes = {
    '.js': 'application/javascript; charset=utf-8',
    '.css': 'text/css; charset=utf-8',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.svg': 'image/svg+xml',
    '.woff': 'font/woff',
    '.woff2': 'font/woff2',
    '.ico': 'image/x-icon'
  };

  const mimeType = mimeTypes[ext] || 'application/octet-stream';

  res.setHeader('Content-Type', mimeType);
  res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');

  console.log(`✅ Serving ${filename} as ${mimeType}`);

  res.sendFile(filePath, (err) => {
    if (err) {
      console.error(`❌ Error serving ${filename}:`, err.message);
      res.status(500).json({ error: 'Asset serving error' });
    }
  });
});

// PRIORITY 2: Health check
app.get('/health', (req, res) => {
  const health = {
    status: 'healthy',
    timestamp: new Date().toISOString(),
    server: 'production',
    build: fs.existsSync(publicPath),
    assets: fs.existsSync(assetsPath) ? fs.readdirSync(assetsPath).length : 0,
    environment: 'production'
  };

  console.log('🏥 Health check:', health);
  res.json(health);
});

// PRIORITY 3: Static file serving
app.use(express.static(publicPath, {
  index: false,
  maxAge: '1d',
  setHeaders: (res, filePath) => {
    const ext = path.extname(filePath).toLowerCase();

    if (ext === '.css') {
      res.setHeader('Content-Type', 'text/css; charset=utf-8');
    } else if (ext === '.js') {
      res.setHeader('Content-Type', 'application/javascript; charset=utf-8');
    } else if (ext === '.png') {
      res.setHeader('Content-Type', 'image/png');
    } else if (ext === '.jpg' || ext === '.jpeg') {
      res.setHeader('Content-Type', 'image/jpeg');
    }

    console.log(`📄 Static: ${path.basename(filePath)} -> ${res.getHeader('Content-Type')}`);
  }
}));

// PRIORITY 4: SPA fallback
app.get('*', (req, res) => {
  const indexPath = path.join(publicPath, 'index.html');

  console.log(`🏠 SPA fallback for: ${req.path}`);

  if (!fs.existsSync(indexPath)) {
    console.error(`❌ Index.html not found: ${indexPath}`);
    return res.status(500).send('Application not built properly');
  }

  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate');

  res.sendFile(indexPath, (err) => {
    if (err) {
      console.error('❌ Error serving index.html:', err.message);
      res.status(500).send('Internal Server Error');
    }
  });
});

// Error handling
app.use((error, req, res, next) => {
  console.error('💥 Server error:', error.message);
  res.status(500).json({
    error: 'Internal Server Error',
    message: process.env.NODE_ENV === 'development' ? error.message : 'Something went wrong'
  });
});

// Start server
app.listen(PORT, '0.0.0.0', () => {
  console.log(`🌐 Server running at: http://localhost:${PORT}`);
  console.log(`💚 Health check: http://localhost:${PORT}/health`);
  console.log(`🎯 Assets endpoint: http://localhost:${PORT}/assets/[filename]`);
  console.log('✅ Production server ready!');
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('🛑 SIGTERM received, shutting down gracefully...');
  process.exit(0);
});

process.on('SIGINT', () => {
  console.log('🛑 SIGINT received, shutting down gracefully...');
  process.exit(0);
});

