import express from 'express';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';

// ES module setup
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = process.env.PORT || 5000;

// Parse JSON bodies for API routes
app.use(express.json());

// Import and register API routes first
import('./dist/index.js')
  .then((module) => {
    // The compiled server exports should be available here
    console.log('✅ API routes loaded from dist/index.js');
  })
  .catch((err) => {
    console.log('ℹ️  Running in static-only mode:', err.message);
  });

// Production static file serving for Replit
const publicPath = path.resolve(__dirname, 'dist', 'public');

console.log(`📁 Serving static files from: ${publicPath}`);
console.log(`📁 Directory exists: ${fs.existsSync(publicPath)}`);

if (!fs.existsSync(publicPath)) {
  console.error(`❌ Build directory not found. Run 'npm run build' first.`);
  process.exit(1);
}

// List available assets
const assetsPath = path.join(publicPath, 'assets');
if (fs.existsSync(assetsPath)) {
  const assets = fs.readdirSync(assetsPath);
  console.log(`📦 Available assets:`, assets);
}

// CRITICAL: Serve assets with explicit MIME types FIRST
app.get('/assets/:filename', (req, res) => {
  const filename = req.params.filename;
  const filePath = path.join(assetsPath, filename);

  console.log(`🎯 Asset request: ${filename}`);

  if (!fs.existsSync(filePath)) {
    console.log(`❌ Asset not found: ${filename}`);
    return res.status(404).json({ error: 'Asset not found' });
  }

  const ext = path.extname(filename).toLowerCase();

  // Set explicit MIME types to prevent JSON responses
  switch (ext) {
    case '.js':
      res.setHeader('Content-Type', 'application/javascript; charset=utf-8');
      break;
    case '.css':
      res.setHeader('Content-Type', 'text/css; charset=utf-8');
      break;
    case '.png':
      res.setHeader('Content-Type', 'image/png');
      break;
    case '.jpg':
    case '.jpeg':
      res.setHeader('Content-Type', 'image/jpeg');
      break;
    case '.svg':
      res.setHeader('Content-Type', 'image/svg+xml');
      break;
    default:
      res.setHeader('Content-Type', 'application/octet-stream');
  }

  // Cache headers for assets
  res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');
  res.setHeader('ETag', `"${filename}"`);

  console.log(`✅ Serving ${filename} as ${res.getHeader('Content-Type')}`);

  // Send the actual file
  res.sendFile(filePath);
});

// Health check
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

// Serve other static files (favicon, etc.)
app.use(express.static(publicPath, {
  index: false, // Don't auto-serve index.html
  maxAge: '1d'
}));

// SPA fallback - MUST be last
app.get('*', (req, res) => {
  const indexPath = path.join(publicPath, 'index.html');

  console.log(`🏠 SPA route: ${req.path}`);

  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.setHeader('Cache-Control', 'no-cache');
  res.sendFile(indexPath);
});

app.listen(PORT, '0.0.0.0', () => {
  console.log(`🚀 DOOODHWALA server running on port ${PORT}`);
  console.log(`🌐 Visit: http://localhost:${PORT}`);
});

