#!/usr/bin/env node
// Test deployment verification script for DOOODHWALA

import https from 'https';

const deployedUrl = 'https://dairy-connect-siddhantsancheti.replit.app/';

console.log('🥛 DOOODHWALA Deployment Test');
console.log('==============================');

// Check deployed HTML
https.get(deployedUrl, (res) => {
  let data = '';

  res.on('data', (chunk) => {
    data += chunk;
  });

  res.on('end', () => {
    console.log('\n📄 Deployed HTML Analysis:');
    console.log('Status Code:', res.statusCode);

    // Extract JS and CSS asset references
    const jsAssets = data.match(/assets\/index-[^"']*\.js/g) || [];
    const cssAssets = data.match(/assets\/index-[^"']*\.css/g) || [];

    console.log('\n🔍 Asset References in Deployed HTML:');
    console.log('JavaScript:', jsAssets);
    console.log('CSS:', cssAssets);

    // Check if it matches our current build
    const currentJS = 'assets/index-Dh8y62a_.js';
    const currentCSS = 'assets/index-CO3VBd_1.css';

    const isJSCorrect = jsAssets.some(asset => asset.includes('Dh8y62a_'));
    const isCSSCorrect = cssAssets.some(asset => asset.includes('CO3VBd_1'));

    console.log('\n✅ Asset Verification:');
    console.log('JavaScript matches current build:', isJSCorrect ? '✅ YES' : '❌ NO (CACHE ISSUE)');
    console.log('CSS matches current build:', isCSSCorrect ? '✅ YES' : '❌ NO (CACHE ISSUE)');

    if (!isJSCorrect || !isCSSCorrect) {
      console.log('\n🚨 DEPLOYMENT CACHE ISSUE CONFIRMED');
      console.log('The deployed HTML is serving cached references to old asset files.');
      console.log('Solution: Click "Deploy" button in Replit to force fresh deployment.');
    } else {
      console.log('\n🎉 DEPLOYMENT ASSETS ARE CORRECT');
      console.log('The issue might be elsewhere. Check browser console for errors.');
    }

    // Check if HTML contains root element
    const hasRoot = data.includes('<div id="root">');
    console.log('HTML has root element:', hasRoot ? '✅ YES' : '❌ NO');

    // Check for Firebase config
    const hasFirebase = data.includes('firebase') || data.includes('Firebase');
    console.log('Contains Firebase references:', hasFirebase ? '✅ YES' : '❌ NO');

    console.log('\n🔧 Next Steps:');
    if (!isJSCorrect || !isCSSCorrect) {
      console.log('1. Click the "Deploy" button in Replit workspace');
      console.log('2. Wait for deployment to complete');
      console.log('3. Hard refresh the browser (Ctrl+F5)');
      console.log('4. Check the deployed site again');
    } else {
      console.log('1. Check browser developer console for JavaScript errors');
      console.log('2. Verify network tab shows successful asset loading');
      console.log('3. Test in incognito mode to avoid local cache');
    }
  });
}).on('error', (err) => {
  console.error('Error fetching deployed page:', err.message);
});

