import { Router } from 'express';
import { 
  generateTokens, 
  verifyToken, 
  verifyRefreshToken, 
  hashPassword, 
  verifyPassword, 
  validatePassword, 
  trackLoginAttempt, 
  requireAuth,
  authRateLimit,
  otpRateLimit,
  passwordResetRateLimit,
  AuthenticatedRequest
} from './middleware/auth';
import { 
  authValidation, 
  registerValidation,
  handleValidationErrors 
} from './middleware/validation';
import { SecurityLogger } from './middleware/logging';
import { storage } from './storage';
import crypto from 'crypto';

const router = Router();

// Generate OTP with logging
function generateOTP(): string {
  const otp = Math.floor(100000 + Math.random() * 900000).toString();
  console.log('🔢 Generated 6-digit OTP:', otp.substring(0, 2) + '****');
  return otp;
}

// SMS service function with detailed error logging
async function sendSMS(phone: string, message: string): Promise<boolean> {
  try {
    // Always log for debugging
    console.log(`📱 SMS to +91${phone}: ${message}`);

    // Check if Twilio credentials are available
    const accountSid = process.env.TWILIO_ACCOUNT_SID;
    const authToken = process.env.TWILIO_AUTH_TOKEN;
    const fromNumber = process.env.TWILIO_PHONE_NUMBER;

    console.log('Twilio credentials check:', {
      accountSid: accountSid ? 'SET' : 'MISSING',
      authToken: authToken ? 'SET' : 'MISSING', 
      fromNumber: fromNumber ? 'SET' : 'MISSING'
    });

    if (accountSid && authToken && fromNumber) {
      // Import Twilio dynamically
      const { default: twilio } = await import('twilio');
      const client = twilio(accountSid, authToken);

      // Format phone number properly
      const formattedPhone = phone.startsWith('+91') ? phone : `+91${phone}`;
      console.log(`Sending SMS via Twilio from ${fromNumber} to ${formattedPhone}`);

      const result = await client.messages.create({
        body: message,
        from: fromNumber,
        to: formattedPhone
      });

      console.log(`✅ SMS sent successfully via Twilio. Message SID: ${result.sid}`);
      return true;
    } else {
      console.log('⚠️ Twilio credentials not configured, SMS will be simulated');
      console.log(`SMS would be sent to ${phone}: ${message}`);
      return true; // Return true for development/testing
    }
  } catch (error: any) {
    console.error('❌ SMS sending failed:', {
      error: error.message,
      code: error.code,
      moreInfo: error.moreInfo,
      phone: phone,
      stack: error.stack
    });

    // In production, we might want to fail if SMS can't be sent
    // For now, return true to not block the OTP flow
    return process.env.NODE_ENV === 'development';
  }
}

// Send OTP endpoint with detailed error logging
router.post('/send-otp', otpRateLimit, authValidation, async (req: any, res: any) => {
  const startTime = Date.now();
  console.log('🔐 OTP Request received:', {
    body: req.body,
    headers: {
      'content-type': req.headers['content-type'],
      'user-agent': req.headers['user-agent']?.substring(0, 50)
    },
    ip: req.ip
  });

  try {
    const { phone } = req.body;

    // Validate phone number
    if (!phone) {
      console.log('❌ Missing phone number in request');
      return res.status(400).json({
        success: false,
        message: 'Phone number is required',
        error: 'MISSING_PHONE'
      });
    }

    // Clean and validate phone format
    const cleanPhone = phone.replace(/[^0-9]/g, '').replace(/^\+?91/, '');
    if (!/^[6-9][0-9]{9}$/.test(cleanPhone)) {
      console.log('❌ Invalid phone format:', { original: phone, cleaned: cleanPhone });
      return res.status(400).json({
        success: false,
        message: 'Invalid phone number format',
        error: 'INVALID_PHONE_FORMAT'
      });
    }

    console.log('✅ Phone validation passed:', { original: phone, cleaned: cleanPhone });

    // Generate and store OTP
    const otp = generateOTP();
    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 minutes

    console.log('🔢 Generated OTP:', { otp: otp, expiresAt: expiresAt.toISOString() });

    try {
      await storage.createOTP(cleanPhone, otp, expiresAt);
      console.log('✅ OTP stored in database successfully');
    } catch (storageError: any) {
      console.error('❌ Failed to store OTP in database:', {
        error: storageError.message,
        stack: storageError.stack,
        phone: cleanPhone
      });
      throw new Error(`Database storage failed: ${storageError.message}`);
    }

    // Send SMS
    const message = `Your DOOODHWALA verification code is: ${otp}. Valid for 5 minutes. Do not share with anyone.`;
    console.log('📱 Attempting to send SMS...');

    try {
      const smsResult = await sendSMS(cleanPhone, message);
      console.log('📱 SMS sending result:', smsResult);
    } catch (smsError: any) {
      console.error('❌ SMS sending failed:', {
        error: smsError.message,
        code: smsError.code,
        stack: smsError.stack
      });
      // Don't fail the request if SMS fails in development
      if (process.env.NODE_ENV === 'production') {
        throw new Error(`SMS delivery failed: ${smsError.message}`);
      }
    }

    // Log successful attempt
    try {
      SecurityLogger.logAuthAttempt(req, true, { 
        event: 'otp_sent', 
        phone: cleanPhone.substring(0, 6) + '****',
        duration: Date.now() - startTime
      });
    } catch (logError: any) {
      console.error('⚠️ Security logging failed:', logError.message);
    }

    const response = {
      success: true,
      message: 'OTP sent successfully',
      expiresIn: 300, // 5 minutes in seconds
      // Include OTP in development for testing
      ...(process.env.NODE_ENV === 'development' && { otp })
    };

    console.log('✅ OTP request completed successfully:', {
      duration: Date.now() - startTime + 'ms',
      phone: cleanPhone.substring(0, 6) + '****'
    });

    res.json(response);

  } catch (error: any) {
    const duration = Date.now() - startTime;
    console.error('❌ OTP request failed:', {
      error: error.message,
      stack: error.stack,
      duration: duration + 'ms',
      body: req.body,
      type: error.constructor.name
    });

    // Log failed attempt
    try {
      SecurityLogger.logAuthAttempt(req, false, { 
        event: 'otp_send_failed', 
        error: error.message,
        duration
      });
    } catch (logError: any) {
      console.error('⚠️ Security logging failed:', logError.message);
    }

    res.status(500).json({
      success: false,
      message: 'Failed to send OTP. Please try again.',
      error: process.env.NODE_ENV === 'development' ? error.message : 'INTERNAL_SERVER_ERROR',
      ...(process.env.NODE_ENV === 'development' && { 
        stack: error.stack,
        type: error.constructor.name
      })
    });
  }
});

// Verify OTP and login/register
router.post('/verify-otp', authRateLimit, authValidation, async (req: any, res: any) => {
  try {
    const { phone, otp } = req.body;

    // Track login attempt for rate limiting
    try {
      trackLoginAttempt(phone, false); // Pre-check for lockout
    } catch (lockoutError: any) {
      SecurityLogger.logAuthAttempt(req, false, { 
        event: 'account_locked', 
        phone: phone.substring(0, 6) + '****'
      });

      return res.status(429).json({
        success: false,
        message: lockoutError.message
      });
    }

    // Verify OTP
    const otpRecord = await storage.getValidOTP(phone, otp);
    if (!otpRecord) {
      trackLoginAttempt(phone, false);
      SecurityLogger.logAuthAttempt(req, false, { 
        event: 'invalid_otp', 
        phone: phone.substring(0, 6) + '****'
      });

      return res.status(400).json({
        success: false,
        message: 'Invalid or expired OTP'
      });
    }

    // Mark OTP as used
    await storage.markOTPAsUsed(otpRecord.id);

    // Check if user exists
    let user = await storage.getUserByPhone(phone);

    if (!user) {
      // Create new user without userType to trigger onboarding
      user = await storage.createUser({
        id: `user_${Date.now()}`,
        phone,
        isVerified: true,
        userType: null, // Let user choose during onboarding
      });

      SecurityLogger.logAuthAttempt(req, true, { 
        event: 'user_registered', 
        userId: user.id,
        phone: phone.substring(0, 6) + '****'
      });
    } else {
      // Update verification status
      if (!user.isVerified) {
        await storage.updateUser(user.id, { isVerified: true });
        user.isVerified = true;
      }

      SecurityLogger.logAuthAttempt(req, true, { 
        event: 'user_login', 
        userId: user.id,
        phone: phone.substring(0, 6) + '****'
      });
    }

    // Generate tokens
    const tokenPayload = {
      id: user.id,
      username: user.username,
      phone: user.phone,
      userType: user.userType,
      isVerified: user.isVerified,
    };

    const { accessToken, refreshToken } = generateTokens(tokenPayload);

    // Reset login attempts on success
    trackLoginAttempt(phone, true);

    res.json({
      success: true,
      message: user ? 'Login successful' : 'Registration successful',
      user: {
        id: user.id,
        username: user.username,
        phone: user.phone,
        userType: user.userType,
        isVerified: user.isVerified,
      },
      tokens: {
        accessToken,
        refreshToken,
        expiresIn: '7d'
      }
    });

  } catch (error: any) {
    SecurityLogger.logAuthAttempt(req, false, { 
      event: 'auth_error', 
      error: error.message 
    });

    res.status(500).json({
      success: false,
      message: 'Authentication failed. Please try again.',
      error: process.env.NODE_ENV === 'development' ? error.message : undefined
    });
  }
});

// Refresh token endpoint
router.post('/refresh-token', async (req, res) => {
  try {
    const { refreshToken } = req.body;

    if (!refreshToken) {
      return res.status(400).json({
        success: false,
        message: 'Refresh token is required'
      });
    }

    // Verify refresh token
    const decoded = verifyRefreshToken(refreshToken);

    // Check if user still exists and is active
    const user = await storage.getUser(decoded.id);
    if (!user || !user.isVerified) {
      return res.status(401).json({
        success: false,
        message: 'Invalid refresh token or user not found'
      });
    }

    // Generate new tokens
    const tokenPayload = {
      id: user.id,
      username: user.username,
      phone: user.phone,
      userType: user.userType,
      isVerified: user.isVerified,
    };

    const { accessToken, refreshToken: newRefreshToken } = generateTokens(tokenPayload);

    SecurityLogger.logAuthAttempt(req, true, { 
      event: 'token_refreshed', 
      userId: user.id 
    });

    res.json({
      success: true,
      tokens: {
        accessToken,
        refreshToken: newRefreshToken,
        expiresIn: '7d'
      }
    });

  } catch (error: any) {
    SecurityLogger.logAuthAttempt(req, false, { 
      event: 'token_refresh_failed', 
      error: error.message 
    });

    res.status(401).json({
      success: false,
      message: 'Invalid refresh token',
      error: process.env.NODE_ENV === 'development' ? error.message : undefined
    });
  }
});

// Get current user endpoint
router.get('/user', requireAuth, async (req: AuthenticatedRequest, res) => {
  try {
    console.log('GET /api/auth/user - req.user:', req.user);

    let user;

    // Try to get user by ID first
    if (req.user!.id) {
      user = await storage.getUser(req.user!.id);
      console.log('Retrieved user from database by ID:', user);
    }

    // If no user found by ID, try to find by phone number (fallback for JWT tokens without ID)
    if (!user && req.user!.phone) {
      console.log('User not found by ID, trying phone lookup for:', req.user!.phone);

      // Try both with and without +91 prefix
      const phoneWithoutPrefix = req.user!.phone.replace(/^\+91/, '');
      const phoneWithPrefix = req.user!.phone.startsWith('+91') ? req.user!.phone : `+91${req.user!.phone}`;

      // Try original format first
      user = await storage.getUserByPhone(req.user!.phone);

      // If not found, try with prefix
      if (!user && req.user!.phone !== phoneWithPrefix) {
        user = await storage.getUserByPhone(phoneWithPrefix);
      }

      // If still not found, try without prefix
      if (!user && req.user!.phone !== phoneWithoutPrefix) {
        user = await storage.getUserByPhone(phoneWithoutPrefix);
      }

      console.log('Retrieved user from database by phone:', user);
    }

    if (!user) {
      console.log('User not found in database for ID:', req.user!.id, 'or phone:', req.user!.phone);

      // If user authenticated successfully but doesn't exist in database, create them
      try {
        const userId = req.user!.id || req.user!.username || `user_${req.user!.phone}`;
        const formattedPhone = req.user!.phone.startsWith('+91') ? req.user!.phone : `+91${req.user!.phone}`;

        console.log(`Creating authenticated user: ${userId} with phone: ${formattedPhone}`);

        user = await storage.upsertUser({
          id: userId,
          phone: formattedPhone,
          userType: req.user!.userType || null, // Don't default to customer
          isVerified: req.user!.isVerified || true,
          username: req.user!.username
        });

        console.log('Created user successfully:', user);
      } catch (createError) {
        console.error('Error creating user:', createError);
        return res.status(500).json({
          success: false,
          message: 'Failed to create user profile'
        });
      }
    }

    res.json({
      success: true,
      user: {
        id: user.id,
        username: user.username,
        phone: user.phone,
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        userType: user.userType,
        isVerified: user.isVerified,
        createdAt: user.createdAt,
      }
    });

  } catch (error: any) {
    console.error('Error in GET /api/auth/user:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to fetch user information',
      error: process.env.NODE_ENV === 'development' ? error.message : undefined
    });
  }
});

// Logout endpoint
