// Update user type endpoint
router.put('/user-type', requireAuth, async (req: AuthenticatedRequest, res) => {
  try {
    const { userType } = req.body;

    // Validate user type
    if (!userType || !['customer', 'milkman'].includes(userType)) {
      return res.status(400).json({
        success: false,
        message: 'Invalid user type. Must be either "customer" or "milkman"'
      });
    }

    // Update user type
    const updatedUser = await storage.updateUser(req.user!.id, { userType });

    SecurityLogger.logAuthAttempt(req, true, { 
      event: 'user_type_updated', 
      userId: req.user!.id,
      newUserType: userType 
    });

    res.json({
      success: true,
      message: 'User type updated successfully',
      user: {
        id: updatedUser.id,
        username: updatedUser.username,
        phone: updatedUser.phone,
        userType: updatedUser.userType,
        isVerified: updatedUser.isVerified
      }
