    SecurityLogger.logAuthAttempt(req, false, { 
      event: 'user_type_update_failed', 
      error: error.message,
      userId: req.user!.id 
    });

    res.status(500).json({
      success: false,
      message: 'Failed to update user type',
      error: process.env.NODE_ENV === 'development' ? error.message : undefined
    });
