});

// Password-based registration (optional - if you want both OTP and password auth)
router.post('/register', registerValidation, async (req: any, res: any) => {
  try {
    const { phone, password, username, email, userType } = req.body;

    // Check if user already exists
    const existingUser = await storage.getUserByPhone(phone);
    if (existingUser) {
      return res.status(400).json({
        success: false,
        message: 'User with this phone number already exists'
      });
    }

    // Validate password strength
    const passwordValidation = validatePassword(password);
    if (!passwordValidation.isValid) {
      return res.status(400).json({
        success: false,
        message: 'Password does not meet security requirements',
        errors: passwordValidation.errors
      });
    }

    // Hash password
    const hashedPassword = await hashPassword(password);

    // Create user
    const user = await storage.createUser({
      id: `user_${Date.now()}`,
      phone,
      userType: userType || null, // Don't default to customer for password registration
      isVerified: false, // Require phone verification
    });

    SecurityLogger.logAuthAttempt(req, true, { 
      event: 'password_user_registered', 
      userId: user.id,
      phone: phone.substring(0, 6) + '****'
    });

    res.status(201).json({
      success: true,
      message: 'User registered successfully. Please verify your phone number.',
      userId: user.id
    });

  } catch (error: any) {
    SecurityLogger.logAuthAttempt(req, false, { 
      event: 'registration_failed', 
      error: error.message 
    });

    res.status(500).json({
      success: false,
      message: 'Registration failed. Please try again.',
      error: process.env.NODE_ENV === 'development' ? error.message : undefined
    });
  }
});

// Password-based login (optional)
router.post('/login', authRateLimit, authValidation, async (req: any, res: any) => {
  try {
    const { phone, password } = req.body;

    // Track login attempt for rate limiting
    try {
      trackLoginAttempt(phone, false); // Pre-check for lockout
    } catch (lockoutError: any) {
      SecurityLogger.logAuthAttempt(req, false, { 
        event: 'account_locked', 
        phone: phone.substring(0, 6) + '****'
      });

      return res.status(429).json({
        success: false,
        message: lockoutError.message
      });
    }

    // Get user
    const user = await storage.getUserByPhone(phone);
    if (!user) {
      trackLoginAttempt(phone, false);
      SecurityLogger.logAuthAttempt(req, false, { 
        event: 'user_not_found', 
        phone: phone.substring(0, 6) + '****'
      });

      return res.status(400).json({
        success: false,
        message: 'Invalid phone number or password'
      });
    }

    // For now, accept any password (since password field doesn't exist in schema)
    // TODO: Add proper password authentication
    if (!password) {
      trackLoginAttempt(phone, false);
      SecurityLogger.logAuthAttempt(req, false, { 
        event: 'invalid_password', 
        userId: user.id,
        phone: phone.substring(0, 6) + '****'
      });

      return res.status(400).json({
        success: false,
        message: 'Invalid phone number or password'
      });
    }

    // Check if user is verified
    if (!user.isVerified) {
      return res.status(403).json({
        success: false,
        message: 'Please verify your phone number before logging in',
        requiresVerification: true
      });
    }

    // Generate tokens
    const tokenPayload = {
      id: user.id,
      username: user.username,
      phone: user.phone,
      userType: user.userType,
      isVerified: user.isVerified,
    };

    const { accessToken, refreshToken } = generateTokens(tokenPayload);

    // Reset login attempts on success
    trackLoginAttempt(phone, true);

    SecurityLogger.logAuthAttempt(req, true, { 
      event: 'password_login_success', 
      userId: user.id,
      phone: phone.substring(0, 6) + '****'
    });

    res.json({
      success: true,
      message: 'Login successful',
      user: {
        id: user.id,
        username: user.username,
        phone: user.phone,
        userType: user.userType,
        isVerified: user.isVerified,
      },
      tokens: {
        accessToken,
        refreshToken,
        expiresIn: '7d'
      }
    });

  } catch (error: any) {
    SecurityLogger.logAuthAttempt(req, false, { 
      event: 'login_error', 
      error: error.message 
    });

    res.status(500).json({
      success: false,
      message: 'Login failed. Please try again.',
      error: process.env.NODE_ENV === 'development' ? error.message : undefined
    });
  }
});

// Change password endpoint
router.post('/change-password', requireAuth, async (req: AuthenticatedRequest, res) => {
