import express, { type Request, Response, NextFunction } from "express";
import { registerRoutes } from "./routes";
import { setupVite, serveStatic, log } from "./vite";
import { configureProductionStatic } from "./production-static";
import path from "path";
import fs from "fs";
import { corsOptions, securityMiddleware, rateLimitingMiddleware } from "./middleware/security";
import { httpLogger, requestIdMiddleware, errorLoggingMiddleware, performanceMonitor, trackAPIUsage } from "./middleware/logging";
import { sanitizeBody, preventSQLInjection } from "./middleware/validation";
import cors from "cors";

const app = express();

// Production vs Development mode setup
const isProductionEnv = process.env.NODE_ENV === "production";
console.log(`🔧 Environment: ${isProductionEnv ? 'PRODUCTION' : 'DEVELOPMENT'}`);

if (isProductionEnv) {
  // PRODUCTION: Serve built assets with correct MIME types
  const publicPath = path.resolve(process.cwd(), "dist", "public");
  const assetsPath = path.join(publicPath, 'assets');

  console.log(`📁 Production paths: public=${publicPath}, assets=${assetsPath}`);
  console.log(`📦 Assets exist: ${fs.existsSync(assetsPath)}`);

  if (fs.existsSync(assetsPath)) {
    const assets = fs.readdirSync(assetsPath);
    console.log(`🎯 Available assets: ${assets.join(', ')}`);
  }

  // PRIORITY 1: Asset serving with explicit MIME types
  app.get('/assets/:filename', (req: express.Request, res: express.Response) => {
    const filename = req.params.filename;
    const filePath = path.join(assetsPath, filename);

    console.log(`🎯 [ASSET] Request: /assets/${filename}`);
    console.log(`🔍 [ASSET] Looking for: ${filePath}`);

    if (!fs.existsSync(filePath)) {
      console.log(`❌ [ASSET] File not found: ${filename}`);
      return res.status(404).json({ error: `Asset ${filename} not found` });
    }

    const ext = path.extname(filename).toLowerCase();

    // Explicit MIME type mapping
    const mimeTypes: Record<string, string> = {
      '.js': 'application/javascript; charset=utf-8',
      '.css': 'text/css; charset=utf-8',
      '.png': 'image/png',
      '.jpg': 'image/jpeg',
      '.jpeg': 'image/jpeg',
      '.svg': 'image/svg+xml',
      '.woff': 'font/woff',
      '.woff2': 'font/woff2'
    };

    const mimeType = mimeTypes[ext] || 'application/octet-stream';

    res.setHeader('Content-Type', mimeType);
    res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');

    console.log(`✅ [ASSET] Serving ${filename} as ${mimeType}`);
    res.sendFile(filePath);
  });

  // PRIORITY 2: Static file fallback  
  app.use(express.static(publicPath, { 
    index: false,
    setHeaders: (res, filePath) => {
      const ext = path.extname(filePath);
      if (ext === '.css') {
        res.setHeader('Content-Type', 'text/css; charset=utf-8');
      } else if (ext === '.js') {
        res.setHeader('Content-Type', 'application/javascript; charset=utf-8');
      }
    }
  }));
}

// Trust proxy for accurate IP detection (important for rate limiting)
app.set('trust proxy', 1);

// Security middleware (early in the stack)
app.use(securityMiddleware);

// CORS configuration
app.use(cors(corsOptions));

// Request logging and monitoring
app.use(requestIdMiddleware);
app.use(httpLogger);
app.use(performanceMonitor);
app.use(trackAPIUsage);

// Body parsing with size limits
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: false, limit: '10mb' }));

// Input sanitization and security
app.use(sanitizeBody);
app.use(preventSQLInjection);

// Rate limiting
app.use(rateLimitingMiddleware);

// Enhanced health check endpoint (before authentication)
app.get('/health', (req: Request, res: Response) => {
  const uptime = process.uptime();
  const memUsage = process.memoryUsage();

  res.status(200).json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    environment: process.env.NODE_ENV || 'development',
    version: '1.0.0',
    uptime: `${Math.floor(uptime / 3600)}h ${Math.floor((uptime % 3600) / 60)}m ${Math.floor(uptime % 60)}s`,
    memory: {
      used: Math.round(memUsage.heapUsed / 1024 / 1024) + ' MB',
      total: Math.round(memUsage.heapTotal / 1024 / 1024) + ' MB'
    },
    app: 'DOOODHWALA',
    services: {
      database: 'connected',
      firebase: 'configured',
      payments: 'active'
    }
  });
});

// Keep-alive endpoint for monitoring services
app.get('/ping', (req: Request, res: Response) => {
  res.status(200).send('pong');
});

// Robot.txt for deployment bots
app.get('/robots.txt', (req: Request, res: Response) => {
  res.type('text/plain');
  res.send(`User-agent: *
Allow: /
Sitemap: https://dairy-connect-siddhantsancheti.replit.app/sitemap.xml`);
});

app.use((req, res, next) => {
  const start = Date.now();
  const path = req.path;
  let capturedJsonResponse: Record<string, any> | undefined = undefined;

  const originalResJson = res.json;
  res.json = function (bodyJson, ...args) {
    capturedJsonResponse = bodyJson;
    return originalResJson.apply(res, [bodyJson, ...args]);
  };

  res.on("finish", () => {
    const duration = Date.now() - start;
    if (path.startsWith("/api")) {
      let logLine = `${req.method} ${path} ${res.statusCode} in ${duration}ms`;
      if (capturedJsonResponse) {
        logLine += ` :: ${JSON.stringify(capturedJsonResponse)}`;
      }

      if (logLine.length > 500) {
        logLine = logLine.slice(0, 499) + "…";
      }

      log(logLine);
    }
  });

  next();
});

(async () => {
  // Setup static files for production
  const isProduction = process.env.NODE_ENV === "production";
  if (isProduction) {
    log('🔧 Setting up production static file serving...');
    configureProductionStatic(app);
    log('✅ Production static serving configured');
  }

  const server = await registerRoutes(app);

  // Enhanced error handling middleware
  app.use(errorLoggingMiddleware);

  // Setup vite in development only (after API routes)
  if (!isProduction) {
    await setupVite(app, server);
  }

  // ALWAYS serve the app on port 5000
  // this serves both the API and the client.
  // It is the only port that is not firewalled.
  const port = process.env.PORT || 5000;
  server.listen({
    port: Number(port),
    host: "0.0.0.0",
    reusePort: true,
  }, () => {
    log(`🥛 DOOODHWALA serving on port ${port}`);
    log(`Security middleware enabled: ${process.env.NODE_ENV === 'production' ? 'Production mode' : 'Development mode'}`);
    log(`🌐 Public URL: https://dairy-connect-siddhantsancheti.replit.app/`);
    log(`💚 Health check: https://dairy-connect-siddhantsancheti.replit.app/health`);

    // Setup monthly billing scheduler with error handling
    try {
      setupMonthlyBillingScheduler();
    } catch (error) {
      console.error('⚠️ Failed to setup monthly billing scheduler:', error);
    }

    // Setup keep-alive mechanism for production with error handling
    if (process.env.NODE_ENV === 'production') {
      try {
        setupKeepAlive();
      } catch (error) {
        console.error('⚠️ Failed to setup keep-alive mechanism:', error);
      }
    }
  });

  // Add error handling for server startup failures
  server.on('error', (err: any) => {
    if (err.code === 'EADDRINUSE') {
      console.error(`❌ Port ${port} is already in use. Please try a different port.`);
      process.exit(1);
    } else if (err.code === 'EACCES') {
      console.error(`❌ Permission denied to bind to port ${port}. Try using a port above 1024.`);
      process.exit(1);
    } else {
      console.error('❌ Server startup error:', err);
      process.exit(1);
    }
  });

  // Graceful shutdown handling
  process.on('SIGTERM', () => {
    log('🛑 SIGTERM received, shutting down gracefully');
    server.close(() => {
      log('🛑 Process terminated');
      process.exit(0);
    });
  });

  process.on('SIGINT', () => {
    log('🛑 SIGINT received, shutting down gracefully');
    server.close(() => {
      log('🛑 Process terminated');
      process.exit(0);
    });
  });
})();

// Keep-alive mechanism to prevent sleeping
function setupKeepAlive() {
  const url = 'https://dairy-connect-siddhantsancheti.replit.app/ping';

  log('🔄 Setting up keep-alive mechanism');

  // Ping every 5 minutes to keep the app awake
  setInterval(async () => {
    try {
      const response = await fetch(url);
      if (response.ok) {
        log('💓 Keep-alive ping successful');
      } else {
        log(`⚠️ Keep-alive ping failed: ${response.status}`);
      }
    } catch (error) {
      log(`❌ Keep-alive ping error: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  }, 5 * 60 * 1000); // 5 minutes
}

// Monthly billing scheduler function
async function setupMonthlyBillingScheduler() {
  console.log('📅 Setting up monthly billing scheduler...');

  // Import storage dynamically to avoid circular dependency
  const { storage } = await import("./storage");

  // Calculate time until next 1st of the month at 9:00 AM
  const now = new Date();
  const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1, 9, 0, 0, 0); // 1st of next month at 9 AM
  const msUntilNext = Math.min(nextMonth.getTime() - now.getTime(), 2147483647); // Cap at 32-bit integer max

  console.log(`📅 Next monthly bill generation scheduled for: ${nextMonth.toLocaleDateString('en-IN')} at 9:00 AM`);

  // Schedule the first run with proper timeout handling
  if (msUntilNext > 1) {
    setTimeout(async () => {
      try {
        console.log('🧾 Starting monthly bill generation...');
        const bills = await storage.generateMonthlyBills();
        console.log(`✅ Monthly billing completed. Generated ${bills.length} bills.`);
      } catch (error) {
        console.error('❌ Monthly billing failed:', error);
      }

      // Set up recurring monthly execution - use a more reasonable interval
      const monthlyInterval = 24 * 60 * 60 * 1000; // Run daily and check if it's the 1st of the month
      setInterval(async () => {
        const currentDate = new Date();
        if (currentDate.getDate() === 1 && currentDate.getHours() === 9) {
          try {
            console.log('🧾 Starting scheduled monthly bill generation...');
            const bills = await storage.generateMonthlyBills();
            console.log(`✅ Scheduled monthly billing completed. Generated ${bills.length} bills.`);
          } catch (error) {
            console.error('❌ Scheduled monthly billing failed:', error);
          }
        }
      }, monthlyInterval);

    }, msUntilNext);
  }

  // For testing in development, run a simplified test after server startup
  if (process.env.NODE_ENV === 'development') {
    console.log('🧪 Development mode: Scheduling monthly billing test...');
    setTimeout(async () => {
      try {
        console.log('🧾 Testing monthly billing system...');
        const bills = await storage.generateMonthlyBills();
        console.log(`✅ Monthly billing test completed. Generated ${bills.length} bills.`);
      } catch (error) {
        console.error('❌ Monthly billing test failed:', error);
      }
    }, 10000); // Run after 10 seconds to allow server to fully start
  }
}

