import Razorpay from 'razorpay';
import Stripe from 'stripe';
import crypto from 'crypto';
import { storage } from './storage';
import { insertPaymentSchema } from '@shared/schema';

// SMS service function - imported from routes.ts
async function sendSMS(phone: string, message: string): Promise<boolean> {
  try {
    console.log(`📱 SMS to +91${phone}: ${message}`);

    const accountSid = process.env.TWILIO_ACCOUNT_SID;
    const authToken = process.env.TWILIO_AUTH_TOKEN;
    const fromNumber = process.env.TWILIO_PHONE_NUMBER;

    if (accountSid && authToken && fromNumber) {
      const twilioModule = await import('twilio');
      const twilio = twilioModule.default;
      const client = twilio(accountSid, authToken);

      // Clean phone number format - remove any existing country code
      const cleanPhone = phone.replace(/^(\+91|91|0)/, '');
      const fullPhone = `+91${cleanPhone}`;

      const result = await client.messages.create({
        body: message,
        from: fromNumber,
        to: fullPhone
      });

      console.log(`✅ SMS sent successfully via Twilio. Message SID: ${result.sid}`);
      return true;
    } else {
      console.log('⚠️ Twilio credentials not found - SMS logged to console only');
      return false;
    }
  } catch (error) {
    console.error('SMS sending failed:', error);
    return false;
  }
}

// Initialize payment gateways
let razorpay: Razorpay | null = null;
let stripe: Stripe | null = null;

// Initialize Razorpay
if (process.env.RAZORPAY_KEY_ID && process.env.RAZORPAY_KEY_SECRET) {
  razorpay = new Razorpay({
    key_id: process.env.RAZORPAY_KEY_ID,
    key_secret: process.env.RAZORPAY_KEY_SECRET,
  });
  console.log('Razorpay initialized for Indian market payments');
} else {
  console.log('Razorpay credentials not provided - Razorpay payments disabled');
}

// Initialize Stripe
if (process.env.STRIPE_SECRET_KEY) {
  stripe = new Stripe(process.env.STRIPE_SECRET_KEY, {
    apiVersion: '2024-09-30.acacia',
  });
  console.log('Stripe initialized for international payments');
} else {
  console.log('Stripe credentials not provided - Stripe payments disabled');
}

interface CreateRazorpayOrderRequest {
  amount: number;
  orderId: string;
  userId: string;
  customerId?: number;
  milkmanId?: number;
  description?: string;
  customerEmail?: string;
  customerPhone?: string;
}

interface ProcessRazorpayPaymentRequest {
  razorpay_order_id: string;
  razorpay_payment_id: string;
  razorpay_signature: string;
  paymentDetails?: any;
}

interface CreateStripePaymentRequest {
  amount: number;
  orderId: string;
  userId: string;
  customerId?: number;
  milkmanId?: number;
  description?: string;
  customerEmail?: string;
}

interface CreateCODOrderRequest {
  amount: number;
  orderId: string;
  userId: string;
  customerId?: number;
  milkmanId?: number;
  description?: string;
  customerPhone?: string;
  deliveryAddress?: string;
}

interface VerifyCODOTPRequest {
  paymentId: number;
  otp: string;
  milkmanId: string;
}

export class PaymentService {
  static async createRazorpayOrder(request: CreateRazorpayOrderRequest) {
    if (!razorpay) {
      throw new Error('Razorpay not configured. Please check your credentials.');
    }

    try {
      const options = {
        amount: Math.round(request.amount * 100), // Amount in paise
        currency: 'INR',
        receipt: request.orderId,
        notes: {
          orderId: request.orderId,
          userId: request.userId,
          customerId: request.customerId?.toString() || '',
          milkmanId: request.milkmanId?.toString() || '',
          description: request.description || 'DOOODHWALA Milk Delivery',
        },
      };

      const razorpayOrder = await razorpay.orders.create(options);

      // Store payment record in database
      const payment = await storage.createPayment({
        orderId: request.orderId,
        userId: request.userId,
        customerId: request.customerId,
        milkmanId: request.milkmanId,
        amount: request.amount.toString(),
        currency: 'INR',
        status: 'pending',
        paymentMethod: 'razorpay',
        gatewayOrderId: razorpayOrder.id,
        description: request.description,
        customerEmail: request.customerEmail,
        customerPhone: request.customerPhone,
      });

      return {
        razorpayOrderId: razorpayOrder.id,
        amount: razorpayOrder.amount,
        currency: razorpayOrder.currency,
        key: process.env.RAZORPAY_KEY_ID,
        paymentId: payment.id,
      };
    } catch (error: any) {
      console.error('Razorpay order creation failed:', error);
      throw new Error(`Payment order creation failed: ${error.message}`);
    }
  }

  static async processRazorpayPayment(request: ProcessRazorpayPaymentRequest) {
    if (!razorpay) {
      throw new Error('Razorpay not configured');
    }

    try {
      // Verify payment signature
      const generatedSignature = crypto
        .createHmac('sha256', process.env.RAZORPAY_KEY_SECRET!)
        .update(`${request.razorpay_order_id}|${request.razorpay_payment_id}`)
        .digest('hex');

      if (generatedSignature !== request.razorpay_signature) {
        throw new Error('Invalid payment signature');
      }

      // Fetch payment details from Razorpay
      const paymentDetails = await razorpay.payments.fetch(request.razorpay_payment_id);

      // Update payment in database
      const payment = await storage.updatePaymentByGatewayOrderId(request.razorpay_order_id, {
        status: 'completed',
        gatewayPaymentId: request.razorpay_payment_id,
        gatewaySignature: request.razorpay_signature,
        processedAt: new Date(),
        gatewayResponse: JSON.stringify(paymentDetails),
      });

      return payment;
    } catch (error: any) {
      console.error('Razorpay payment processing failed:', error);

      // Update payment status to failed
      try {
        await storage.updatePaymentByGatewayOrderId(request.razorpay_order_id, {
          status: 'failed',
          failureReason: error.message,
        });
      } catch (updateError) {
        console.error('Failed to update payment status:', updateError);
      }

      throw error;
    }
  }

  static async createStripePaymentIntent(request: CreateStripePaymentRequest) {
    if (!stripe) {
      throw new Error('Stripe not configured. Please check your credentials.');
    }

    try {
      const paymentIntent = await stripe.paymentIntents.create({
        amount: Math.round(request.amount * 100), // Amount in smallest currency unit
        currency: 'inr',
        description: request.description || 'DOOODHWALA Milk Delivery',
        metadata: {
          orderId: request.orderId,
          userId: request.userId,
          customerId: request.customerId?.toString() || '',
          milkmanId: request.milkmanId?.toString() || '',
        },
        receipt_email: request.customerEmail || undefined,
      });

      // Store payment record in database
      const payment = await storage.createPayment({
        orderId: request.orderId,
        userId: request.userId,
        customerId: request.customerId,
        milkmanId: request.milkmanId,
        amount: request.amount.toString(),
        currency: 'INR',
        status: 'pending',
        paymentMethod: 'stripe',
        gatewayOrderId: paymentIntent.id,
        description: request.description,
        customerEmail: request.customerEmail,
      });

      return {
        clientSecret: paymentIntent.client_secret,
        paymentIntentId: paymentIntent.id,
        amount: request.amount,
        currency: 'INR',
        paymentId: payment.id,
      };
    } catch (error: any) {
      console.error('Stripe payment intent creation failed:', error);
      throw new Error(`Payment intent creation failed: ${error.message}`);
    }
  }

  static async processRazorpayWebhook(payload: any, signature: string) {
    if (!process.env.RAZORPAY_WEBHOOK_SECRET) {
      console.log('Razorpay webhook secret not configured');
      return;
    }

    try {
      // Verify webhook signature
      const expectedSignature = crypto
        .createHmac('sha256', process.env.RAZORPAY_WEBHOOK_SECRET)
        .update(JSON.stringify(payload))
        .digest('hex');

      if (signature !== expectedSignature) {
        throw new Error('Invalid webhook signature');
      }

      const { event, payload: eventPayload } = payload;

      switch (event) {
        case 'payment.captured':
          await this.handleRazorpayPaymentCaptured(eventPayload.payment.entity);
          break;
        case 'payment.failed':
          await this.handleRazorpayPaymentFailed(eventPayload.payment.entity);
          break;
        default:
          console.log(`Unhandled Razorpay webhook event: ${event}`);
      }
    } catch (error: any) {
      console.error('Razorpay webhook processing failed:', error);
      throw error;
    }
  }

  static async processStripeWebhook(payload: any) {
    // Basic Stripe webhook processing (signature verification would need raw body)
    try {
      const { type, data } = payload;

      switch (type) {
        case 'payment_intent.succeeded':
          await this.handleStripePaymentSucceeded(data.object);
          break;
        case 'payment_intent.payment_failed':
          await this.handleStripePaymentFailed(data.object);
          break;
        default:
          console.log(`Unhandled Stripe webhook event: ${type}`);
      }
    } catch (error: any) {
      console.error('Stripe webhook processing failed:', error);
      throw error;
    }
  }

  static async processRefund(paymentId: number, amount?: number, reason?: string) {
    const payment = await storage.getPayment(paymentId);
    if (!payment) {
      throw new Error('Payment not found');
    }

    if (payment.status !== 'completed') {
      throw new Error('Can only refund completed payments');
    }

    try {
      let refund;

      if (payment.paymentMethod === 'razorpay' && razorpay) {
        refund = await razorpay.payments.refund(payment.gatewayPaymentId!, {
          amount: amount ? Math.round(amount * 100) : Math.round(parseFloat(payment.amount) * 100),
          notes: {
            reason: reason || 'Customer requested refund',
            paymentId: paymentId.toString(),
          },
        });
      } else if (payment.paymentMethod === 'stripe' && stripe) {
        refund = await stripe.refunds.create({
          payment_intent: payment.gatewayOrderId,
          amount: amount ? Math.round(amount * 100) : Math.round(parseFloat(payment.amount) * 100),
          reason: 'requested_by_customer',
          metadata: {
            reason: reason || 'Customer requested refund',
            paymentId: paymentId.toString(),
          },
        });
      } else {
        throw new Error('Refund not supported for this payment method');
      }

      // Update payment status
      await storage.updatePayment(paymentId, {
        status: 'refunded',
        refundedAt: new Date(),
        refundAmount: amount?.toString() || payment.amount,
        refundReason: reason,
      });

      return refund;
    } catch (error: any) {
      console.error('Refund processing failed:', error);
      throw new Error(`Refund failed: ${error.message}`);
    }
  }

  private static async handleRazorpayPaymentCaptured(payment: any) {
    try {
      await storage.updatePaymentByGatewayPaymentId(payment.id, {
        status: 'completed',
        processedAt: new Date(),
        gatewayResponse: JSON.stringify(payment),
      });
      console.log(`Razorpay payment captured: ${payment.id}`);
    } catch (error) {
      console.error('Failed to handle Razorpay payment captured:', error);
    }
  }

  private static async handleRazorpayPaymentFailed(payment: any) {
    try {
      await storage.updatePaymentByGatewayPaymentId(payment.id, {
        status: 'failed',
        failureReason: payment.error_description || 'Payment failed',
        gatewayResponse: JSON.stringify(payment),
      });
      console.log(`Razorpay payment failed: ${payment.id}`);
    } catch (error) {
      console.error('Failed to handle Razorpay payment failed:', error);
    }
  }

  private static async handleStripePaymentSucceeded(paymentIntent: any) {
    try {
      await storage.updatePaymentByGatewayOrderId(paymentIntent.id, {
        status: 'completed',
        processedAt: new Date(),
        gatewayResponse: JSON.stringify(paymentIntent),
      });
      console.log(`Stripe payment succeeded: ${paymentIntent.id}`);
    } catch (error) {
      console.error('Failed to handle Stripe payment succeeded:', error);
    }
  }

  private static async handleStripePaymentFailed(paymentIntent: any) {
    try {
      await storage.updatePaymentByGatewayOrderId(paymentIntent.id, {
        status: 'failed',
        failureReason: paymentIntent.last_payment_error?.message || 'Payment failed',
        gatewayResponse: JSON.stringify(paymentIntent),
      });
      console.log(`Stripe payment failed: ${paymentIntent.id}`);
    } catch (error) {
      console.error('Failed to handle Stripe payment failed:', error);
    }
  }

  static async createCODOrder(request: CreateCODOrderRequest) {
    try {
      // Generate 6-digit OTP for COD verification
      const codOTP = Math.floor(100000 + Math.random() * 900000).toString();
      const otpExpiry = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours expiry

      // Create COD payment record in database
      const payment = await storage.createPayment({
        orderId: request.orderId,
        userId: request.userId,
        customerId: request.customerId,
        milkmanId: request.milkmanId,
        amount: request.amount.toString(),
        currency: 'INR',
        status: 'pending', // Will be updated to 'completed' when OTP is verified
        paymentMethod: 'cod',
        description: request.description || 'DOOODHWALA Cash on Delivery',
        customerPhone: request.customerPhone,
        paymentDetails: JSON.stringify({
          deliveryAddress: request.deliveryAddress,
          codInstructions: 'Pay in cash upon delivery and provide OTP to milkman',
          exactAmount: request.amount,
          codOTP: codOTP,
          otpExpiry: otpExpiry.toISOString(),
          otpVerified: false
        })
      });

      // Send OTP to customer via SMS
      let smsSuccess = false;
      try {
        if (request.customerPhone) {
          const smsMessage = `DOOODHWALA COD Order: Your payment verification code is ${codOTP}. Share this with your milkman when paying ₹${request.amount} in cash. Valid for 24 hours.`;
          smsSuccess = await sendSMS(request.customerPhone, smsMessage);
          console.log(`COD OTP sent to ${request.customerPhone}: ${codOTP} - Success: ${smsSuccess}`);
        }
      } catch (smsError) {
        console.error('Failed to send COD OTP SMS:', smsError);
        // Don't fail the order creation if SMS fails
        smsSuccess = false;
      }

      // Send OTP to customer via YD Chat
      let chatSuccess = false;
      try {
        if (request.customerId && request.milkmanId) {
          const chatMessage = `🔐 COD Payment OTP: ${codOTP}\n\n💰 Order: ${request.orderId}\n💳 Amount: ₹${request.amount}\n\n📋 Instructions:\n• Share this OTP with your milkman when paying cash\n• OTP is valid for 24 hours\n• Keep this message for your reference`;

          console.log(`Attempting to send YD chat OTP for customerId: ${request.customerId}, milkmanId: ${request.milkmanId}`);

          const chatMessage_result = await storage.createChatMessage({
            customerId: request.customerId,
            milkmanId: request.milkmanId,
            senderId: 'system',
            message: chatMessage,
            messageType: 'system',
            senderType: 'system',
            isRead: false,
            orderQuantity: null,
          });

          console.log(`YD Chat message created:`, chatMessage_result);
          chatSuccess = true;
          console.log(`✅ COD OTP sent via YD chat for order ${request.orderId}`);
        } else {
          console.log(`❌ Cannot send YD chat - missing customerId: ${request.customerId} or milkmanId: ${request.milkmanId}`);
        }
      } catch (chatError) {
        console.error('❌ Failed to send COD OTP via YD chat:', chatError);
        chatSuccess = false;
      }

      return {
        success: true,
        paymentId: payment.id,
        orderId: request.orderId,
        amount: request.amount,
        currency: 'INR',
        paymentMethod: 'cod',
        status: 'pending',
        otpSent: smsSuccess || chatSuccess,
        smsOtpSent: smsSuccess,
        chatOtpSent: chatSuccess,
        codOTP: codOTP, // Include for development/testing
        message: (smsSuccess || chatSuccess) 
          ? `COD order created successfully. OTP sent via ${smsSuccess ? 'SMS' : ''}${smsSuccess && chatSuccess ? ' and ' : ''}${chatSuccess ? 'YD Chat' : ''}. Share OTP ${codOTP} with your milkman when paying ₹${request.amount} in cash.`
          : `COD order created successfully. Pay ₹${request.amount} in cash upon delivery.`
      };
    } catch (error: any) {
      console.error('COD order creation failed:', error);
      throw new Error(`COD order creation failed: ${error.message}`);
    }
  }

  static async verifyCODOTP(request: VerifyCODOTPRequest) {
    try {
      const payment = await storage.getPayment(request.paymentId);
      if (!payment) {
        throw new Error('Payment not found');
      }

      if (payment.paymentMethod !== 'cod') {
        throw new Error('Payment is not a COD order');
      }

      if (payment.status !== 'pending') {
        throw new Error('COD payment already processed');
      }

      const paymentDetails = JSON.parse(payment.paymentDetails || '{}');
      const storedOTP = paymentDetails.codOTP;
      const otpExpiry = new Date(paymentDetails.otpExpiry);
      const isOTPVerified = paymentDetails.otpVerified;

      if (isOTPVerified) {
        throw new Error('OTP already verified for this payment');
      }

      if (!storedOTP) {
        throw new Error('No OTP found for this COD payment');
      }

      if (new Date() > otpExpiry) {
        throw new Error('OTP has expired');
      }

      if (request.otp !== storedOTP) {
        throw new Error('Invalid OTP');
      }

      // OTP is valid, mark payment as completed
      const updatedPayment = await storage.updatePayment(request.paymentId, {
        status: 'completed',
        processedAt: new Date(),
        paymentDetails: JSON.stringify({
          ...paymentDetails,
          otpVerified: true,
          verifiedBy: request.milkmanId,
          cashReceivedAt: new Date().toISOString(),
          confirmationMethod: 'otp_verification'
        })
      });

      return {
        success: true,
        payment: updatedPayment,
        message: 'COD payment verified successfully'
      };
    } catch (error: any) {
      console.error('COD OTP verification failed:', error);
      throw new Error(`COD OTP verification failed: ${error.message}`);
    }
  }

  static async confirmCODPayment(paymentId: number, deliveredBy: string) {
    try {
      const payment = await storage.getPayment(paymentId);
      if (!payment) {
        throw new Error('Payment not found');
      }

      if (payment.paymentMethod !== 'cod') {
        throw new Error('Payment is not a COD order');
      }

      if (payment.status !== 'pending') {
        throw new Error('COD payment already processed');
      }

      // Update payment status to completed
      const updatedPayment = await storage.updatePayment(paymentId, {
        status: 'completed',
        processedAt: new Date(),
        paymentDetails: JSON.stringify({
          ...JSON.parse(payment.paymentDetails || '{}'),
          deliveredBy,
          cashReceivedAt: new Date().toISOString(),
          confirmationMethod: 'manual'
        })
      });

      return updatedPayment;
    } catch (error: any) {
      console.error('COD payment confirmation failed:', error);
      throw new Error(`COD payment confirmation failed: ${error.message}`);
    }
  }
}

export default PaymentService;

