import express, { type Express, type Request, type Response } from "express";
import path from "path";
import fs from "fs";

export function setupProductionServer(app: Express) {
  const distPath = path.resolve(process.cwd(), "dist", "public");

  console.log(`[Production] Static files path: ${distPath}`);
  console.log(`[Production] Directory exists: ${fs.existsSync(distPath)}`);

  if (!fs.existsSync(distPath)) {
    throw new Error(`Build directory not found: ${distPath}. Run 'npm run build' first.`);
  }

  // List available assets
  const assetsPath = path.join(distPath, 'assets');
  if (fs.existsSync(assetsPath)) {
    const assets = fs.readdirSync(assetsPath);
    console.log(`[Production] Available assets:`, assets);
  }

  // PRIORITY: Handle assets directory with explicit MIME types
  app.get('/assets/:filename', (req: Request, res: Response) => {
    const filename = req.params.filename;
    const filePath = path.join(assetsPath, filename);

    console.log(`[Assets] Request for: ${filename}`);
    console.log(`[Assets] Full path: ${filePath}`);
    console.log(`[Assets] File exists: ${fs.existsSync(filePath)}`);

    if (!fs.existsSync(filePath)) {
      console.log(`[Assets] File not found: ${filename}`);
      return res.status(404).json({ error: 'Asset not found' });
    }

    const ext = path.extname(filename).toLowerCase();

    // Set explicit MIME types
    switch (ext) {
      case '.js':
        res.setHeader('Content-Type', 'application/javascript; charset=utf-8');
        break;
      case '.css':
        res.setHeader('Content-Type', 'text/css; charset=utf-8');
        break;
      case '.png':
        res.setHeader('Content-Type', 'image/png');
        break;
      case '.jpg':
      case '.jpeg':
        res.setHeader('Content-Type', 'image/jpeg');
        break;
      case '.svg':
        res.setHeader('Content-Type', 'image/svg+xml');
        break;
      default:
        res.setHeader('Content-Type', 'application/octet-stream');
    }

    // Set cache headers
    res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');
    res.setHeader('ETag', `"${filename}"`);

    console.log(`[Assets] Serving ${filename} as ${res.getHeader('Content-Type')}`);

    // Send the file
    res.sendFile(filePath);
  });

  // Serve other static files (favicon, etc.)
  app.use(express.static(distPath, {
    index: false,
    maxAge: '1d'
  }));

  // SPA fallback - serve index.html for non-API routes
  app.get('*', (req: Request, res: Response) => {
    // Don't serve index.html for API routes or assets
    if (req.path.startsWith('/api/') || req.path.startsWith('/assets/')) {
      return res.status(404).json({ error: 'Not found' });
    }

    const indexPath = path.join(distPath, 'index.html');
    console.log(`[SPA] Serving index.html for: ${req.path}`);

    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.setHeader('Cache-Control', 'no-cache');
    res.sendFile(indexPath);
  });
}

