import express, { type Express, type Request, type Response } from "express";
import path from "path";
import fs from "fs";
import { fileURLToPath } from 'url';

// Get the directory name in ES modules
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

export function configureProductionStatic(app: Express) {
  // Production static file serving for Replit deployment
  const publicPath = path.resolve(__dirname, "..", "dist", "public");

  console.log(`[Production] Serving static files from: ${publicPath}`);
  console.log(`[Production] Directory exists: ${fs.existsSync(publicPath)}`);

  if (!fs.existsSync(publicPath)) {
    throw new Error(`Production build not found at ${publicPath}. Run 'npm run build' first.`);
  }

  // List all available assets for debugging
  const assetsDir = path.join(publicPath, 'assets');
  if (fs.existsSync(assetsDir)) {
    const assets = fs.readdirSync(assetsDir);
    console.log(`[Production] Assets available:`, assets);
  }

  // Serve static assets with proper MIME types and caching
  app.use('/assets', express.static(path.join(publicPath, 'assets'), {
    maxAge: '1y', // Cache assets for 1 year in production
    etag: true,
    lastModified: true,
    setHeaders: (res, filePath, stat) => {
      const ext = path.extname(filePath).toLowerCase();

      // Force correct MIME types
      switch (ext) {
        case '.js':
          res.setHeader('Content-Type', 'application/javascript; charset=utf-8');
          break;
        case '.css':
          res.setHeader('Content-Type', 'text/css; charset=utf-8');
          break;
        case '.png':
          res.setHeader('Content-Type', 'image/png');
          break;
        case '.jpg':
        case '.jpeg':
          res.setHeader('Content-Type', 'image/jpeg');
          break;
        case '.svg':
          res.setHeader('Content-Type', 'image/svg+xml');
          break;
        case '.woff':
          res.setHeader('Content-Type', 'font/woff');
          break;
        case '.woff2':
          res.setHeader('Content-Type', 'font/woff2');
          break;
        case '.ico':
          res.setHeader('Content-Type', 'image/x-icon');
          break;
        default:
          res.setHeader('Content-Type', 'application/octet-stream');
      }

      // Set immutable cache for hashed assets
      res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');

      console.log(`[Assets] Serving ${path.basename(filePath)} as ${res.getHeader('Content-Type')}`);
    }
  }));

  // Serve other static files (favicon, etc.) from public root
  app.use(express.static(publicPath, {
    index: false, // Don't auto-serve index.html for directories
    maxAge: '1d'
  }));

  // SPA fallback - serve index.html for all non-API, non-asset routes
  app.get('*', (req: Request, res: Response) => {
    // Don't serve index.html for API routes, assets, or health checks
    if (req.path.startsWith('/api/') || 
        req.path.startsWith('/assets/') || 
        req.path.startsWith('/health') ||
        req.path.startsWith('/ping')) {
      return res.status(404).json({ error: 'Not found' });
    }

    const indexPath = path.join(publicPath, 'index.html');

    console.log(`[SPA] Serving index.html for route: ${req.path}`);

    // Set proper headers for HTML
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate');
    res.setHeader('Pragma', 'no-cache');
    res.setHeader('Expires', '0');

    res.sendFile(indexPath, (err) => {
      if (err) {
        console.error('[SPA] Error serving index.html:', err);
        res.status(500).send('Internal Server Error');
      }
    });
  });
}

