// Helper function to calculate recommendation score
function calculateRecommendationScore(milkman: any): number {
  let score = 0;

  // Distance score (closer = higher score)
  if (milkman.distance) {
    if (milkman.distance <= 1) score += 40;
    else if (milkman.distance <= 3) score += 30;
    else if (milkman.distance <= 5) score += 20;
    else if (milkman.distance <= 10) score += 10;
  }

  // Rating score (higher rating = higher score)
  const rating = parseFloat(milkman.rating || '0');
  score += rating * 10;

  // Review count score (more reviews = higher score)
  const reviewCount = parseInt(milkman.totalReviews || '0');
  if (reviewCount > 50) score += 20;
  else if (reviewCount > 20) score += 15;
  else if (reviewCount > 10) score += 10;
  else if (reviewCount > 5) score += 5;

  // Verification score
  if (milkman.verified) score += 15;

  // Availability score
  if (milkman.isAvailable) score += 10;

  // Price competitiveness (lower price = higher score)
  const price = parseFloat(milkman.pricePerLiter || '100');
  if (price <= 40) score += 15;
  else if (price <= 50) score += 10;
  else if (price <= 60) score += 5;

  return Math.round(score);
}

// Helper function to get distance label
function getDistanceLabel(distance: number): string {
  if (distance === 0) return "Location not available";
  if (distance < 1) return `${(distance * 1000).toFixed(0)}m away`;
  if (distance < 10) return `${distance.toFixed(1)}km away`;
  return `${Math.round(distance)}km away`;
}

// Initialize Stripe only if the key is available
let stripe: Stripe | null = null;
if (process.env.STRIPE_SECRET_KEY) {
