  });
}

// JWT authentication now handled by unified middleware
const JWT_SECRET = process.env.JWT_SECRET || 'your-super-secure-jwt-secret-change-in-production';

// Configure multer for voice message uploads
const upload = multer({
  storage: multer.diskStorage({
    destination: (req, file, cb) => {
      const uploadDir = 'uploads/voice-messages';
      fs.mkdirSync(uploadDir, { recursive: true });
