      cb(null, true);
    } else {
      cb(null, false);
    }
  }
});

// OTP validation schemas for Indian phone numbers
const sendOTPSchema = z.object({
  phone: z.string().transform((val) => {
    // Clean and normalize Indian phone numbers
    let cleaned = val.replace(/[^0-9]/g, '');
    // Remove +91 country code if present
    if (cleaned.startsWith('91') && cleaned.length === 12) {
      cleaned = cleaned.substring(2);
    }
    return cleaned;
  }).refine((val) => /^[6-9][0-9]{9}$/.test(val), {
    message: "Phone number must be a valid 10-digit Indian mobile number starting with 6, 7, 8, or 9"
  })
});

const verifyOTPSchema = z.object({
  phone: z.string().transform((val) => {
    // Clean and normalize Indian phone numbers
    let cleaned = val.replace(/[^0-9]/g, '');
    // Remove +91 country code if present
    if (cleaned.startsWith('91') && cleaned.length === 12) {
      cleaned = cleaned.substring(2);
    }
    return cleaned;
  }).refine((val) => /^[6-9][0-9]{9}$/.test(val), {
    message: "Phone number must be a valid 10-digit Indian mobile number starting with 6, 7, 8, or 9"
  }),
  otp: z.string().regex(/^[0-9]{6}$/, "OTP must be exactly 6 digits")
});

// OTP generation and SMS service
function generateOTP(): string {
  const otp = Math.floor(100000 + Math.random() * 900000).toString();
  console.log('🔢 [MAIN] Generated 6-digit OTP:', otp.substring(0, 2) + '****');
  return otp;
}

// SMS service function - Twilio integration
async function sendSMS(phone: string, message: string): Promise<boolean> {
  try {
    // Always log for debugging
    console.log(`📱 SMS to +91${phone}: ${message}`);

    // Check if Twilio credentials are available
    const accountSid = process.env.TWILIO_ACCOUNT_SID;
    const authToken = process.env.TWILIO_AUTH_TOKEN;
    const fromNumber = process.env.TWILIO_PHONE_NUMBER;

    if (accountSid && authToken && fromNumber) {
      // Import Twilio dynamically to handle ES modules
      let client;
      try {
        // Import Twilio correctly for ES modules
        const twilioModule = await import('twilio');
        const twilio = twilioModule.default;
        client = twilio(accountSid, authToken);
      } catch (importError) {
        console.error('Twilio import failed:', importError);
        return false;
      }

      // Send SMS via Twilio
      const result = await client.messages.create({
        body: message,
        from: fromNumber,
        to: `+91${phone}` // Indian phone number format
      });

      console.log(`✅ SMS sent successfully via Twilio. Message SID: ${result.sid}`);
      return true;

    } else {
      console.log('⚠️ Twilio credentials not found - SMS logged to console only');

      // Fallback options for other SMS providers
      /* 
      // Fast2SMS integration (Indian SMS provider):
      const fast2smsKey = process.env.FAST2SMS_API_KEY;
      if (fast2smsKey) {
        const response = await fetch('https://www.fast2sms.com/dev/bulkV2', {
          method: 'POST',
          headers: {
            'authorization': fast2smsKey,
            'Content-Type': 'application/x-www-form-urlencoded'
          },
          body: `variables_values=${encodeURIComponent(message)}&route=otp&numbers=${phone}`
        });
        const data = await response.json();
        console.log('Fast2SMS response:', data);
        return data.return;
      }

      // MSG91 integration (Indian SMS provider):
      const msg91Key = process.env.MSG91_API_KEY;
      if (msg91Key) {
        const response = await fetch(`https://api.msg91.com/api/sendotp.php?authkey=${msg91Key}&mobile=${phone}&message=${encodeURIComponent(message)}&sender=MSGIND&otp_length=6&otp_expiry=10`);
        const data = await response.json();
        console.log('MSG91 response:', data);
        return data.type === 'success';
      }
      */

      return true; // Return true for development when no SMS provider is configured
    }

  } catch (error) {
    console.error('❌ SMS sending failed:', error);

    // Log specific Twilio errors
    if (error && typeof error === 'object' && 'code' in error) {
      console.error(`Twilio Error ${(error as any).code}: ${(error as any).message}`);

      // Common Twilio error codes
      switch ((error as any).code) {
        case 21408:
          console.error('Permission denied - check Twilio phone number permissions');
          break;
        case 21614:
          console.error('Invalid phone number format');
          break;
        case 21211:
          console.error('Invalid Twilio phone number');
          break;
        default:
          console.error('Check Twilio credentials and account status');
      }
    }

    return false;
  }
}

// JWT token generation is now handled by auth middleware

// Legacy middleware - replaced by requireAuth
const authenticateToken: RequestHandler = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ message: 'Access token required' });
  }

  jwt.verify(token, JWT_SECRET, (err: any, decoded: any) => {
    if (err) {
      return res.status(403).json({ message: 'Invalid token' });
    }
    (req as any).userId = decoded.userId || decoded.id;
    (req as any).user = {
      id: decoded.userId || decoded.id,
      username: decoded.username,
      phone: decoded.phone,
      userType: decoded.userType,
      isVerified: decoded.isVerified
    };
    next();
  });
};

// Session configuration
function getSession() {
  const sessionTtl = 7 * 24 * 60 * 60 * 1000; // 1 week

  // Use memory store for session storage to avoid database connection issues
  const MemoryStoreClass = MemoryStore(session);
  const sessionStore = new MemoryStoreClass({
    checkPeriod: 86400000, // prune expired entries every 24h
    ttl: sessionTtl,
  });

  return session({
    secret: process.env.SESSION_SECRET || 'dairy-dash-secret-key-change-in-production',
    store: sessionStore,
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      maxAge: sessionTtl,
    },
  });
}

// Use requireAuth consistently for all authenticated routes

// Admin authorization middleware
const requireAdmin: RequestHandler = async (req, res, next) => {
  try {
    const userId = (req as any).userId;
    if (!userId) {
      return res.status(401).json({ message: "Authentication required" });
    }

    const user = await storage.getUserById(userId);
    if (!user || user.userType !== 'admin') {
      return res.status(403).json({ 
        message: "Access denied. Admin privileges required.",
        userType: user?.userType || "unknown"
      });
    }

    next();
  } catch (error: any) {
    console.error('Admin check error:', error.message);
    res.status(500).json({ message: "Authorization check failed" });
  }
};

export async function registerRoutes(app: Express): Promise<Server> {
  // Set up session middleware
  app.set("trust proxy", 1);
  app.use(getSession());

  // OTP Authentication Routes
  app.post('/api/auth/send-otp', async (req, res) => {
    const startTime = Date.now();
    console.log('🔐 [MAIN] OTP Request received:', {
      body: req.body,
      headers: {
        'content-type': req.headers['content-type'],
        'user-agent': req.headers['user-agent']?.substring(0, 50)
      },
      ip: req.ip
    });

    try {
      const { phone } = sendOTPSchema.parse(req.body);

      console.log('✅ [MAIN] Phone validation passed:', { phone });

      // Generate OTP
      const otp = generateOTP();
      const expiresAt = new Date(Date.now() + 10 * 60 * 1000); // 10 minutes

      console.log('🔢 [MAIN] Generated OTP:', { otp: otp.substring(0, 2) + '****', expiresAt: expiresAt.toISOString() });

      // Store OTP in database
      try {
        await storage.createOTP(phone, otp, expiresAt);
        console.log('✅ [MAIN] OTP stored in database successfully');
      } catch (storageError: any) {
        console.error('❌ [MAIN] Failed to store OTP in database:', {
          error: storageError.message,
          stack: storageError.stack,
          phone
        });
        throw new Error(`Database storage failed: ${storageError.message}`);
      }

      // Send SMS
      const smsMessage = `Your DOOODHWALA verification code is: ${otp}. Valid for 10 minutes. Do not share this code with anyone.`;
      console.log('📱 [MAIN] Attempting to send SMS...');

      try {
        const smsSent = await sendSMS(phone, smsMessage);
        console.log('📱 [MAIN] SMS sending result:', smsSent);

        // In production with Twilio, fail if SMS couldn't be sent
        if (!smsSent && process.env.NODE_ENV === 'production' && process.env.TWILIO_ACCOUNT_SID) {
          throw new Error('SMS delivery failed - Twilio error');
        }
      } catch (smsError: any) {
        console.error('❌ [MAIN] SMS sending failed:', {
          error: smsError.message,
          code: smsError.code,
          stack: smsError.stack
        });
        // Don't fail the request if SMS fails in development
        if (process.env.NODE_ENV === 'production') {
          throw new Error(`SMS delivery failed: ${smsError.message}`);
        }
      }

      const response = {
        success: true,
        message: "OTP sent successfully",
        // For development only - remove in production
        otp: process.env.NODE_ENV === 'development' ? otp : undefined
      };

      console.log('✅ [MAIN] OTP request completed successfully:', {
        duration: Date.now() - startTime + 'ms',
        phone: phone?.substring(0, 6) + '****'
      });

      res.json(response);

    } catch (error: any) {
      const duration = Date.now() - startTime;
      console.error('❌ [MAIN] OTP request failed:', {
        error: error.message,
        stack: error.stack,
        duration: duration + 'ms',
        body: req.body,
        type: error.constructor.name
      });

      if (error.name === 'ZodError') {
        return res.status(400).json({
          success: false,
          message: "Invalid phone number format",
          errors: error.errors,
          error: 'VALIDATION_ERROR'
        });
      }

      res.status(500).json({ 
        success: false,
        message: "Failed to send OTP. Please try again.",
        error: process.env.NODE_ENV === 'development' ? error.message : 'INTERNAL_SERVER_ERROR',
        ...(process.env.NODE_ENV === 'development' && {
          stack: error.stack,
          type: error.constructor.name
        })
      });
    }
  });

  app.post('/api/auth/verify-otp', async (req, res) => {
    try {
      const { phone, otp } = verifyOTPSchema.parse(req.body);

      // Normalize phone number - remove +91 prefix to match OTP storage format
      const normalizedPhone = phone.replace(/^\+91/, '');

      // Debug: Log verification attempt
      console.log(`Verifying OTP: phone=${phone}, normalized=${normalizedPhone}, otp=${otp}`);

      // Development bypass - allow 123456 as a test OTP (6 digits required)
      let isValid = false;
      if (process.env.NODE_ENV === 'development' && otp === '123456') {
        console.log('Development OTP bypass used: 123456');
        isValid = true;
      } else {
        // Verify OTP using normalized phone number
        isValid = await storage.verifyOTP(normalizedPhone, otp);
      }
      console.log(`OTP verification result: ${isValid}`);

      if (!isValid) {
        // Debug: Show all stored OTPs for this phone (both formats)
        const allOtps = await storage.getDebugOTPs(normalizedPhone);
        const allOtpsWithPrefix = await storage.getDebugOTPs(phone);
        console.log(`All OTPs for ${normalizedPhone}:`, allOtps);
        console.log(`All OTPs for ${phone}:`, allOtpsWithPrefix);

        // Show current time and expiry details for debugging
        const now = new Date();
        console.log(`Current time: ${now.toISOString()}`);
        allOtps.forEach(otpRecord => {
          console.log(`OTP ${otpRecord.code}: expires at ${otpRecord.expiresAt.toISOString()}, used: ${otpRecord.isUsed}, expired: ${otpRecord.expiresAt <= now}`);
        });

        return res.status(400).json({
          message: "Invalid or expired OTP"
        });
      }

      // Find or create user - try both phone formats for compatibility
      let user = null;

      // Try to find existing user by phone
      try {
        user = await storage.getUserByPhone(phone);

        if (!user) {
          // Try normalized phone format (without +91 prefix)
          user = await storage.getUserByPhone(normalizedPhone);
        }
      } catch (phoneError) {
        console.error('Error in phone lookup:', phoneError);
        user = null;
      }

      // Try to find by user ID if not found by phone
      if (!user) {
        const userId = `user_${phone.replace(/^\+91/, '')}`;
        try {
          user = await storage.getUserById(userId);
        } catch (e) {
          console.log('getUserById error:', e);
        }
      }

      // Create new user if still not found
      if (!user) {
        const userId = `user_${phone.replace(/^\+91/, '')}`;
        try {
          user = await storage.createUser({
            id: userId,
            phone,
            userType: null, // Allow user to select type during onboarding
            isVerified: true
          });

          if (!user) {
            throw new Error('Failed to create user - createUser returned undefined');
          }
        } catch (createError) {
          console.error('Error creating new user:', createError);
          throw new Error('Failed to create user account');
        }
      } else {
        // Update verification status for existing user
        if (!user.isVerified) {
          user = await storage.updateUser(user.id, { isVerified: true });
        }
      }

      if (!user) {
        throw new Error('User object is undefined after creation or retrieval');
      }

      // Generate JWT tokens using the same method as authRoutes.ts
      const tokenPayload = {
        userId: user.id,
        id: user.id, // For backward compatibility
        username: user.username || `user_${phone.substring(-4)}`,
        phone: user.phone,
        userType: user.userType,
        isVerified: user.isVerified,
      };

      // Import generateTokens from auth middleware
      const { generateTokens } = await import('./middleware/auth');
      const { accessToken, refreshToken } = generateTokens(tokenPayload);

      res.json({
        success: true,
        message: "OTP verified successfully",
        user: {
          id: user.id,
          username: user.username,
          phone: user.phone,
          userType: user.userType,
          firstName: user.firstName,
          lastName: user.lastName,
          email: user.email,
          isVerified: user.isVerified
        },
        tokens: {
          accessToken,
          refreshToken,
          expiresIn: '7d'
        }
      });
    } catch (error: any) {
      console.error('Verify OTP error:', error);
      if (error.name === 'ZodError') {
        return res.status(400).json({
          message: "Invalid phone number or OTP format",
          errors: error.errors
        });
      }
      res.status(500).json({ message: "Server error while verifying OTP" });
    }
  });



  app.post('/api/auth/logout', requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      // In JWT-based auth, logout is handled on client side by removing token
      res.json({
        success: true,
        message: "Logged out successfully"
      });
    } catch (error: any) {
      console.error('Logout error:', error);
      res.status(500).json({ message: "Server error" });
    }
  });

  // Also handle GET and POST for /logout and /api/logout for compatibility
  app.get('/logout', (req, res) => {
    res.json({ success: true, message: "Logged out successfully" });
  });

  app.post('/logout', (req, res) => {
    res.json({ success: true, message: "Logged out successfully" });
  });

  app.get('/api/logout', (req, res) => {
    res.json({ success: true, message: "Logged out successfully" });
