  // Consolidated billing routes
  // Get consolidated bill for all group members of a milkman
  app.get('/api/bills/consolidated/:milkmanId', requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const userId = req.user?.id || req.user?.username || `user_${req.user?.phone}`;
      const { milkmanId } = req.params;

      // Get all customers assigned to this milkman for group billing
      const groupMembers = await storage.getCustomersByMilkman(parseInt(milkmanId));

      // Get all chat messages with orders from group members this month
      const currentMonth = new Date().toISOString().slice(0, 7); // YYYY-MM format
      let totalAmount = 0;
      let ordersByMember = [];

      for (const member of groupMembers) {
        const messages = await storage.getChatMessages(member.id, parseInt(milkmanId));

        // Filter order messages from current month
        const monthlyOrders = messages.filter((msg: any) => {
          const msgDate = new Date(msg.createdAt);
          const msgMonth = msgDate.toISOString().slice(0, 7);
          return msg.messageType === 'order' && msgMonth === currentMonth && msg.orderTotal;
        });

        let memberTotal = 0;
        const memberOrders = monthlyOrders.map((order: any) => {
          const amount = parseFloat(order.orderTotal);
          memberTotal += amount;
          totalAmount += amount;

          return {
            id: order.id,
            date: order.createdAt,
            items: order.orderItems || [{
              product: 'Milk',
              quantity: order.orderQuantity || 1,
              price: amount,
            }],
            total: amount
          };
        });

        if (memberOrders.length > 0) {
          ordersByMember.push({
            memberId: member.id,
            memberName: member.name || 'Customer',
            orders: memberOrders,
            memberTotal
          });
        }
      }

      // If no orders found from chat messages, use current bill data for each member
      if (totalAmount <= 0) {
        totalAmount = 0;
        ordersByMember = [];

        for (const member of groupMembers) {
          // Get member's current bill
          const currentBill = await storage.getCurrentBill(member.userId);
          if (currentBill && currentBill.totalAmount > 0) {
            const memberTotal = currentBill.totalAmount;
            totalAmount += memberTotal;

            // Create order entry from current bill
            ordersByMember.push({
              memberId: member.id,
              memberName: member.name || 'Customer',
              orders: [
                {
                  id: currentBill.id,
                  date: currentBill.updatedAt || new Date().toISOString(),
                  items: currentBill.items || [{
                    product: 'Current Month Bill',
                    quantity: 1,
                    price: memberTotal
                  }],
                  total: memberTotal
                }
              ],
              memberTotal
            });
          }
        }

        // If still no bills found, show actual group members with zero amounts
        if (totalAmount <= 0 && groupMembers.length > 0) {
          return res.json({
            milkmanId: parseInt(milkmanId),
            month: currentMonth,
            totalAmount: 0,
            memberCount: groupMembers.length,
            ordersByMember: groupMembers.map(member => ({
              memberId: member.id,
              memberName: member.name || 'Customer',
              orders: [],
              memberTotal: 0
            })),
            generatedAt: new Date()
          });
        }

        // If no group members found at all
        return res.json({
          milkmanId: parseInt(milkmanId),
          month: currentMonth,
          totalAmount: 0,
          memberCount: 0,
          ordersByMember: [],
          generatedAt: new Date()
        });
      }

      res.json({
        milkmanId: parseInt(milkmanId),
        month: currentMonth,
        totalAmount,
        memberCount: ordersByMember.length,
        ordersByMember,
        generatedAt: new Date()
      });

    } catch (error: any) {
      console.error('Get consolidated bill error:', error);
      res.status(500).json({ message: error.message });
    }
  });

