      });

      // Auto-generate bill for order messages
      if (messageType === 'order' && orderTotal) {
        // Get or create current month bill
        const currentDate = new Date();
        const currentMonth = currentDate.toISOString().slice(0, 7); // YYYY-MM format

        let bill = await storage.getCurrentMonthBill(parseInt(customerId), parseInt(milkmanId));

