          bill = await storage.createBill({
            customerId: parseInt(customerId),
            milkmanId: parseInt(milkmanId),
            billMonth: currentMonth,
            totalOrders: 1,
            totalQuantity: orderQuantityNum.toString(),
            subtotal: totalAmountNum.toString(),
