            status: "pending",
            dueDate: new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 15), // Due on 15th of next month
          });
        } else {
          // Update existing bill
          const orderQuantityNum = parseFloat(orderQuantity?.toString() || '0');
          const totalAmountNum = parseFloat(orderTotal.toString());
          const currentTotal = parseFloat(bill.totalAmount.toString());
          const currentQuantity = parseFloat(bill.totalQuantity.toString());

          const newTotalOrders = bill.totalOrders + 1;
          const newTotalQuantity = currentQuantity + orderQuantityNum;
          const newTotalAmount = currentTotal + totalAmountNum;

          await storage.updateBill(bill.id, {
            totalOrders: newTotalOrders,
            totalQuantity: newTotalQuantity.toString(),
            subtotal: newTotalAmount.toString(),
            totalAmount: newTotalAmount.toString(),
          });
        }
      }

