  app.put('/api/chat/edit/:messageId', requireAuth, async (req: AuthenticatedRequest, res) => {
    try {
      const { messageId } = req.params;
      const { message, orderQuantity } = req.body;

      // Get the original message to check if it's an order and get billing details
      const originalMessage = await storage.getChatMessage(parseInt(messageId));

      // Update message if it's still editable
      const updatedMessage = await storage.updateChatMessage(parseInt(messageId), {
        message,
        orderQuantity: orderQuantity ? parseFloat(orderQuantity) : undefined,
        editedAt: new Date(),
      });

      // If it's an order message, recalculate billing
      if (originalMessage && originalMessage.messageType === 'order' && originalMessage.orderTotal && orderQuantity) {
        const customerId = originalMessage.customerId;
        const milkmanId = originalMessage.milkmanId;
        const currentMonth = new Date().toISOString().slice(0, 7);

        // Get current month bill
        const bill = await storage.getCurrentMonthBill(customerId, milkmanId);

        if (bill) {
          // Calculate the difference between old and new quantities
          const oldQuantity = parseFloat(originalMessage.orderQuantity?.toString() || '0');
          const newQuantity = parseFloat(orderQuantity);
          const quantityDifference = newQuantity - oldQuantity;

          // Calculate the price difference (assuming same price per unit)
          const pricePerUnit = parseFloat(originalMessage.orderTotal.toString()) / oldQuantity;
          const totalDifference = quantityDifference * pricePerUnit;

          // Update bill totals
          const newTotalQuantity = parseFloat(bill.totalQuantity.toString()) + quantityDifference;
          const newTotalAmount = parseFloat(bill.totalAmount.toString()) + totalDifference;

          await storage.updateBill(bill.id, {
            totalQuantity: newTotalQuantity.toString(),
            subtotal: newTotalAmount.toString(),
            totalAmount: newTotalAmount.toString(),
          });

          // Update the message's order total and recalculate orderItems if they exist
          const updateData: any = {
            orderTotal: newQuantity * pricePerUnit,
          };

          // If the message has orderItems, recalculate them proportionally
          if (originalMessage.orderItems && Array.isArray(originalMessage.orderItems)) {
            const totalOriginalQuantity = originalMessage.orderItems.reduce((sum: number, item: any) => sum + item.quantity, 0);
            const scaleFactor = newQuantity / totalOriginalQuantity;

            updateData.orderItems = originalMessage.orderItems.map((item: any) => ({
              ...item,
              quantity: item.quantity * scaleFactor,
            }));
          }

          await storage.updateChatMessage(parseInt(messageId), updateData);
        }
      }

      res.json({ success: true });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

