  // Helper function to calculate distance between two coordinates using Haversine formula
  function calculateDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
    const R = 6371; // Radius of the Earth in kilometers
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLng = (lng2 - lng1) * Math.PI / 180;
    const a = 
      Math.sin(dLat/2) * Math.sin(dLat/2) +
      Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * 
      Math.sin(dLng/2) * Math.sin(dLng/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    const distance = R * c; // Distance in kilometers
    return distance;
  }

  // Function to check for nearby milkmen and send notifications based on customer's registered address
  async function checkForNearbyMilkmen(customerId: number, customerLat?: number, customerLng?: number): Promise<void> {
    try {
      const customer = await storage.getCustomer(customerId);

      if (!customer) return;

      // Use customer's registered address coordinates from profile
      let lat = customerLat;
      let lng = customerLng;

      // If coordinates not provided, get from customer's registered address
      if (!lat || !lng) {
        if (customer.latitude && customer.longitude) {
          lat = parseFloat(customer.latitude.toString());
          lng = parseFloat(customer.longitude.toString());
        } else {
          console.log(`Customer ${customerId} has no registered address coordinates for proximity notifications`);
          return;
        }
      }

      const availableMilkmen = await storage.getAvailableMilkmen(lat, lng);

      // Filter milkmen within 200 meters (0.2 km) of registered address
      const nearbyMilkmen = availableMilkmen.filter(milkman => {
        if (!milkman.latitude || !milkman.longitude) return false;
        const milkmanLat = parseFloat(milkman.latitude.toString());
        const milkmanLng = parseFloat(milkman.longitude.toString());
        const distance = calculateDistance(lat!, lng!, milkmanLat, milkmanLng);
        return distance <= 0.2; // Within 200 meters
      });

      // Send notifications for nearby milkmen
      for (const milkman of nearbyMilkmen) {
        // Check if notification was already sent today
        const today = new Date();
        today.setHours(0, 0, 0, 0);

        const existingNotifications = await storage.getNotifications(customer.userId);
        const todayNotification = existingNotifications.find(notification => 
          notification.relatedId === milkman.id &&
          notification.type === 'proximity' &&
          notification.createdAt >= today
        );

        if (!todayNotification) {
          // Send notification to customer
          await storage.createNotification({
            userId: customer.userId,
            title: "Your Doodhwala is Nearby! 🥛",
            message: `${milkman.contactName} from ${milkman.businessName} is within 200m of your registered address. Place your order for fresh milk delivery!`,
            type: 'proximity',
            relatedId: milkman.id,
            isRead: false,
          });

          console.log(`Proximity notification sent to customer ${customerId} for milkman ${milkman.contactName} (200m radius from registered address)`);
        }
      }
    } catch (error) {
      console.error('Error checking for nearby milkmen:', error);
    }
  }

