  // Function to generate and send monthly bill
  async function generateAndSendMonthlyBill(customerId: number, milkmanId: number, month: number, year: number): Promise<void> {
    try {
      const customer = await storage.getCustomer(customerId);
      const milkman = await storage.getMilkman(milkmanId);

      if (!customer || !milkman) {
        console.error(`Customer ${customerId} or milkman ${milkmanId} not found`);
        return;
      }

      // Get orders from previous month
      const startDate = new Date(year, month - 1, 1);
      const endDate = new Date(year, month, 0, 23, 59, 59);

      const orders = await storage.getOrdersByCustomer(customerId);
      const monthlyOrders = orders.filter(order => 
        order.milkmanId === milkmanId &&
        order.createdAt >= startDate && 
        order.createdAt <= endDate &&
        order.status === 'delivered'
      );

      if (monthlyOrders.length === 0) {
        console.log(`No orders found for customer ${customerId} and milkman ${milkmanId} in ${month}/${year}`);
        return;
      }

      // Calculate totals
      const totalAmount = monthlyOrders.reduce((sum, order) => 
        sum + parseFloat(order.totalAmount.toString()), 0
      );
      const totalQuantity = monthlyOrders.reduce((sum, order) => 
        sum + parseFloat(order.quantity.toString()), 0
      );

      // Create bill record
      const bill = await storage.createBill({
        customerId,
        milkmanId,
        month,
        year,
        totalAmount: totalAmount.toString(),
        totalQuantity: totalQuantity.toString(),
        orderIds: monthlyOrders.map(o => o.id),
        status: 'pending',
        dueDate: new Date(year, month, 15), // Due on 15th of current month
        generatedAt: new Date(),
      });

      // Send bill as chat message from milkman
      const billMessage = `📋 **Monthly Bill - ${getMonthName(month)} ${year}**\n\n` +
        `Dear ${customer.fullName || 'Valued Customer'},\n\n` +
        `Here's your milk delivery summary:\n` +
        `• Total Quantity: ${totalQuantity.toFixed(1)} liters\n` +
        `• Total Orders: ${monthlyOrders.length}\n` +
        `• **Total Amount: ₹${totalAmount.toFixed(2)}**\n` +
        `• Due Date: ${new Date(year, month, 15).toLocaleDateString('en-IN')}\n\n` +
        `Thank you for choosing ${milkman.businessName}!\n` +
        `For any queries, please contact: ${milkman.phone}`;

      // Send as chat message from milkman
      const chatMessage = await storage.createChatMessage({
        customerId,
        milkmanId,
        message: billMessage,
        senderType: 'milkman',
        timestamp: new Date(),
        messageType: 'bill',
        billId: bill.id,
        isRead: false,
        isDelivered: false,
        isAccepted: false,
      });

      // Create notification for customer
      await storage.createNotification({
        userId: customer.userId,
        title: "Monthly Bill Received",
        message: `Your ${getMonthName(month)} ${year} bill of ₹${totalAmount.toFixed(2)} from ${milkman.businessName} is ready.`,
        type: 'bill',
        relatedId: bill.id,
        isRead: false,
      });

      console.log(`Monthly bill generated and sent to customer ${customerId} from milkman ${milkmanId}`);

    } catch (error) {
      console.error('Error generating monthly bill:', error);
    }
  }

