  // Background service for automatic monthly bill generation
  function scheduleMonthlyBillGeneration() {
    const now = new Date();
    const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1, 9, 0, 0); // 1st of next month at 9 AM
    const timeUntilNext = Math.min(nextMonth.getTime() - now.getTime(), 2147483647); // Prevent overflow

    // Only schedule if there's a reasonable time to wait (not in the past or too far future)
    if (timeUntilNext > 0 && timeUntilNext <= 2147483647) {
      setTimeout(async () => {
        console.log('Starting automated monthly bill generation...');

        try {
          const billGenTime = new Date();
          const previousMonth = billGenTime.getMonth() === 0 ? 12 : billGenTime.getMonth();
          const year = billGenTime.getMonth() === 0 ? billGenTime.getFullYear() - 1 : billGenTime.getFullYear();

          // Get all customer-milkman relationships from previous month
          const orders = await storage.getAllOrders();
          const uniquePairs = new Set<string>();

          const startOfPrevMonth = new Date(year, previousMonth - 1, 1);
          const endOfPrevMonth = new Date(year, previousMonth, 0, 23, 59, 59);

          orders.forEach(order => {
            if (order.status === 'delivered' && 
                order.createdAt >= startOfPrevMonth && 
                order.createdAt <= endOfPrevMonth) {
              uniquePairs.add(`${order.customerId}-${order.milkmanId}`);
            }
          });

          let billsGenerated = 0;
          for (const pair of uniquePairs) {
            const [customerId, milkmanId] = pair.split('-').map(Number);
            await generateAndSendMonthlyBill(customerId, milkmanId, previousMonth, year);
            billsGenerated++;
          }

          console.log(`Automated monthly bill generation completed: ${billsGenerated} bills generated`);

          // Schedule next month's generation recursively
          scheduleMonthlyBillGeneration();
        } catch (error) {
          console.error('Error in automated monthly bill generation:', error);
        }
      }, timeUntilNext);

      console.log(`Next monthly bill generation scheduled for: ${nextMonth.toISOString()}`);
    } else {
      console.log('Monthly bill generation scheduling skipped due to timing constraints');
    }
  }

