        return res.status(400).json({ error: "Chat name and milkman ID are required" });
      }

      const familyChat = await storage.createFamilyChat(chatName, milkmanId, userId);
      res.json(familyChat);
    } catch (error: any) {
      console.error('Error creating family chat:', error);
      res.status(500).json({ error: error.message });
    }
  });

  app.post("/api/family-chats/join", authenticateToken, async (req, res) => {
    try {
      const userId = req.user?.id;
      if (!userId) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      const { chatCode } = req.body;

      if (!chatCode) {
        return res.status(400).json({ error: "Chat code is required" });
      }

      const familyChat = await storage.joinFamilyChat(chatCode, userId);
      res.json(familyChat);
    } catch (error: any) {
      console.error('Error joining family chat:', error);
      res.status(400).json({ error: error.message });
    }
  });

  app.get("/api/family-chats/my-chats", authenticateToken, async (req, res) => {
    try {
      const userId = req.user?.id;
      if (!userId) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      const chats = await storage.getUserFamilyChats(userId);
      res.json(chats);
    } catch (error: any) {
      console.error('Error fetching family chats:', error);
      res.status(500).json({ error: error.message });
    }
  });

  app.get("/api/family-chats/:chatId", authenticateToken, async (req, res) => {
    try {
      const userId = req.user?.id;
      const chatId = parseInt(req.params.chatId);

      if (!userId) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      // Verify user is a member of this chat
      const userChats = await storage.getUserFamilyChats(userId);
      const isUserMember = userChats.some(chat => chat.id === chatId);

      if (!isUserMember) {
        return res.status(403).json({ error: "You are not a member of this chat" });
      }

      const familyChat = await storage.getFamilyChat(chatId);
      if (!familyChat) {
        return res.status(404).json({ error: "Family chat not found" });
      }

      res.json(familyChat);
    } catch (error: any) {
      console.error('Error fetching family chat:', error);
      res.status(500).json({ error: error.message });
    }
  });

  app.get("/api/family-chats/:chatId/messages", authenticateToken, async (req, res) => {
    try {
      const userId = req.user?.id;
      const chatId = parseInt(req.params.chatId);

      if (!userId) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      // Verify user is a member of this chat
      const userChats = await storage.getUserFamilyChats(userId);
      const isUserMember = userChats.some(chat => chat.id === chatId);

      if (!isUserMember) {
        return res.status(403).json({ error: "You are not a member of this chat" });
      }

      const messages = await storage.getFamilyChatMessages(chatId);
      res.json(messages);
    } catch (error: any) {
      console.error('Error fetching family chat messages:', error);
      res.status(500).json({ error: error.message });
    }
  });

  app.post("/api/family-chats/:chatId/messages", authenticateToken, async (req, res) => {
    try {
      const userId = req.user?.id;
      const chatId = parseInt(req.params.chatId);

      if (!userId) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      const { message, messageType = 'text', orderItems } = req.body;

      if (!message) {
        return res.status(400).json({ error: "Message is required" });
      }

      // Verify user is a member of this chat
      const userChats = await storage.getUserFamilyChats(userId);
      const isUserMember = userChats.some(chat => chat.id === chatId);

      if (!isUserMember) {
        return res.status(403).json({ error: "You are not a member of this chat" });
      }

      const chatMessage = await storage.sendFamilyChatMessage(
        chatId,
        userId,
        message,
        messageType,
        orderItems
      );

      res.json(chatMessage);
    } catch (error: any) {
      console.error('Error sending family chat message:', error);
      res.status(500).json({ error: error.message });
    }
  });

  app.delete("/api/family-chats/:chatId/leave", authenticateToken, async (req, res) => {
    try {
      const userId = req.user?.id;
      const chatId = parseInt(req.params.chatId);

      if (!userId) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      await storage.leaveFamilyChat(chatId, userId);
      res.json({ message: "Successfully left family chat" });
    } catch (error: any) {
      console.error('Error leaving family chat:', error);
      res.status(500).json({ error: error.message });
    }
  });

  // WebSocket server for real-time chat
  const wss = new WebSocketServer({ server: httpServer, path: '/ws' });

  // Store connected clients with their user information
  const connectedClients = new Map<string, { ws: WebSocket, userId: string, userType: 'customer' | 'milkman' }>();

  wss.on('connection', (ws, req) => {
    console.log('New WebSocket connection');

    // Handle WebSocket messages
    ws.on('message', async (message) => {
      try {
        const data = JSON.parse(message.toString());

        if (data.type === 'authenticate') {
          // Authenticate user and store connection
          const { userId, userType } = data;
          // Create unique connection key based on user type and ID
          const connectionKey = userType === 'customer' ? `user_cust_${userId}` : `user_milkman_${userId}`;
          connectedClients.set(connectionKey, { ws, userId, userType });
          console.log(`User ${userId} (${userType}) connected via WebSocket with key: ${connectionKey}`);

          ws.send(JSON.stringify({ type: 'authenticated', userId }));
        } else if (data.type === 'chat_message') {
          // Handle new chat message
          const { customerId, milkmanId, message: messageText, senderType } = data;

          // Save message to database
          const chatMessage = await storage.createChatMessage({
            customerId: parseInt(customerId),
            milkmanId: parseInt(milkmanId),
            message: messageText,
            senderType,
            timestamp: new Date(),
            isRead: false,
            isDelivered: false,
            isAccepted: false,
          });

          // Send message to recipient
          const recipientType = senderType === 'customer' ? 'milkman' : 'customer';
          const recipientId = senderType === 'customer' ? `user_milkman_${milkmanId}` : `user_cust_${customerId}`;

          const recipientConnection = connectedClients.get(recipientId);
          if (recipientConnection && recipientConnection.ws.readyState === WebSocket.OPEN) {
            recipientConnection.ws.send(JSON.stringify({
              type: 'new_message',
              message: chatMessage,
              customerId,
              milkmanId
            }));
          }

          // Send confirmation to sender
          ws.send(JSON.stringify({
            type: 'message_sent',
            message: chatMessage
          }));
        } else if (data.type === 'mark_messages_read') {
          // Mark messages as read
          const { customerId, milkmanId, senderType } = data;
          await storage.markMessagesAsRead(parseInt(customerId), parseInt(milkmanId), senderType);

          // Notify the other party that messages were read
          const otherPartyType = senderType === 'customer' ? 'milkman' : 'customer';
          const otherPartyId = senderType === 'customer' ? `user_milkman_${milkmanId}` : `user_cust_${customerId}`;

          const otherPartyConnection = connectedClients.get(otherPartyId);
          if (otherPartyConnection && otherPartyConnection.ws.readyState === WebSocket.OPEN) {
            otherPartyConnection.ws.send(JSON.stringify({
              type: 'messages_read',
              customerId,
              milkmanId
            }));
          }
        } else if (data.type === 'order_accepted') {
          // Handle order acceptance
          const { messageId, customerId, milkmanId } = data;
          await storage.markMessageAsAccepted(parseInt(messageId));

          // Notify customer that order was accepted
          const customerConnection = connectedClients.get(`user_cust_${customerId}`);
          if (customerConnection && customerConnection.ws.readyState === WebSocket.OPEN) {
            customerConnection.ws.send(JSON.stringify({
              type: 'order_accepted',
              messageId,
              customerId,
              milkmanId
            }));
          }
        }
      } catch (error) {
        console.error('WebSocket message error:', error);
        ws.send(JSON.stringify({ type: 'error', message: 'Invalid message format' }));
      }
    });

    ws.on('close', () => {
      // Remove client from connected clients
      for (const [userId, client] of connectedClients.entries()) {
        if (client.ws === ws) {
          connectedClients.delete(userId);
          console.log(`User ${userId} disconnected from WebSocket`);
          break;
        }
      }
    });

    ws.on('error', (error) => {
      console.error('WebSocket error:', error);
    });
  });

  return httpServer;
}

