import express, { type Express } from "express";
import path from "path";
import fs from "fs";

export function serveStaticFixed(app: Express) {
  // Fix: Use correct path to dist/public
  const distPath = path.resolve(process.cwd(), "dist", "public");

  console.log(`[Static] Looking for static files at: ${distPath}`);
  console.log(`[Static] Directory exists: ${fs.existsSync(distPath)}`);

  if (!fs.existsSync(distPath)) {
    throw new Error(
      `Could not find the build directory: ${distPath}, make sure to build the client first`,
    );
  }

  // List assets for debugging
  const assetsPath = path.join(distPath, 'assets');
  if (fs.existsSync(assetsPath)) {
    console.log(`[Static] Assets found:`, fs.readdirSync(assetsPath));
  }

  // Priority route for assets directory
  app.use('/assets', express.static(path.join(distPath, 'assets'), {
    maxAge: process.env.NODE_ENV === 'production' ? '31536000' : '0',
    etag: true,
    lastModified: true,
    setHeaders: (res, filePath) => {
      const ext = path.extname(filePath).toLowerCase();

      // Set correct MIME types explicitly
      switch (ext) {
        case '.js':
          res.setHeader('Content-Type', 'application/javascript; charset=utf-8');
          break;
        case '.css':
          res.setHeader('Content-Type', 'text/css; charset=utf-8');
          break;
        case '.png':
          res.setHeader('Content-Type', 'image/png');
          break;
        case '.jpg':
        case '.jpeg':
          res.setHeader('Content-Type', 'image/jpeg');
          break;
        case '.svg':
          res.setHeader('Content-Type', 'image/svg+xml');
          break;
      }

      // Set cache control for assets
      res.setHeader('Cache-Control', process.env.NODE_ENV === 'production' 
        ? 'public, max-age=31536000, immutable' 
        : 'no-cache');

      console.log(`[Assets] Serving ${ext} file: ${path.basename(filePath)} (${res.getHeader('Content-Type')})`);
    }
  }));

  // Serve other static files from root
  app.use(express.static(distPath, {
    maxAge: process.env.NODE_ENV === 'production' ? '86400' : '0',
    etag: true,
    lastModified: true,
    index: false,
  }));

  // catch-all fallback for SPA routing (MUST be last)
  app.get("*", (_req, res) => {
    const indexPath = path.resolve(distPath, "index.html");
    console.log(`[Static] SPA fallback to index.html for: ${_req.originalUrl}`);

    // Only serve index.html for GET requests that don't match static files
    if (_req.path.startsWith('/api/') || _req.path.startsWith('/assets/')) {
      return res.status(404).json({ error: 'Not found' });
    }

    // Set proper HTML content type
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate');

    res.sendFile(indexPath);
  });
}

