  async getValidOTP(phone: string, code: string): Promise<OtpCode | undefined> {
    const now = new Date();
    return Array.from(this.otpCodes.values()).find(
      otp => otp.phone === phone && otp.code === code && !otp.isUsed && otp.expiresAt > now
    );
  }

  async verifyOTP(phone: string, code: string): Promise<boolean> {
    const otp = await this.getValidOTP(phone, code);
    if (otp) {
      await this.markOTPAsUsed(otp.id);
      return true;
    }
    return false;
  }

  async markOTPAsUsed(id: number): Promise<void> {
    const otp = this.otpCodes.get(id);
    if (otp) {
      // Create a new object with isUsed set to true to ensure the Map is updated
      const updatedOtp = { ...otp, isUsed: true };
      this.otpCodes.set(id, updatedOtp);
    }
  }

