  async getAvailableMilkmen(lat?: number, lng?: number): Promise<Milkman[]> {
    const availableMilkmen = Array.from(this.milkmen.values()).filter(m => m.isAvailable);

    if (!lat || !lng) {
      return availableMilkmen;
    }

    // Calculate distance and sort by proximity
    const milkmenWithDistance = availableMilkmen.map(milkman => {
      const distance = this.calculateDistance(
        lat, lng,
        parseFloat(milkman.latitude || '0'),
        parseFloat(milkman.longitude || '0')
      );
      return { ...milkman, distance };
    });

    // Sort by distance (closest first)
    return milkmenWithDistance.sort((a, b) => a.distance - b.distance);
  }

  private calculateDistance(lat1: number, lon1: number, lat2: number, lon2: number): number {
    const R = 6371; // Radius of the Earth in kilometers
    const dLat = this.deg2rad(lat2 - lat1);
    const dLon = this.deg2rad(lon2 - lon1);
    const a = 
      Math.sin(dLat/2) * Math.sin(dLat/2) +
      Math.cos(this.deg2rad(lat1)) * Math.cos(this.deg2rad(lat2)) * 
      Math.sin(dLon/2) * Math.sin(dLon/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    return R * c; // Distance in kilometers
  }

  private deg2rad(deg: number): number {
    return deg * (Math.PI/180);
  }

