  async getActiveAds(position?: string, targetAudience?: string, targetLocation?: string): Promise<Ad[]> {
    const now = new Date();
    return Array.from(this.ads.values())
      .filter(ad => {
        if (!ad.isActive) return false;
        if (ad.endDate && ad.endDate < now) return false;
        if (ad.startDate && ad.startDate > now) return false;
        if (position && ad.position !== position) return false;
        if (targetAudience && ad.targetAudience !== 'all' && ad.targetAudience !== targetAudience) return false;
        if (targetLocation && ad.targetLocation && !ad.targetLocation.includes(targetLocation)) return false;
        return true;
      })
      .sort((a, b) => (b.priority || 1) - (a.priority || 1));
  }

