      if (stats.clicks !== undefined) ad.clicks = (ad.clicks || 0) + stats.clicks;
      if (stats.conversions !== undefined) ad.conversions = (ad.conversions || 0) + stats.conversions;
      ad.updatedAt = new Date();
      this.ads.set(id, ad);
    }
  }

