  async getAdminStats(): Promise<{
    totalUsers: number;
    totalMilkmen: number;
    totalOrders: number;
    totalRevenue: number;
    dailyOrders: number;
    weeklyRevenue: number;
    pendingOrders: number;
    activeUsers: number;
  }> {
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

    const allOrders = Array.from(this.orders.values());
    const allPayments = Array.from(this.payments.values());

    // Daily orders (today)
    const dailyOrders = allOrders.filter(order => 
      order.createdAt >= today
    ).length;

    // Weekly revenue
    const weeklyRevenue = allPayments
      .filter(payment => 
        payment.status === 'completed' && 
        payment.createdAt >= weekAgo
      )
      .reduce((sum, payment) => sum + parseFloat(payment.amount.toString()), 0);

    // Total revenue
    const totalRevenue = allPayments
      .filter(payment => payment.status === 'completed')
      .reduce((sum, payment) => sum + parseFloat(payment.amount.toString()), 0);

    // Pending orders
    const pendingOrders = allOrders.filter(order => 
      order.status === 'pending'
    ).length;

    // Active users (users who have placed orders in last 30 days)
    const monthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
    const activeUsers = new Set(
      allOrders
        .filter(order => order.createdAt >= monthAgo)
        .map(order => order.userId)
    ).size;

    return {
      totalUsers: this.users.size,
      totalMilkmen: this.milkmen.size,
      totalOrders: this.orders.size,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
      dailyOrders,
      weeklyRevenue: Math.round(weeklyRevenue * 100) / 100,
      pendingOrders,
      activeUsers,
    };
  }

