export class DatabaseStorage implements IStorage {
  // User operations (mandatory for Replit Auth)
  async getUser(id: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.id, id));
    return user;
  }

  async getUserById(id: string): Promise<User | undefined> {
    return this.getUser(id);
  }

  async getAllUsers(): Promise<User[]> {
    const allUsers = await db.select().from(users);
    return allUsers;
  }

  async createUser(user: { id: string; phone: string; userType?: string | null; isVerified?: boolean; username?: string }): Promise<User> {
    try {
      console.log('DatabaseStorage.createUser called with:', JSON.stringify(user, null, 2));

      const userData = {
        id: user.id,
        phone: user.phone,
        username: user.username || `user_${user.phone.replace(/^\+91/, '')}`,
        userType: user.userType === undefined ? null : user.userType,
        isVerified: user.isVerified ?? false,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      console.log('userData being inserted:', JSON.stringify(userData, null, 2));

      const [newUser] = await db.insert(users).values(userData).returning();

      console.log('newUser created successfully:', JSON.stringify(newUser, null, 2));
      return newUser;
    } catch (error) {
      console.error('DatabaseStorage.createUser error:', error);
      throw error;
    }
  }

  async updateUser(id: string, updates: Partial<User>): Promise<User> {
    const [updatedUser] = await db
      .update(users)
      .set({ ...updates, updatedAt: new Date() })
      .where(eq(users.id, id))
      .returning();
    return updatedUser;
  }

  async upsertUser(userData: UpsertUser): Promise<User> {
    const [user] = await db
      .insert(users)
      .values(userData)
      .onConflictDoUpdate({
        target: users.id,
        set: {
          ...userData,
          updatedAt: new Date(),
        },
      })
      .returning();
    return user;
  }

  async getUserByPhone(phone: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.phone, phone));
    return user;
  }

  async getUserByEmail(email: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.email, email));
    return user;
  }

  async updateUserVerification(id: string, isVerified: boolean): Promise<void> {
    await db
      .update(users)
      .set({ isVerified, updatedAt: new Date() })
      .where(eq(users.id, id));
  }

  // OTP operations
  async createOTP(phone: string, code: string, expiresAt: Date): Promise<void> {
    await db.insert(otpCodes).values({
      phone,
      code,
      expiresAt,
    });
  }

  async getValidOTP(phone: string, code: string): Promise<OtpCode | undefined> {
    const now = new Date();
    const [otp] = await db
      .select()
      .from(otpCodes)
      .where(
        and(
          eq(otpCodes.phone, phone),
          eq(otpCodes.code, code),
          eq(otpCodes.isUsed, false),
          gte(otpCodes.expiresAt, now)
        )
      );
    return otp;
  }

  async markOTPAsUsed(id: number): Promise<void> {
    await db
      .update(otpCodes)
      .set({ isUsed: true })
      .where(eq(otpCodes.id, id));
  }

  async verifyOTP(phone: string, code: string): Promise<boolean> {
