  async generateMonthlyBills(): Promise<Bill[]> {
    const now = new Date();
    const previousMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
    const billMonth = previousMonth.toISOString().slice(0, 7); // YYYY-MM format

    console.log(`🧾 Generating monthly bills for ${billMonth}...`);

    const generatedBills: Bill[] = [];

    // Get all unique customer-milkman pairs from the previous month's delivered orders
    const deliveredOrders = await db
      .select()
      .from(orders)
      .where(
        and(
          eq(orders.status, 'delivered'),
          gte(orders.createdAt, new Date(billMonth + '-01')),
          gte(new Date(billMonth + '-31'), orders.createdAt)
        )
      );

    const processedPairs = new Set<string>();

    for (const order of deliveredOrders) {
      const pairKey = `${order.customerId}-${order.milkmanId}`;

      if (!processedPairs.has(pairKey)) {
        processedPairs.add(pairKey);

        // Check if bill already exists for this pair and month
        const [existingBill] = await db
          .select()
          .from(bills)
          .where(
            and(
              eq(bills.customerId, order.customerId),
              eq(bills.milkmanId, order.milkmanId),
              eq(bills.billMonth, billMonth)
            )
          );

        if (!existingBill) {
          // Get all orders for this customer-milkman pair in the previous month
          const monthOrders = await this.getPreviousMonthOrders(
            order.customerId,
            order.milkmanId,
            billMonth
          );

          if (monthOrders.length > 0) {
            // Calculate bill details
            const totalAmount = monthOrders.reduce((sum, o) => sum + (o.totalAmount || 0), 0);

            // Get customer and milkman details
            const [customer] = await db.select().from(customers).where(eq(customers.id, order.customerId));
            const [milkman] = await db.select().from(milkmen).where(eq(milkmen.id, order.milkmanId));

            if (customer && milkman) {
              const billData: InsertBill = {
                customerId: order.customerId,
                milkmanId: order.milkmanId,
                billMonth,
                totalAmount,
                totalOrders: monthOrders.length,
                items: monthOrders.map(o => ({
                  date: o.createdAt.toISOString().split('T')[0],
                  product: o.items?.[0]?.name || 'Fresh Milk',
                  quantity: o.quantity || 1,
                  price: o.totalAmount || 0,
                  deliveredAt: o.deliveredAt?.toISOString().split('T')[0] || o.createdAt.toISOString().split('T')[0]
                })),
                status: 'pending',
                dueDate: new Date(now.getFullYear(), now.getMonth(), 15) // 15th of current month
              };

              const bill = await this.createBill(billData);
              generatedBills.push(bill);

              // Send bill notification in chat
              await this.sendBillNotificationInChat(customer, milkman, bill);

              console.log(`✅ Generated bill #${bill.id} for ${customer.name} - ${milkman.name}: ₹${totalAmount}`);
            }
          }
        }
      }
    }

    console.log(`🎉 Generated ${generatedBills.length} monthly bills for ${billMonth}`);
    return generatedBills;
  }

  private async sendBillNotificationInChat(customer: Customer, milkman: Milkman, bill: Bill): Promise<void> {
    const billMessage = `📋 *Monthly Bill Generated*\n\n` +
      `Dear ${customer.name},\n\n` +
      `Your monthly bill for ${bill.billMonth} has been generated.\n\n` +
      `📊 *Bill Summary:*\n` +
      `• Total Orders: ${bill.totalOrders}\n` +
      `• Total Amount: ₹${bill.totalAmount}\n` +
      `• Due Date: ${bill.dueDate?.toLocaleDateString('en-IN')}\n\n` +
      `💳 *Payment Options:*\n` +
      `• Online Payment (UPI/Card/Net Banking)\n` +
      `• Cash on Delivery\n` +
      `• Digital Wallet\n\n` +
      `Click to view detailed bill and make payment.\n\n` +
      `Thank you for choosing our service! 🥛\n` +
      `- ${milkman.name}`;

    const messageData: InsertChatMessage = {
      customerId: customer.id,
      milkmanId: milkman.id,
      message: billMessage,
      messageType: 'bill',
      billId: bill.id,
      senderType: 'milkman'
    };

    await this.createChatMessage(messageData);
  }

