  async getActiveAds(position?: string, targetAudience?: string, targetLocation?: string): Promise<Ad[]> {
    const now = new Date();
    let query = db
      .select()
      .from(ads)
      .where(
        and(
          eq(ads.isActive, true),
          gte(ads.endDate, now),
          gte(now, ads.startDate)
        )
      );

    let activeAds = await query;

    if (position) {
      activeAds = activeAds.filter(ad => ad.position === position);
    }

    if (targetAudience) {
      activeAds = activeAds.filter(ad => 
        !ad.targetAudience || 
        ad.targetAudience === targetAudience
      );
    }

    if (targetLocation) {
      activeAds = activeAds.filter(ad => 
        !ad.targetLocation || 
        ad.targetLocation === targetLocation ||
        ad.targetLocation === 'India'
      );
    }

    return activeAds.sort((a, b) => (b.priority || 0) - (a.priority || 0));
  }

