  async getAdAnalytics(adId: number): Promise<any> {
    const ad = await this.getAd(adId);
    if (!ad) return null;

    const events = await db
      .select()
      .from(adTracking)
      .where(eq(adTracking.adId, adId))
      .orderBy(desc(adTracking.createdAt))
      .limit(100);

    const impressions = events.filter(e => e.event === 'impression').length;
    const clicks = events.filter(e => e.event === 'click').length;
    const conversions = events.filter(e => e.event === 'conversion').length;

    return {
      id: adId,
      title: ad.title,
      impressions,
      clicks,
      conversions,
      ctr: impressions > 0 ? (clicks / impressions) * 100 : 0,
      conversionRate: clicks > 0 ? (conversions / clicks) * 100 : 0,
      totalSpent: (clicks * (ad.costPerClick || 0)) + (impressions * (ad.costPerImpression || 0)),
      events: events.slice(0, 50)
    };
  }

