  async getPaymentsByOrderId(orderId: string): Promise<Payment[]> {
    return await db
      .select()
      .from(payments)
      .where(eq(payments.orderId, orderId))
      .orderBy(desc(payments.createdAt));
  }

  // ================================
  // ADMIN OPERATIONS
  // ================================

  async getAdminStats(): Promise<{
    totalUsers: number;
    totalMilkmen: number;
    totalOrders: number;
    totalRevenue: number;
    dailyOrders: number;
    weeklyRevenue: number;
    pendingOrders: number;
    activeUsers: number;
  }> {
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    const monthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

    // Get all basic counts
    const [totalUsers] = await db.select({ count: db.$count() }).from(users);
    const [totalMilkmen] = await db.select({ count: db.$count() }).from(milkmen);
    const [totalOrders] = await db.select({ count: db.$count() }).from(orders);

    // Daily orders
    const [dailyOrdersResult] = await db
      .select({ count: db.$count() })
      .from(orders)
      .where(gte(orders.createdAt, today));

    // Pending orders
    const [pendingOrdersResult] = await db
      .select({ count: db.$count() })
      .from(orders)
      .where(eq(orders.status, 'pending'));

    // Active users in last 30 days
    const [activeUsersResult] = await db
      .selectDistinct({ userId: orders.userId })
      .from(orders)
      .where(gte(orders.createdAt, monthAgo));

    // Total revenue (completed payments)
    const revenueResults = await db
      .select({ amount: payments.amount })
      .from(payments)
      .where(eq(payments.status, 'completed'));

    const totalRevenue = revenueResults.reduce((sum, payment) => 
      sum + parseFloat(payment.amount.toString()), 0
    );

    // Weekly revenue
    const weeklyRevenueResults = await db
      .select({ amount: payments.amount })
      .from(payments)
      .where(
        and(
          eq(payments.status, 'completed'),
          gte(payments.createdAt, weekAgo)
        )
      );

    const weeklyRevenue = weeklyRevenueResults.reduce((sum, payment) => 
      sum + parseFloat(payment.amount.toString()), 0
    );

    return {
      totalUsers: totalUsers.count,
      totalMilkmen: totalMilkmen.count,
      totalOrders: totalOrders.count,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
      dailyOrders: dailyOrdersResult.count,
      weeklyRevenue: Math.round(weeklyRevenue * 100) / 100,
      pendingOrders: pendingOrdersResult.count,
      activeUsers: activeUsersResult.length,
    };
  }

  async getAllUsers(): Promise<User[]> {
    return await db
      .select()
      .from(users)
      .orderBy(desc(users.createdAt));
  }

  async getAllMilkmen(): Promise<Milkman[]> {
    return await db
      .select()
      .from(milkmen)
      .orderBy(desc(milkmen.createdAt));
  }

  async getAllOrders(): Promise<Order[]> {
    return await db
      .select()
      .from(orders)
      .orderBy(desc(orders.createdAt));
  }

  async getAllPayments(): Promise<Payment[]> {
    return await db
      .select()
      .from(payments)
      .orderBy(desc(payments.createdAt));
  }

  async updateMilkmanVerification(milkmanId: number, verified: boolean): Promise<boolean> {
    try {
      const [result] = await db
        .update(milkmen)
        .set({ verified, updatedAt: new Date() })
        .where(eq(milkmen.id, milkmanId))
        .returning({ id: milkmen.id });

      return !!result;
    } catch (error) {
      console.error('Error updating milkman verification:', error);
      return false;
    }
  }


  async createAdminUser(phone: string): Promise<User> {
    const adminUserId = `admin_${phone}`;

    const adminUserData = {
      id: adminUserId,
      phone,
      username: `Admin_${phone}`,
      email: `admin_${phone}@dooodhwala.com`,
      fullName: `Admin User ${phone}`,
      userType: 'admin' as const,
      isVerified: true,
      preferences: {},
    };

    const [adminUser] = await db
      .insert(users)
      .values(adminUserData)
      .onConflictDoUpdate({
        target: users.id,
        set: {
          ...adminUserData,
          updatedAt: new Date(),
        },
      })
      .returning();

    return adminUser;
  }

  // Location tracking methods for proximity notifications
  async updateUserLocation(userId: string, latitude: number, longitude: number): Promise<void> {
    // Update user's location in the users table
    await db
      .update(users)
      .set({ 
        latitude: latitude.toString(),
        longitude: longitude.toString(),
        updatedAt: new Date() 
      })
      .where(eq(users.id, userId));

    // Also create location tracking record
    await db.insert(locations).values({
      userId,
      latitude: latitude.toString(),
      longitude: longitude.toString(),
      timestamp: new Date(),
    });

    console.log(`Location updated for user ${userId}: ${latitude}, ${longitude}`);
  }

  // Family chat operations
  async createFamilyChat(chatName: string, milkmanId: number, createdBy: string): Promise<any> {
    // Generate unique 6-digit code
    const chatCode = Math.floor(100000 + Math.random() * 900000).toString();

    const [familyChat] = await db
      .insert(familyChats)
      .values({
        chatName,
        milkmanId,
        createdBy,
        chatCode,
        isActive: true,
      })
      .returning();

    // Add creator as admin member
    await db
      .insert(familyChatMembers)
      .values({
        chatId: familyChat.id,
        userId: createdBy,
        isAdmin: true,
      });

    return {
      ...familyChat,
      members: [{
        userId: createdBy,
        isAdmin: true,
        joinedAt: new Date(),
      }]
    };
  }

  async joinFamilyChat(chatCode: string, userId: string): Promise<any> {
    // Find the family chat
    const [familyChat] = await db
      .select()
      .from(familyChats)
      .where(and(
        eq(familyChats.chatCode, chatCode),
        eq(familyChats.isActive, true)
      ));

    if (!familyChat) {
      throw new Error('Invalid chat code or chat not found');
    }

    // Check if user is already a member
    const [existingMember] = await db
      .select()
      .from(familyChatMembers)
      .where(and(
        eq(familyChatMembers.chatId, familyChat.id),
        eq(familyChatMembers.userId, userId)
      ));

    if (existingMember) {
      throw new Error('You are already a member of this chat');
    }

    // Add user as member
    await db
      .insert(familyChatMembers)
      .values({
        chatId: familyChat.id,
        userId: userId,
        isAdmin: false,
      });

    // Send join notification in chat
    await this.sendFamilyChatMessage(
      familyChat.id,
      'system',
      `A new family member has joined the chat`,
      'join'
    );

    return familyChat;
  }

  async getUserFamilyChats(userId: string): Promise<any[]> {
    const chats = await db
      .select({
        id: familyChats.id,
        chatName: familyChats.chatName,
        milkmanId: familyChats.milkmanId,
        createdBy: familyChats.createdBy,
        chatCode: familyChats.chatCode,
        isActive: familyChats.isActive,
        createdAt: familyChats.createdAt,
      })
      .from(familyChats)
      .innerJoin(familyChatMembers, eq(familyChatMembers.chatId, familyChats.id))
      .where(and(
        eq(familyChatMembers.userId, userId),
        eq(familyChats.isActive, true)
      ));

    // Get members for each chat
    const chatsWithMembers = await Promise.all(
      chats.map(async (chat) => {
        const members = await this.getFamilyChatMembers(chat.id);
        return { ...chat, members };
      })
    );

    return chatsWithMembers;
  }

  async getFamilyChat(chatId: number): Promise<any> {
    const [familyChat] = await db
      .select()
      .from(familyChats)
      .where(eq(familyChats.id, chatId));

    if (!familyChat) return null;

    const members = await this.getFamilyChatMembers(chatId);
    return { ...familyChat, members };
  }

  async sendFamilyChatMessage(chatId: number, senderId: string, message: string, messageType: string = 'text', orderItems?: any): Promise<any> {
    // Get family chat details
    const familyChat = await this.getFamilyChat(chatId);
    if (!familyChat) {
      throw new Error('Family chat not found');
    }

    const messageData = {
      familyChatId: chatId,
      milkmanId: familyChat.milkmanId,
      senderId: senderId,
      message,
      messageType,
      senderType: senderId === 'system' ? 'system' as const : 'customer' as const,
      orderItems: orderItems ? JSON.stringify(orderItems) : null,
      isRead: false,
      isDelivered: false,
      isAccepted: false,
    };

    const [chatMessage] = await db
      .insert(chatMessages)
      .values(messageData)
      .returning();

    return chatMessage;
  }

  async getFamilyChatMessages(chatId: number): Promise<any[]> {
    const messages = await db
      .select()
      .from(chatMessages)
      .where(eq(chatMessages.familyChatId, chatId))
      .orderBy(chatMessages.createdAt);

    return messages;
  }

  async getFamilyChatMembers(chatId: number): Promise<any[]> {
    const members = await db
      .select({
        id: familyChatMembers.id,
        userId: familyChatMembers.userId,
        userName: users.name,
        joinedAt: familyChatMembers.joinedAt,
        isAdmin: familyChatMembers.isAdmin,
      })
      .from(familyChatMembers)
      .innerJoin(users, eq(users.id, familyChatMembers.userId))
      .where(eq(familyChatMembers.chatId, chatId));

    return members;
  }

  async leaveFamilyChat(chatId: number, userId: string): Promise<void> {
    await db
      .delete(familyChatMembers)
      .where(and(
        eq(familyChatMembers.chatId, chatId),
        eq(familyChatMembers.userId, userId)
      ));

    // Send leave notification
    await this.sendFamilyChatMessage(
      chatId,
      'system',
      `A family member has left the chat`,
      'notification'
    );
  }

  // Notification operations
  async createNotification(notificationData: InsertNotification): Promise<Notification> {
    const [notification] = await db
      .insert(notifications)
      .values(notificationData)
      .returning();
    console.log("DatabaseStorage: Created notification for user:", notificationData.userId, "title:", notificationData.title);
    return notification;
  }
}

// Use DatabaseStorage for production - persistent storage with PostgreSQL database
export const storage = new DatabaseStorage();

