.dark {
  /* Modern dark theme */
  --background: hsl(222, 16%, 9%);
  --foreground: hsl(0, 0%, 95%);
  --muted: hsl(222, 16%, 16%);
  --muted-foreground: hsl(220, 9%, 65%);
  --popover: hsl(222, 16%, 11%);
  --popover-foreground: hsl(0, 0%, 95%);
  --card: hsl(222, 16%, 11%);
  --card-foreground: hsl(0, 0%, 95%);
  --border: hsl(222, 16%, 20%);
  --input: hsl(222, 16%, 20%);
  --primary: hsl(221, 83%, 53%);
  --primary-foreground: hsl(0, 0%, 100%);
  --secondary: hsl(222, 16%, 16%);
  --secondary-foreground: hsl(0, 0%, 95%);
  --accent: hsl(221, 83%, 53%);
  --accent-foreground: hsl(0, 0%, 100%);
  --destructive: hsl(0, 84%, 60%);
  --destructive-foreground: hsl(0, 0%, 100%);
  --ring: hsl(221, 83%, 53%);
  --radius: 0.75rem;

  /* Dark mode brand colors */
  --brand-primary: hsl(221, 83%, 53%);
  --brand-secondary: hsl(142, 76%, 36%);
  --brand-accent: hsl(25, 95%, 53%);
  --surface: hsl(222, 16%, 11%);
  --surface-secondary: hsl(222, 16%, 14%);
  --success: hsl(142, 76%, 36%);
  --warning: hsl(38, 92%, 50%);
  --error: hsl(0, 84%, 60%);
  --info: hsl(199, 89%, 48%);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
    font-feature-settings: "rlig" 1, "calt" 1;
  }

  h1, h2, h3, h4, h5, h6 {
    @apply font-semibold tracking-tight;
  }

  h1 {
    @apply text-3xl md:text-4xl;
  }

  h2 {
    @apply text-2xl md:text-3xl;
  }

  h3 {
    @apply text-xl md:text-2xl;
  }
}

@layer utilities {
  .bg-surface {
    background-color: var(--surface);
  }

  .bg-surface-secondary {
    background-color: var(--surface-secondary);
  }

  .text-brand-primary {
    color: var(--brand-primary);
  }

  .bg-brand-primary {
    background-color: var(--brand-primary);
  }

  .text-brand-secondary {
    color: var(--brand-secondary);
  }

  .bg-brand-secondary {
    background-color: var(--brand-secondary);
  }

  .text-success {
    color: var(--success);
  }

  .bg-success {
    background-color: var(--success);
  }

  .text-warning {
    color: var(--warning);
  }

  .bg-warning {
    background-color: var(--warning);
  }

  .text-error {
    color: var(--error);
  }

  .bg-error {
    background-color: var(--error);
  }

  .text-info {
    color: var(--info);
  }

  .bg-info {
    background-color: var(--info);
  }

  .glass-effect {
    background: rgba(255, 255, 255, 0.1);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.2);
  }

  .modern-card {
    @apply bg-card border border-border rounded-xl shadow-sm;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  }

  .modern-card:hover {
    @apply shadow-lg;
    transform: translateY(-2px);
  }

  .modern-button {
    @apply rounded-lg font-medium;
    @apply transition-all duration-200 ease-in-out;
    @apply hover:shadow-lg hover:-translate-y-0.5;
    @apply active:translate-y-0 active:shadow-md;
    color: white !important;
    background: linear-gradient(135deg, hsl(221, 83%, 53%) 0%, hsl(142, 76%, 36%) 100%);
    border: 1px solid hsl(221, 83%, 53%);
    min-height: 2.5rem;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
  }

  .modern-button:hover {
    background: linear-gradient(135deg, hsl(142, 76%, 36%) 0%, hsl(221, 83%, 53%) 100%);
    border-color: hsl(142, 76%, 36%);
    color: white !important;
    box-shadow: 0 8px 25px -8px rgba(56, 178, 172, 0.4), 0 4px 16px -4px rgba(0, 0, 0, 0.1);
  }

  .modern-button:disabled {
    background: hsl(220, 9%, 46%) !important;
    border-color: hsl(220, 9%, 46%) !important;
    color: hsl(220, 9%, 65%) !important;
    cursor: not-allowed;
    transform: none;
    box-shadow: none;
    opacity: 0.6;
  }

  .modern-input {
    @apply bg-background border border-border rounded-lg;
    @apply focus:border-primary focus:ring-1 focus:ring-primary;
    @apply transition-all duration-200 ease-in-out;
  }

  .gradient-text {
    background: linear-gradient(135deg, var(--brand-primary), var(--brand-secondary));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  /* Enhanced Settings Button - Light and Dark Mode */
  .settings-btn-enhanced {
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.12) 0%, rgba(99, 102, 241, 0.12) 100%);
    border: 2px solid rgba(59, 130, 246, 0.4) !important;
    box-shadow: 0 4px 12px rgba(59, 130, 246, 0.2);
    backdrop-filter: blur(8px);
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    position: relative;
    overflow: hidden;
    color: #1a202c !important;
    pointer-events: auto !important;
    cursor: pointer !important;
  }

  .dark .settings-btn-enhanced {
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.15) 0%, rgba(99, 102, 241, 0.15) 100%);
