import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import { Request, Response, NextFunction } from 'express';
import { storage } from '../storage';
import rateLimit from 'express-rate-limit';

// JWT Secret from environment
const JWT_SECRET = process.env.JWT_SECRET || 'your-super-secure-jwt-secret-change-in-production';
const JWT_EXPIRES_IN = process.env.JWT_EXPIRES_IN || '7d';
const JWT_REFRESH_SECRET = process.env.JWT_REFRESH_SECRET || 'your-refresh-secret-change-in-production';

// Password policies
export const PASSWORD_POLICIES = {
  minLength: 8,
  requireUppercase: true,
  requireLowercase: true,
  requireNumbers: true,
  requireSpecialChars: true,
  maxAttempts: 5,
  lockoutDuration: 15 * 60 * 1000, // 15 minutes
};

// Extended Request interface
export interface AuthenticatedRequest extends Request {
  user?: {
    id: string;
    username: string | null;
    phone: string;
    userType: 'customer' | 'milkman' | 'admin';
    isVerified: boolean;
  };
}

// Password validation
export function validatePassword(password: string): { isValid: boolean; errors: string[] } {
  const errors: string[] = [];

  if (password.length < PASSWORD_POLICIES.minLength) {
    errors.push(`Password must be at least ${PASSWORD_POLICIES.minLength} characters long`);
  }

  if (PASSWORD_POLICIES.requireUppercase && !/[A-Z]/.test(password)) {
    errors.push('Password must contain at least one uppercase letter');
  }

  if (PASSWORD_POLICIES.requireLowercase && !/[a-z]/.test(password)) {
    errors.push('Password must contain at least one lowercase letter');
  }

  if (PASSWORD_POLICIES.requireNumbers && !/\d/.test(password)) {
    errors.push('Password must contain at least one number');
  }

  if (PASSWORD_POLICIES.requireSpecialChars && !/[!@#$%^&*(),.?":{}|<>]/.test(password)) {
    errors.push('Password must contain at least one special character');
  }

  return {
    isValid: errors.length === 0,
    errors
  };
}

// Hash password
export async function hashPassword(password: string): Promise<string> {
  const saltRounds = 12; // High salt rounds for security
  return bcrypt.hash(password, saltRounds);
}

// Verify password
export async function verifyPassword(password: string, hashedPassword: string): Promise<boolean> {
  return bcrypt.compare(password, hashedPassword);
}

// Generate JWT tokens
export function generateTokens(payload: any) {
  const accessToken = jwt.sign(payload, JWT_SECRET, {
    expiresIn: JWT_EXPIRES_IN,
    issuer: 'dooodhwala-api',
    audience: 'dooodhwala-users',
  } as jwt.SignOptions);

  const refreshToken = jwt.sign(payload, JWT_REFRESH_SECRET, {
    expiresIn: '30d',
    issuer: 'dooodhwala-api',
    audience: 'dooodhwala-users',
  } as jwt.SignOptions);

  return { accessToken, refreshToken };
}

// Verify JWT token
export function verifyToken(token: string): any {
  try {
    console.log('verifyToken - JWT_SECRET exists:', !!JWT_SECRET);
    console.log('verifyToken - JWT_SECRET length:', JWT_SECRET?.length);
    const decoded = jwt.verify(token, JWT_SECRET, {
      issuer: 'dooodhwala-api',
      audience: 'dooodhwala-users',
    });
    console.log('verifyToken - successfully decoded:', decoded);
    return decoded;
  } catch (error: any) {
    console.log('verifyToken - JWT verification error:', error.message);
    console.log('verifyToken - Error details:', error);
    throw new Error('Invalid or expired token');
  }
}

// Verify refresh token
export function verifyRefreshToken(token: string): any {
  try {
    return jwt.verify(token, JWT_REFRESH_SECRET, {
      issuer: 'dooodhwala-api',
      audience: 'dooodhwala-users',
    });
  } catch (error) {
    throw new Error('Invalid or expired refresh token');
  }
}

// Authentication middleware
export function requireAuth(req: AuthenticatedRequest, res: Response, next: NextFunction) {
  try {
    const authHeader = req.headers.authorization;
    console.log('requireAuth - authHeader:', authHeader);

    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      console.log('requireAuth - No valid auth header');
      return res.status(401).json({ 
        success: false, 
        message: 'Access token required. Please include Authorization: Bearer <token> header.' 
      });
    }

    const token = authHeader.substring(7); // Remove "Bearer " prefix
    console.log('requireAuth - token (first 50 chars):', token.substring(0, 50));

    const decoded = verifyToken(token);
    console.log('requireAuth - decoded token:', decoded);

    // Attach user info to request
    // Handle both 'id' and 'userId' field names for backward compatibility
    const userId = decoded.userId || decoded.id;
    req.user = {
      id: userId || decoded.username, // Fallback to username if no ID
      username: decoded.username || null,
      phone: decoded.phone || null,
      userType: decoded.userType || 'customer',
      isVerified: decoded.isVerified || true,
    };

    console.log('requireAuth - req.user set to:', req.user);
    next();
  } catch (error: any) {
    console.log('requireAuth - error:', error.message);
    return res.status(401).json({ 
      success: false, 
      message: 'Invalid or expired token',
      error: error.message 
    });
  }
}

// Role-based authorization
export function requireRole(...allowedRoles: ('customer' | 'milkman' | 'admin')[]) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({ 
        success: false, 
        message: 'Authentication required' 
      });
    }

    if (!allowedRoles.includes(req.user.userType)) {
      return res.status(403).json({ 
        success: false, 
        message: `Access denied. Required roles: ${allowedRoles.join(', ')}`,
        userRole: req.user.userType
      });
    }

    next();
  };
}

// Admin-only middleware
export const requireAdmin = requireRole('admin');

// Customer-only middleware
export const requireCustomer = requireRole('customer');

// Milkman-only middleware
export const requireMilkman = requireRole('milkman');

// Customer or Milkman middleware
export const requireCustomerOrMilkman = requireRole('customer', 'milkman');

// Verified user middleware
export function requireVerifiedUser(req: AuthenticatedRequest, res: Response, next: NextFunction) {
  if (!req.user) {
    return res.status(401).json({ 
      success: false, 
      message: 'Authentication required' 
    });
  }

  if (!req.user.isVerified) {
    return res.status(403).json({ 
      success: false, 
      message: 'Account verification required. Please verify your phone number.' 
    });
  }

  next();
}

// Rate limiting for authentication endpoints
export const authRateLimit = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: {
    success: false,
    message: 'Too many authentication attempts. Please try again in 15 minutes.',
  },
  standardHeaders: true,
  legacyHeaders: false,
});

// Rate limiting for password reset
export const passwordResetRateLimit = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 3, // 3 password reset attempts per hour
  message: {
    success: false,
    message: 'Too many password reset attempts. Please try again in 1 hour.',
  },
  standardHeaders: true,
  legacyHeaders: false,
});

// Rate limiting for OTP requests
export const otpRateLimit = rateLimit({
  windowMs: 5 * 60 * 1000, // 5 minutes
  max: 3, // 3 OTP requests per 5 minutes
  message: {
    success: false,
    message: 'Too many OTP requests. Please wait 5 minutes before requesting again.',
  },
  standardHeaders: true,
  legacyHeaders: false,
});

// Account lockout tracking
const loginAttempts = new Map<string, { count: number; lastAttempt: Date; lockedUntil?: Date }>();

export function trackLoginAttempt(identifier: string, success: boolean) {
  const now = new Date();
  const attempts = loginAttempts.get(identifier) || { count: 0, lastAttempt: now };

  if (attempts.lockedUntil && now < attempts.lockedUntil) {
    throw new Error(`Account locked. Try again after ${attempts.lockedUntil.toISOString()}`);
  }

  if (success) {
    // Reset on successful login
    loginAttempts.delete(identifier);
  } else {
    // Increment failed attempts
    attempts.count += 1;
    attempts.lastAttempt = now;

    if (attempts.count >= PASSWORD_POLICIES.maxAttempts) {
      attempts.lockedUntil = new Date(now.getTime() + PASSWORD_POLICIES.lockoutDuration);
    }

    loginAttempts.set(identifier, attempts);

    if (attempts.lockedUntil) {
      throw new Error(`Too many failed attempts. Account locked until ${attempts.lockedUntil.toISOString()}`);
    }
  }
}

// Clean up expired lockouts
setInterval(() => {
  const now = new Date();
  const entries = Array.from(loginAttempts.entries());
  for (const [key, attempts] of entries) {
    if (attempts.lockedUntil && now >= attempts.lockedUntil) {
      loginAttempts.delete(key);
    }
  }
}, 60 * 1000); // Clean up every minute

