import winston from 'winston';
import morgan from 'morgan';
import { Request, Response, NextFunction } from 'express';
import path from 'path';

// Environment configuration
const isProduction = process.env.NODE_ENV === 'production';
const isDevelopment = process.env.NODE_ENV === 'development';

// Safe JSON stringification function to handle circular references
function safeStringify(obj: any): string {
  const seen = new WeakSet();
  return JSON.stringify(obj, (key, val) => {
    if (val != null && typeof val === "object") {
      if (seen.has(val)) {
        return "[Circular]";
      }
      seen.add(val);
    }
    return val;
  });
}

// Winston logger configuration
const logFormat = winston.format.combine(
  winston.format.timestamp({
    format: 'YYYY-MM-DD HH:mm:ss'
  }),
  winston.format.errors({ stack: true }),
  winston.format.json(),
  winston.format.printf((info) => {
    const { timestamp, level, message, stack, ...meta } = info;
    const log: any = {
      timestamp,
      level,
      message
    };

    if (stack) {
      log.stack = stack;
    }

    if (meta && typeof meta === 'object' && Object.keys(meta).length > 0) {
      log.meta = meta;
    }

    return safeStringify(log);
  })
);

// Create logs directory if it doesn't exist
const logsDir = path.join(process.cwd(), 'logs');

// Logger instance
export const logger = winston.createLogger({
  level: isProduction ? 'info' : 'debug',
  format: logFormat,
  defaultMeta: { 
    service: 'dooodhwala-api',
    environment: process.env.NODE_ENV || 'development',
    ...(process.env.NODE_ENV === 'production' && { hostname: process.env.HOSTNAME })
  },
  transports: [
    // Console logging
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple(),
        winston.format.printf(({ timestamp, level, message, stack }) => {
          return `${timestamp} [${level}]: ${message}${stack ? '\n' + stack : ''}`;
        })
      )
    }),

    // File logging for errors
    new winston.transports.File({
      filename: path.join(logsDir, 'error.log'),
      level: 'error',
      maxsize: 10 * 1024 * 1024, // 10MB
      maxFiles: 5,
      tailable: true
    }),

    // File logging for all logs
    new winston.transports.File({
      filename: path.join(logsDir, 'combined.log'),
      maxsize: 10 * 1024 * 1024, // 10MB
      maxFiles: 10,
      tailable: true
    }),

    // Security-specific logs
    new winston.transports.File({
      filename: path.join(logsDir, 'security.log'),
      level: 'warn',
      maxsize: 10 * 1024 * 1024, // 10MB
      maxFiles: 15,
      tailable: true
    })
  ],

  // Handle uncaught exceptions and rejections
  exceptionHandlers: [
    new winston.transports.File({
      filename: path.join(logsDir, 'exceptions.log')
    })
  ],

  rejectionHandlers: [
    new winston.transports.File({
      filename: path.join(logsDir, 'rejections.log')
    })
  ]
});

// Morgan HTTP logging configuration
const morganFormat = isDevelopment 
  ? 'dev' 
  : ':remote-addr - :remote-user [:date[clf]] ":method :url HTTP/:http-version" :status :res[content-length] ":referrer" ":user-agent" :response-time ms';

// Custom morgan token for user ID
morgan.token('user-id', (req: any) => {
  return req.user?.id || 'anonymous';
});

// Custom morgan token for request ID
morgan.token('request-id', (req: any) => {
  return req.requestId || 'unknown';
});

// Enhanced morgan format with security info
const securityMorganFormat = ':remote-addr - :user-id [:date[clf]] ":method :url HTTP/:http-version" :status :res[content-length] ":referrer" ":user-agent" :response-time ms req-id::request-id';

// Morgan middleware
export const httpLogger = morgan(securityMorganFormat, {
  stream: {
    write: (message: string) => {
      logger.info(message.trim());
    }
  },
  skip: (req: Request) => {
    // Skip logging for health checks and static assets
    return req.url === '/health' || 
           req.url === '/api/health' || 
           req.url.startsWith('/static/') ||
           req.url.endsWith('.css') ||
           req.url.endsWith('.js') ||
           req.url.endsWith('.ico');
  }
});

// Security event logger
export class SecurityLogger {
  static logAuthAttempt(req: Request, success: boolean, details?: any) {
    const logData = {
      event: 'authentication_attempt',
      success,
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      phone: req.body?.phone,
      timestamp: new Date().toISOString(),
      ...details
    };

    if (success) {
      logger.info('Authentication successful', logData);
    } else {
      logger.warn('Authentication failed', logData);
    }
  }

  static logPermissionDenied(req: Request, userId?: string, requiredRole?: string) {
    logger.warn('Access denied', {
      event: 'permission_denied',
      userId,
      requiredRole,
      userRole: (req as any).user?.userType,
      ip: req.ip,
      url: req.url,
      method: req.method,
      userAgent: req.get('User-Agent'),
      timestamp: new Date().toISOString()
    });
  }

  static logSuspiciousActivity(req: Request, reason: string, details?: any) {
    logger.warn('Suspicious activity detected', {
      event: 'suspicious_activity',
      reason,
      ip: req.ip,
      userId: (req as any).user?.id,
      url: req.url,
      method: req.method,
      userAgent: req.get('User-Agent'),
      timestamp: new Date().toISOString(),
      ...details
    });
  }

  static logPaymentEvent(event: string, details: any) {
    logger.info('Payment event', {
      event: 'payment_transaction',
      type: event,
      timestamp: new Date().toISOString(),
      ...details
    });
  }

  static logDataBreach(details: any) {
    logger.error('SECURITY ALERT: Potential data breach', {
      event: 'data_breach_alert',
      severity: 'CRITICAL',
      timestamp: new Date().toISOString(),
      ...details
    });
  }

  static logRateLimitExceeded(req: Request, limit: number) {
    logger.warn('Rate limit exceeded', {
      event: 'rate_limit_exceeded',
      ip: req.ip,
      userId: (req as any).user?.id,
      limit,
      url: req.url,
      userAgent: req.get('User-Agent'),
      timestamp: new Date().toISOString()
    });
  }
}

// Request ID middleware
export function requestIdMiddleware(req: Request, res: Response, next: NextFunction) {
  const requestId = Math.random().toString(36).substring(2, 15);
  (req as any).requestId = requestId;
  res.setHeader('X-Request-ID', requestId);
  next();
}

// Error logging middleware
export function errorLoggingMiddleware(err: any, req: Request, res: Response, next: NextFunction) {
  const errorId = Math.random().toString(36).substring(2, 15);

  logger.error('Request error', {
    errorId,
    error: {
      message: err.message,
      stack: err.stack,
      name: err.name
    },
    request: {
      method: req.method,
      url: req.url,
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      userId: (req as any).user?.id,
      requestId: (req as any).requestId
    },
    timestamp: new Date().toISOString()
  });

  // Don't expose internal errors in production
  if (process.env.NODE_ENV === 'production') {
    res.status(500).json({
      success: false,
      message: 'Internal server error',
      errorId
    });
  } else {
    res.status(500).json({
      success: false,
      message: err.message,
      errorId,
      stack: err.stack
    });
  }
}

// Performance monitoring
export function performanceMonitor(req: Request, res: Response, next: NextFunction) {
  const startTime = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - startTime;

    // Log slow requests (>2 seconds)
    if (duration > 2000) {
      logger.warn('Slow request detected', {
        event: 'slow_request',
        method: req.method,
        url: req.url,
        duration,
        userId: (req as any).user?.id,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });
    }

    // Log long-running requests (>10 seconds)
    if (duration > 10000) {
      SecurityLogger.logSuspiciousActivity(req, 'Long running request', { duration });
    }
  });

  next();
}

// Database query logging
export function logDatabaseQuery(query: string, params?: any, duration?: number) {
  if (isDevelopment || duration && duration > 1000) { // Log slow queries
    logger.debug('Database query', {
      event: 'database_query',
      query: query.substring(0, 200), // Truncate long queries
      params: params ? JSON.stringify(params).substring(0, 100) : undefined,
      duration,
      timestamp: new Date().toISOString()
    });
  }
}

// API usage analytics
const apiUsage = new Map<string, { count: number; lastAccess: Date }>();

export function trackAPIUsage(req: Request, res: Response, next: NextFunction) {
  const endpoint = `${req.method} ${req.route?.path || req.path}`;
  const usage = apiUsage.get(endpoint) || { count: 0, lastAccess: new Date() };

  usage.count++;
  usage.lastAccess = new Date();
  apiUsage.set(endpoint, usage);

  next();
}

// Periodic API usage reporting
setInterval(() => {
  if (apiUsage.size > 0) {
    logger.info('API usage report', {
      event: 'api_usage_report',
      endpoints: Array.from(apiUsage.entries()).map(([endpoint, data]) => ({
        endpoint,
        count: data.count,
        lastAccess: data.lastAccess
      })),
      timestamp: new Date().toISOString()
    });

    // Reset counters
    apiUsage.clear();
  }
}, 60 * 60 * 1000); // Every hour

// Health check logging
export function logHealthCheck(status: 'healthy' | 'unhealthy', details?: any) {
  logger.info('Health check', {
    event: 'health_check',
    status,
    timestamp: new Date().toISOString(),
    ...details
  });
}

