import helmet from 'helmet';
import rateLimit from 'express-rate-limit';
import slowDown from 'express-slow-down';
import hpp from 'hpp';
import cors from 'cors';
import { Request, Response, NextFunction } from 'express';

// Environment-based configuration
const isProduction = process.env.NODE_ENV === 'production';
const isDevelopment = process.env.NODE_ENV === 'development';

// CORS configuration for production security
export const corsOptions = {
  origin: function (origin: string | undefined, callback: (error: Error | null, success?: boolean) => void) {
    // Allow requests with no origin (mobile apps, Postman, etc.)
    if (!origin) return callback(null, true);

    const allowedOrigins = [
      process.env.CLIENT_URL || 'http://localhost:3000',
      process.env.PRODUCTION_URL || 'https://your-app.replit.app',
      'https://replit.com',
      'https://e17c267b-4c10-4fa7-9e7f-39f369d955f8-00-3g0kj7ff3t859.worf.replit.dev',
      'https://dairy-connect-siddhantsancheti.replit.app', // Production Replit domain
      ...(process.env.ADDITIONAL_CORS_ORIGINS?.split(',') || [])
    ];

    // In development, allow localhost variations
    if (isDevelopment) {
      allowedOrigins.push(
        'http://localhost:3000',
        'http://localhost:5000',
        'http://127.0.0.1:3000',
        'http://127.0.0.1:5000'
      );
    }

    if (allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      console.warn(`CORS blocked origin: ${origin}`);
      callback(new Error(`Origin ${origin} not allowed by CORS policy`));
    }
  },
  credentials: true, // Allow cookies and auth headers
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
  allowedHeaders: [
    'Origin',
    'X-Requested-With',
    'Content-Type',
    'Authorization',
    'Accept',
    'Cache-Control',
    'X-CSRF-Token'
  ],
  exposedHeaders: ['X-RateLimit-Limit', 'X-RateLimit-Remaining', 'X-RateLimit-Reset'],
  maxAge: 86400, // 24 hours
};

// Helmet security headers configuration
export const helmetConfig = helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      styleSrc: [
        "'self'",
        "'unsafe-inline'", // Needed for styled-components
        "https://fonts.googleapis.com",
        "https://checkout.razorpay.com",
        "https://js.stripe.com"
      ],
      scriptSrc: [
        "'self'",
        "https://checkout.razorpay.com",
        "https://js.stripe.com",
        "https://maps.googleapis.com",
        "https://www.googletagmanager.com",
        "https://www.google-analytics.com",
        ...(isDevelopment ? ["'unsafe-eval'", "'unsafe-inline'"] : [])
      ],
      imgSrc: [
        "'self'",
        "data:",
        "https:",
        "blob:",
        "https://maps.googleapis.com",
        "https://maps.gstatic.com"
      ],
      fontSrc: [
        "'self'",
        "https://fonts.gstatic.com",
        "https://fonts.googleapis.com"
      ],
      connectSrc: [
        "'self'",
        "https://api.razorpay.com",
        "https://api.stripe.com",
        "https://maps.googleapis.com",
        "https://www.google-analytics.com",
        "https://www.googletagmanager.com",
        "https://analytics.google.com",
        ...(isDevelopment ? ["ws://localhost:*", "wss://localhost:*"] : [])
      ],
      frameSrc: [
        "'self'",
        "https://checkout.razorpay.com",
        "https://js.stripe.com"
      ],
      objectSrc: ["'none'"],
      upgradeInsecureRequests: isProduction ? [] : null,
    },
  },
  crossOriginEmbedderPolicy: false, // Disable for payment gateways
  hsts: {
    maxAge: 31536000, // 1 year
    includeSubDomains: true,
    preload: true
  },
  noSniff: true,
  frameguard: { action: 'deny' },
  xssFilter: true,
  referrerPolicy: { policy: 'strict-origin-when-cross-origin' }
});

// General API rate limiting
export const generalRateLimit = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: isProduction ? 100 : 1000, // Stricter in production
  message: {
    error: 'Too many requests from this IP',
    message: 'Please try again later',
    retryAfter: '15 minutes'
  },
  standardHeaders: true,
  legacyHeaders: false,
  skip: (req: Request) => {
    // Skip rate limiting for health checks
    return req.path === '/health' || req.path === '/api/health';
  }
});

// Strict rate limiting for sensitive endpoints
export const strictRateLimit = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // Very limited
  message: {
    error: 'Too many requests to sensitive endpoint',
    message: 'Please try again later',
    retryAfter: '15 minutes'
  },
  standardHeaders: true,
  legacyHeaders: false,
});

// Payment-specific rate limiting
export const paymentRateLimit = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 20, // 20 payment attempts per hour
  message: {
    error: 'Too many payment attempts',
    message: 'Please try again later or contact support',
    retryAfter: '1 hour'
  },
  standardHeaders: true,
  legacyHeaders: false,
});

// Slow down for repeated requests
export const speedLimiter = slowDown({
  windowMs: 15 * 60 * 1000, // 15 minutes
  delayAfter: 50, // Allow 50 requests per window without delay
  delayMs: () => 500, // Add 500ms delay per request after delayAfter
  maxDelayMs: 20000, // Maximum delay of 20 seconds
  validate: { delayMs: false }, // Disable warning
});

// HTTP Parameter Pollution protection
export const hppProtection = hpp({
  whitelist: ['tags', 'categories', 'sort'], // Allow arrays for these params
});

// Force HTTPS in production
export function forceHTTPS(req: Request, res: Response, next: NextFunction) {
  if (isProduction && req.header('x-forwarded-proto') !== 'https') {
    return res.redirect(301, `https://${req.get('Host')}${req.url}`);
  }
  next();
}

// Security headers middleware
export function securityHeaders(req: Request, res: Response, next: NextFunction) {
  // Remove server information
  res.removeHeader('X-Powered-By');

  // Add custom security headers
  res.setHeader('X-API-Version', '1.0');
  res.setHeader('X-Request-ID', Math.random().toString(36));

  // Prevent clickjacking
  res.setHeader('X-Frame-Options', 'DENY');

  // Prevent MIME type sniffing
  res.setHeader('X-Content-Type-Options', 'nosniff');

  // Enable XSS protection
  res.setHeader('X-XSS-Protection', '1; mode=block');

  // Strict transport security
  if (isProduction) {
    res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains; preload');
  }

  next();
}

// IP-based blocking middleware
const blockedIPs = new Set<string>([
  // Add known malicious IPs here
]);

export function blockMaliciousIPs(req: Request, res: Response, next: NextFunction) {
  const clientIP = req.ip || req.socket.remoteAddress || '';

  if (blockedIPs.has(clientIP)) {
    console.warn(`Blocked request from banned IP: ${clientIP}`);
    return res.status(403).json({
      error: 'Access denied',
      message: 'Your IP address has been blocked due to suspicious activity'
    });
  }

  next();
}

// Request size limiting
export function limitRequestSize(maxSize: number = 10 * 1024 * 1024) { // 10MB default
  return (req: Request, res: Response, next: NextFunction) => {
    const contentLength = parseInt(req.get('content-length') || '0');

    if (contentLength > maxSize) {
      return res.status(413).json({
        error: 'Request too large',
        message: `Request size ${contentLength} exceeds maximum allowed size ${maxSize}`,
        maxSize
      });
    }

    next();
  };
}

// Suspicious activity detection
const suspiciousActivity = new Map<string, { requests: number; lastRequest: Date }>();

export function detectSuspiciousActivity(req: Request, res: Response, next: NextFunction) {
  const identifier = (req as any).user?.id || req.ip;
  const now = new Date();
  const windowMs = 60 * 1000; // 1 minute window

  const activity = suspiciousActivity.get(identifier) || { requests: 0, lastRequest: now };

  // Reset if outside window
  if (now.getTime() - activity.lastRequest.getTime() > windowMs) {
    activity.requests = 0;
  }

  activity.requests++;
  activity.lastRequest = now;
  suspiciousActivity.set(identifier, activity);

  // Flag suspicious patterns
  if (activity.requests > 200) { // More than 200 requests per minute
    console.warn(`Suspicious activity detected from ${identifier}: ${activity.requests} requests in 1 minute`);

    // You could implement additional actions here:
    // - Add to temporary blocklist
    // - Send alerts
    // - Require additional verification
  }

  next();
}

// Security middleware stack
export const securityMiddleware = [
  forceHTTPS,
  helmetConfig,
  securityHeaders,
  blockMaliciousIPs,
  hppProtection,
  limitRequestSize(),
  detectSuspiciousActivity,
];

// Rate limiting middleware stack
export const rateLimitingMiddleware = [
  speedLimiter,
  generalRateLimit,
];

// Cleanup function for memory-based tracking
setInterval(() => {
  const now = new Date();
  const maxAge = 60 * 60 * 1000; // 1 hour

  // Clean up old suspicious activity entries
  const entries = Array.from(suspiciousActivity.entries());
  for (const [key, activity] of entries) {
    if (now.getTime() - activity.lastRequest.getTime() > maxAge) {
      suspiciousActivity.delete(key);
    }
  }
}, 10 * 60 * 1000); // Run cleanup every 10 minutes

