import { body, param, query, validationResult } from 'express-validator';
import { Request, Response, NextFunction } from 'express';
import sanitizeHtml from 'xss';
import mongoSanitize from 'express-mongo-sanitize';

// Custom validation error handler
export function handleValidationErrors(req: Request, res: Response, next: NextFunction) {
  const errors = validationResult(req);

  if (!errors.isEmpty()) {
    const formattedErrors = errors.array().map(error => ({
      field: error.type === 'field' ? error.path : 'unknown',
      message: error.msg,
      value: error.type === 'field' ? error.value : undefined,
    }));

    return res.status(400).json({
      success: false,
      message: 'Validation failed',
      errors: formattedErrors,
    });
  }

  next();
}

// Sanitize HTML content
export function sanitizeInput(input: string): string {
  if (typeof input !== 'string') return input;

  return sanitizeHtml(input, {
    whiteList: {}, // No HTML tags allowed
    stripIgnoreTag: true,
    stripIgnoreTagBody: ['script', 'style'],
  });
}

// Sanitize request body middleware
export function sanitizeBody(req: Request, res: Response, next: NextFunction) {
  if (req.body) {
    // Remove potential NoSQL injection patterns
    req.body = mongoSanitize.sanitize(req.body);

    // Sanitize string fields
    const sanitizeObject = (obj: any): any => {
      if (typeof obj === 'string') {
        return sanitizeInput(obj);
      }

      if (Array.isArray(obj)) {
        return obj.map(sanitizeObject);
      }

      if (obj !== null && typeof obj === 'object') {
        const sanitized: any = {};
        for (const [key, value] of Object.entries(obj)) {
          sanitized[key] = sanitizeObject(value);
        }
        return sanitized;
      }

      return obj;
    };

    req.body = sanitizeObject(req.body);
  }

  next();
}

// Phone number validation
export const validatePhone = body('phone')
  .isMobilePhone('en-IN')
  .withMessage('Invalid Indian phone number format')
  .isLength({ min: 10, max: 15 })
  .withMessage('Phone number must be between 10-15 digits')
  .customSanitizer((value) => {
    // Normalize phone number format
    return value.replace(/[^\d]/g, '').replace(/^91/, '');
  });

// Password validation
export const validatePassword = body('password')
  .isLength({ min: 8, max: 128 })
  .withMessage('Password must be between 8-128 characters')
  .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*(),.?":{}|<>])[A-Za-z\d!@#$%^&*(),.?":{}|<>]/)
  .withMessage('Password must contain at least one uppercase letter, one lowercase letter, one number, and one special character')
  .custom((value) => {
    // Additional security checks
    const commonPasswords = [
      'password', '123456', '12345678', 'qwerty', 'abc123', 
      'password123', 'admin', 'letmein', 'welcome', 'monkey'
    ];

    if (commonPasswords.includes(value.toLowerCase())) {
      throw new Error('Password is too common. Please choose a stronger password.');
    }

    return true;
  });

// Email validation
export const validateEmail = body('email')
  .optional()
  .isEmail()
  .withMessage('Invalid email format')
  .normalizeEmail({
    gmail_remove_dots: false,
    gmail_remove_subaddress: false,
  });

// Name validation
export const validateName = (field: string) => 
  body(field)
    .trim()
    .isLength({ min: 2, max: 50 })
    .withMessage(`${field} must be between 2-50 characters`)
    .matches(/^[a-zA-Z\s\u0900-\u097F]*$/)
    .withMessage(`${field} can only contain letters and spaces (including Hindi characters)`)
    .customSanitizer(sanitizeInput);

// Address validation
export const validateAddress = body('address')
  .trim()
  .isLength({ min: 10, max: 200 })
  .withMessage('Address must be between 10-200 characters')
  .customSanitizer(sanitizeInput);

// Business name validation
export const validateBusinessName = body('businessName')
  .trim()
  .isLength({ min: 2, max: 100 })
  .withMessage('Business name must be between 2-100 characters')
  .customSanitizer(sanitizeInput);

// Amount validation
export const validateAmount = (field: string) =>
  body(field)
    .isFloat({ min: 0.01, max: 100000 })
    .withMessage(`${field} must be a positive number between 0.01 and 100,000`)
    .customSanitizer((value) => parseFloat(value).toFixed(2));

// ID parameter validation
export const validateId = (paramName: string = 'id') =>
  param(paramName)
    .isInt({ min: 1 })
    .withMessage(`${paramName} must be a positive integer`)
    .toInt();

// Pagination validation
export const validatePagination = [
  query('page')
    .optional()
    .isInt({ min: 1, max: 1000 })
    .withMessage('Page must be between 1-1000')
    .toInt(),
  query('limit')
    .optional()
    .isInt({ min: 1, max: 100 })
    .withMessage('Limit must be between 1-100')
    .toInt(),
];

// Date validation
export const validateDate = (field: string) =>
  body(field)
    .optional()
    .isISO8601()
    .withMessage(`${field} must be a valid ISO 8601 date`)
    .toDate();

// Enum validation
export const validateEnum = (field: string, allowedValues: string[]) =>
  body(field)
    .isIn(allowedValues)
    .withMessage(`${field} must be one of: ${allowedValues.join(', ')}`);

// File upload validation
export const validateFileUpload = (field: string, allowedTypes: string[], maxSize: number = 5 * 1024 * 1024) => {
  return (req: any, res: Response, next: NextFunction) => {
    const file = req.file;

    if (!file) {
      return res.status(400).json({
        success: false,
        message: `${field} file is required`,
      });
    }

    if (!allowedTypes.includes(file.mimetype)) {
      return res.status(400).json({
        success: false,
        message: `${field} must be one of: ${allowedTypes.join(', ')}`,
      });
    }

    if (file.size > maxSize) {
      return res.status(400).json({
        success: false,
        message: `${field} size must be less than ${maxSize / (1024 * 1024)}MB`,
      });
    }

    next();
  };
};

// SQL injection prevention
export function preventSQLInjection(req: Request, res: Response, next: NextFunction) {
  const sqlInjectionPatterns = [
    /(\b(SELECT|INSERT|UPDATE|DELETE|DROP|CREATE|ALTER|EXEC|UNION|SCRIPT)\b)/gi,
    /(--|\/\*|\*\/|;|'|"|\bOR\b|\bAND\b)/gi,
    /(\b(HAVING|GROUP BY|ORDER BY|LIMIT|OFFSET)\b)/gi,
  ];

  function checkForSQLInjection(obj: any, path: string = ''): boolean {
    if (typeof obj === 'string') {
      return sqlInjectionPatterns.some(pattern => pattern.test(obj));
    }

    if (Array.isArray(obj)) {
      return obj.some((item, index) => checkForSQLInjection(item, `${path}[${index}]`));
    }

    if (obj !== null && typeof obj === 'object') {
      return Object.entries(obj).some(([key, value]) => 
        checkForSQLInjection(value, path ? `${path}.${key}` : key)
      );
    }

    return false;
  }

  if (checkForSQLInjection(req.body) || checkForSQLInjection(req.query) || checkForSQLInjection(req.params)) {
    return res.status(400).json({
      success: false,
      message: 'Potentially malicious input detected. Request blocked for security.',
    });
  }

  next();
}

// Common validation chains
export const authValidation = [
  validatePhone,
  handleValidationErrors,
];

export const registerValidation = [
  validatePhone,
  validatePassword,
  validateName('username'),
  validateEmail,
  handleValidationErrors,
];

export const profileValidation = [
  validateName('contactName').optional(),
  validateAddress.optional(),
  validateBusinessName.optional(),
  validateEmail,
  handleValidationErrors,
];

export const paymentValidation = [
  validateAmount('amount'),
  body('orderId')
    .trim()
    .isLength({ min: 5, max: 50 })
    .withMessage('Order ID must be between 5-50 characters')
    .customSanitizer(sanitizeInput),
  body('description')
    .optional()
    .trim()
    .isLength({ max: 200 })
    .withMessage('Description must be less than 200 characters')
    .customSanitizer(sanitizeInput),
  handleValidationErrors,
];

export const messageValidation = [
  body('message')
    .trim()
    .isLength({ min: 1, max: 1000 })
    .withMessage('Message must be between 1-1000 characters')
    .customSanitizer(sanitizeInput),
  body('orderQuantity')
    .optional()
    .isFloat({ min: 0.1, max: 100 })
    .withMessage('Order quantity must be between 0.1-100')
    .toFloat(),
  handleValidationErrors,
];

