import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Star, Clock, Truck, Phone } from "lucide-react";
import { useLanguage, getTranslatedText } from '@/hooks/useLanguage';

interface MilkmanCardProps {
  milkman: {
    id: number;
    businessName: string;
    pricePerLiter: string;
    deliveryTimeStart: string;
    deliveryTimeEnd: string;
    rating: string;
    totalReviews: number;
    isAvailable: boolean;
    verified?: boolean;
  };
  onOrder: () => void;
  onContact?: () => void;
}

export function MilkmanCard({ milkman, onOrder, onContact }: MilkmanCardProps) {
  const { language } = useLanguage();

  const formatTime = (time: string) => {
    // Convert 24h format to 12h format
    const [hours, minutes] = time.split(':');
    const hour = parseInt(hours);
    const ampm = hour >= 12 ? 'PM' : 'AM';
    const hour12 = hour % 12 || 12;
    return `${hour12}:${minutes} ${ampm}`;
  };

  return (
    <div className="border rounded-xl p-3 sm:p-4 hover:shadow-md transition-shadow milkman-card-container">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 sm:gap-4">
        <div className="flex items-center space-x-3 sm:space-x-4 min-w-0 flex-1">
          {/* Profile placeholder */}
          <div className="w-10 h-10 sm:w-12 sm:h-12 bg-gray-200 dark:bg-gray-700 rounded-full flex items-center justify-center flex-shrink-0">
            <span className="text-lg sm:text-xl">👨‍🌾</span>
          </div>
          <div className="min-w-0 flex-1">
            <div className="flex items-center space-x-2 mb-1">
              <h3 className="font-semibold text-mobile-primary truncate text-sm sm:text-base">{getTranslatedText(milkman.businessName, language)}</h3>
              {milkman.verified && (
                <Badge variant="secondary" className="text-xs flex-shrink-0">
                  {getTranslatedText("Verified", language)}
                </Badge>
              )}
            </div>
            <div className="flex flex-col sm:flex-row sm:items-center sm:space-x-2 text-xs sm:text-sm text-mobile-secondary">
              <div className="flex items-center space-x-1 mb-1 sm:mb-0">
                <Star className="h-3 w-3 text-yellow-400 fill-current flex-shrink-0" />
                <span className="truncate">{parseFloat(milkman.rating).toFixed(1)} ({milkman.totalReviews} {getTranslatedText("reviews", language)})</span>
              </div>
              <span className="text-gray-400 hidden sm:inline">•</span>
              <span className="whitespace-nowrap">0.5 {getTranslatedText("km away", language)}</span>
            </div>
          </div>
        </div>
        <div className="flex items-center justify-end space-x-2 flex-shrink-0">
          <Badge className={`${milkman.isAvailable ? "bg-green-100 text-green-800" : "bg-yellow-100 text-yellow-800"} text-xs`}>
            <div className={`w-2 h-2 rounded-full mr-1 ${milkman.isAvailable ? "bg-green-500" : "bg-yellow-500"}`} />
            {getTranslatedText(milkman.isAvailable ? "Available" : "Busy", language)}
          </Badge>
          {milkman.isAvailable ? (
            <Button 
              className="btn-mobile-enhanced modern-button text-xs sm:text-sm"
              onClick={onOrder}
              size="sm"
            >
              {getTranslatedText("Order Now", language)}
            </Button>
          ) : (
            <Button variant="outline" disabled className="btn-mobile-enhanced text-xs sm:text-sm" size="sm">
              {getTranslatedText("Notify Me", language)}
            </Button>
          )}
        </div>
      </div>

      <div className="mt-3 flex flex-wrap items-center gap-2 sm:gap-4 text-xs sm:text-sm text-mobile-secondary">
        <span className="flex items-center whitespace-nowrap">
          <span className="text-lg sm:text-2xl mr-1">🥛</span>
          <span className="font-medium text-mobile-primary">₹{milkman.pricePerLiter}/L</span>
        </span>
        <span className="flex items-center whitespace-nowrap">
          <Clock className="h-3 w-3 mr-1 text-secondary-green flex-shrink-0" />
          {formatTime(milkman.deliveryTimeStart)} - {formatTime(milkman.deliveryTimeEnd)}
        </span>
        <span className="flex items-center whitespace-nowrap">
          <Truck className="h-3 w-3 mr-1 text-accent-orange flex-shrink-0" />
          {getTranslatedText("Free delivery", language)}
        </span>
        {onContact && (
          <Button
            size="sm"
            variant="ghost"
            className="p-1 h-6 w-6 flex-shrink-0 touch-target"
            onClick={onContact}
          >
            <Phone className="h-3 w-3" />
          </Button>
        )}
      </div>
    </div>
  );
}

client/src/components/milkman-service-re.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Clock, DollarSign, User, MessageSquare, Send } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { queryClient } from "@/lib/queryClient";

export function MilkmanServiceRequests() {
  const [selectedRequest, setSelectedRequest] = useState<any>(null);
  const [quotingServices, setQuotingServices] = useState<any[]>([]);
  const [milkmanNotes, setMilkmanNotes] = useState("");
  const { toast } = useToast();

  const { data: serviceRequests, isLoading } = useQuery({
    queryKey: ["/api/service-requests/milkman"],
  });

  const provideQuoteMutation = useMutation({
    mutationFn: async (data: any) => {
      const response = await fetch(`/api/service-requests/${data.requestId}/quote`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          services: data.services,
          notes: data.notes,
        }),
      });
      if (!response.ok) throw new Error('Failed to provide quote');
      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Quote Sent!",
        description: "Your price quote has been sent to the customer.",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/service-requests/milkman"] });
      setSelectedRequest(null);
      setQuotingServices([]);
      setMilkmanNotes("");
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const openQuoteDialog = (request: any) => {
    setSelectedRequest(request);
    setQuotingServices(request.services.map((service: any) => ({
      ...service,
      quotedPrice: service.price || "",
    })));
    setMilkmanNotes("");
  };

  const updateQuotedPrice = (serviceIndex: number, price: string) => {
    setQuotingServices(prev => 
      prev.map((service, index) => 
        index === serviceIndex ? { ...service, quotedPrice: price } : service
      )
    );
  };

  const handleSubmitQuote = () => {
    // Validate all services have quoted prices
    const invalidServices = quotingServices.filter(service => !service.quotedPrice || parseFloat(service.quotedPrice) <= 0);
    if (invalidServices.length > 0) {
      toast({
        title: "Missing Prices",
        description: "Please provide valid prices for all services.",
        variant: "destructive",
      });
      return;
    }

    provideQuoteMutation.mutate({
      requestId: selectedRequest.id,
      services: quotingServices,
      notes: milkmanNotes,
    });
  };

  const calculateTotal = (services: any[]) => {
    return services.reduce((total, service) => {
      const price = parseFloat(service.quotedPrice || 0);
      const quantity = service.requestedQuantity || 1;
      return total + (price * quantity);
    }, 0);
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'pending':
        return <Badge variant="secondary" className="flex items-center gap-1">
          <Clock className="h-3 w-3" />
          Pending Response
        </Badge>;
      case 'quoted':
        return <Badge className="flex items-center gap-1">
          <DollarSign className="h-3 w-3" />
          Quote Sent
        </Badge>;
      case 'accepted':
        return <Badge variant="default" className="flex items-center gap-1 bg-green-600">
          Accepted
        </Badge>;
      case 'rejected':
        return <Badge variant="destructive" className="flex items-center gap-1">
          Rejected
        </Badge>;
      default:
        return <Badge variant="secondary">{status}</Badge>;
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin w-8 h-8 border-4 border-primary border-t-transparent rounded-full" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-semibold">Service Requests</h2>
        <Badge variant="outline">
          {serviceRequests?.filter((r: any) => r.status === 'pending').length || 0} Pending
        </Badge>
      </div>

      {!serviceRequests || serviceRequests.length === 0 ? (
        <Card>
          <CardContent className="p-8 text-center">
            <MessageSquare className="h-12 w-12 mx-auto text-gray-400 mb-4" />
            <h3 className="text-lg font-semibold mb-2">No Service Requests</h3>
            <p className="text-gray-600">
              You haven't received any service requests yet. Customers will be able to request custom pricing for your services.
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {serviceRequests.map((request: any) => (
            <Card key={request.id}>
              <CardHeader>
                <div className="flex justify-between items-start">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center">
                      <User className="h-5 w-5 text-blue-600" />
                    </div>
                    <div>
                      <CardTitle className="text-lg">
                        Service Request #{request.id}
                      </CardTitle>
                      <p className="text-sm text-gray-600">
                        From customer • {new Date(request.createdAt).toLocaleDateString()}
                      </p>
                    </div>
                  </div>
                  {getStatusBadge(request.status)}
                </div>
              </CardHeader>
              <CardContent className="space-y-4">
                {/* Services */}
                <div>
                  <h4 className="font-semibold mb-2">Requested Services:</h4>
                  <div className="space-y-2">
                    {request.services.map((service: any, index: number) => (
                      <div key={index} className="flex justify-between items-center p-3 bg-gray-50 rounded">
                        <div>
                          <span className="font-medium">{service.name}</span>
                          <span className="text-sm text-gray-600 ml-2">
                            × {service.requestedQuantity}
                          </span>
                        </div>
                        {service.quotedPrice && (
                          <div className="text-right">
                            <div className="font-semibold">
                              ₹{service.quotedPrice} {service.unit}
                            </div>
                            <div className="text-sm text-gray-600">
                              Total: ₹{(parseFloat(service.quotedPrice) * service.requestedQuantity).toFixed(2)}
                            </div>
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </div>

                {/* Customer Notes */}
                {request.customerNotes && (
                  <div>
                    <h4 className="font-semibold mb-2">Customer Notes:</h4>
                    <p className="text-sm text-gray-600 p-3 bg-gray-50 rounded">
                      {request.customerNotes}
                    </p>
                  </div>
                )}

                {/* Milkman Response */}
                {request.milkmanNotes && (
                  <div>
                    <h4 className="font-semibold mb-2">Your Response:</h4>
                    <p className="text-sm text-gray-600 p-3 bg-blue-50 rounded">
                      {request.milkmanNotes}
                    </p>
                  </div>
                )}

                {/* Actions */}
                <div className="flex gap-3 pt-4 border-t">
                  {request.status === 'pending' && (
                    <Dialog>
                      <DialogTrigger asChild>
                        <Button onClick={() => openQuoteDialog(request)}>
                          <DollarSign className="h-4 w-4 mr-2" />
                          Provide Quote
                        </Button>
                      </DialogTrigger>
                      <DialogContent className="max-w-2xl">
                        <DialogHeader>
                          <DialogTitle>Provide Price Quote</DialogTitle>
                        </DialogHeader>
                        <div className="space-y-4">
                          <div>
                            <Label className="text-base font-semibold mb-3 block">
                              Set Prices for Services
                            </Label>
                            <div className="space-y-3">
                              {quotingServices.map((service, index) => (
                                <div key={index} className="flex items-center gap-4 p-3 border rounded">
                                  <div className="flex-1">
                                    <div className="font-medium">{service.name}</div>
                                    <div className="text-sm text-gray-500">
                                      Quantity: {service.requestedQuantity} {service.unit}
                                    </div>
                                  </div>
                                  <div className="flex items-center gap-2">
                                    <Label htmlFor={`price-${index}`}>₹</Label>
                                    <Input
                                      id={`price-${index}`}
                                      type="number"
                                      step="0.01"
                                      placeholder="Price per unit"
                                      value={service.quotedPrice}
                                      onChange={(e) => updateQuotedPrice(index, e.target.value)}
                                      className="w-24"
                                    />
                                    <span className="text-sm text-gray-500">/{service.unit}</span>
                                  </div>
                                </div>
                              ))}
                            </div>
                          </div>

                          <div>
                            <Label htmlFor="notes" className="text-base font-semibold mb-2 block">
                              Additional Notes (Optional)
                            </Label>
                            <Textarea
                              id="notes"
                              placeholder="Any additional information about the quote..."
                              value={milkmanNotes}
                              onChange={(e) => setMilkmanNotes(e.target.value)}
                              className="min-h-[100px]"
                            />
                          </div>

                          <div className="p-4 bg-blue-50 rounded-lg">
                            <div className="flex justify-between items-center">
                              <span className="text-lg font-semibold">Total Quote:</span>
                              <span className="text-xl font-bold text-blue-600">
                                ₹{calculateTotal(quotingServices).toFixed(2)}
                              </span>
                            </div>
                          </div>

                          <div className="flex gap-3">
                            <Button
                              onClick={handleSubmitQuote}
                              disabled={provideQuoteMutation.isPending}
                              className="flex-1"
                            >
                              <Send className="h-4 w-4 mr-2" />
                              {provideQuoteMutation.isPending ? "Sending..." : "Send Quote"}
                            </Button>
                          </div>
                        </div>
                      </DialogContent>
                    </Dialog>
                  )}
                  {request.status === 'quoted' && (
                    <div className="text-sm text-gray-600">
                      Quote sent • Total: ₹{calculateTotal(request.services).toFixed(2)}
                    </div>
                  )}
                  {request.status === 'accepted' && (
                    <Badge variant="default" className="bg-green-600">
                      Order Accepted • ₹{calculateTotal(request.services).toFixed(2)}
                    </Badge>
                  )}
                  {request.status === 'rejected' && (
                    <Badge variant="destructive">
                      Quote Rejected
                    </Badge>
                  )}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

