// API configuration for connecting to external backend
import { API_BASE_URL } from "./queryClient";

export interface APIResponse<T = any> {
  success: boolean;
  data?: T;
  message?: string;
  error?: string;
}

// Test backend connection and available endpoints
export async function testBackendConnection(): Promise<{
  isConnected: boolean;
  availableEndpoints: string[];
  serverInfo: any;
}> {
  try {
    // Test basic connection
    const response = await fetch(API_BASE_URL, { 
      method: "GET",
      mode: "cors",
      credentials: "include"
    });

    const data = await response.json();

    return {
      isConnected: true,
      availableEndpoints: [],
      serverInfo: data
    };
  } catch (error) {
    console.error("Backend connection failed:", error);
    return {
      isConnected: false,
      availableEndpoints: [],
      serverInfo: null
    };
  }
}

// Flexible authentication API that adapts to backend structure
export class AuthAPI {
  private baseUrl: string;

  constructor(baseUrl: string = API_BASE_URL) {
    this.baseUrl = baseUrl;
  }

  async sendOTP(phone: string): Promise<APIResponse> {
    // Your backend expects 10-digit phone number without country code
    const cleanPhone = phone.replace(/[^0-9]/g, '').replace(/^\+?91/, ''); // Remove +91 prefix if present

    // Validate Indian mobile number format
    if (!/^[6-9][0-9]{9}$/.test(cleanPhone)) {
      throw new Error("Please enter a valid 10-digit Indian mobile number starting with 6, 7, 8, or 9");
    }

    console.log(`Attempting to send OTP to: ${cleanPhone} (from ${phone})`);
    console.log(`Backend URL: ${this.baseUrl}`);

    // Your backend has the /api/auth/send-otp endpoint working
    const endpoint = "/api/auth/send-otp";

    try {
      const fullUrl = `${this.baseUrl}${endpoint}`;
      console.log(`Trying endpoint: ${fullUrl}`);

      const response = await fetch(fullUrl, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Accept": "application/json"
        },
        body: JSON.stringify({ phone: cleanPhone }), // Send 10-digit number
        mode: "cors",
        credentials: "omit", // Try without credentials first to avoid preflight issues
        cache: "no-cache"
      });

      console.log(`Response status for ${endpoint}:`, response.status, response.statusText);

      if (response.ok) {
        const data = await response.json();
        console.log(`Success response from ${endpoint}:`, data);
        return {
          success: true,
          data,
          message: "OTP sent successfully"
        };
      } else {
        let errorData;
        try {
          errorData = await response.json();
        } catch (e) {
          const errorText = await response.text();
          errorData = { message: errorText };
        }

        console.log(`Error response from ${endpoint}:`, errorData);

        // Handle validation errors from backend
        if (response.status === 400 && errorData.errors) {
          const errorMsg = errorData.errors.map((err: any) => err.msg).join(', ');
          throw new Error(errorMsg);
        }

        // Handle server errors with clear messaging
        if (response.status === 500 && errorData.message === "Server error while sending OTP") {
          throw new Error("Backend OTP service not configured. The backend received the request but the SMS/OTP service needs to be set up. Please configure your OTP service (SMS provider, etc.) in the backend.");
        }

        throw new Error(errorData.message || `HTTP ${response.status}: ${response.statusText}`);
      }
    } catch (error: any) {
      console.log(`Network error for ${endpoint}:`, error);
      console.log(`Error details:`, {
        name: error.name,
        message: error.message,
        stack: error.stack,
        cause: error.cause
      });

      // Provide more specific error messaging
      if (error.name === 'TypeError' && error.message.includes('Failed to fetch')) {
        throw new Error("Network connection failed. The Replit environment cannot reach your external backend server. This might be due to network restrictions or firewall settings on either side. Your backend is running correctly, but there's a connectivity issue between Replit and your backend server.");
      } else if (error.message.includes('CORS')) {
        throw new Error("Cross-origin request blocked. Backend may need CORS configuration.");
      } else if (error.name === 'TypeError') {
        throw new Error(`Network request failed: ${error.message}`);
      }

      throw error;
    }
  }

  async verifyOTP(phone: string, otp: string): Promise<APIResponse> {
    // Your backend expects 10-digit phone number without country code
    const cleanPhone = phone.replace(/[^0-9]/g, '').replace(/^\+?91/, ''); // Remove +91 prefix if present

    console.log(`Attempting to verify OTP for: ${cleanPhone} with OTP: ${otp}`);
    console.log(`Backend URL: ${this.baseUrl}`);

    const endpoint = "/api/auth/verify-otp";

    try {
      const response = await fetch(`${this.baseUrl}${endpoint}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Accept": "application/json"
        },
        body: JSON.stringify({ phone: cleanPhone, otp }), // Send 10-digit number
        mode: "cors",
        credentials: "omit", // Try without credentials first to avoid preflight issues
        cache: "no-cache"
      });

      console.log(`Verify OTP response status:`, response.status, response.statusText);

      if (response.ok) {
        const data = await response.json();
        console.log(`Verify OTP success response:`, data);

        // The backend returns { success: true, message: "...", user: {...}, accessToken: "...", tokens?: {...} }
        // Handle both response formats: direct accessToken and tokens object
        let tokens;
        if (data.tokens) {
          tokens = data.tokens;
        } else if (data.accessToken) {
          tokens = {
            accessToken: data.accessToken,
            refreshToken: data.refreshToken
          };
        }

        return {
          success: true,
          data: {
            tokens: tokens,
            user: data.user
          },
          message: data.message || "OTP verified successfully"
        };
      } else {
        const errorData = await response.json();
        console.log(`Verify OTP error response:`, errorData);

        // Handle validation errors from backend
        if (response.status === 400 && errorData.errors) {
          const errorMsg = errorData.errors.map((err: any) => err.msg).join(', ');
          throw new Error(errorMsg);
        }

        throw new Error(errorData.message || `HTTP ${response.status}: ${response.statusText}`);
      }
    } catch (error: any) {
      console.log(`Verify OTP network error:`, error);
      throw error;
    }
  }

  async getUserProfile(): Promise<APIResponse> {
    const token = localStorage.getItem('accessToken');

    const endpoints = [
      "/api/auth/user",
      "/auth/user",
      "/user",
      "/api/user",
      "/profile"
    ];

    for (const endpoint of endpoints) {
      try {
        const response = await fetch(`${this.baseUrl}${endpoint}`, {
          headers: {
            ...(token ? { "Authorization": `Bearer ${token}` } : {}),
          },
          mode: "cors",
          credentials: "include"
        });

        if (response.ok) {
          const data = await response.json();
          return {
            success: true,
            data,
            message: "User profile retrieved"
          };
        }
      } catch (error) {
        console.log(`Endpoint ${endpoint} failed:`, error);
        continue;
      }
    }

    return {
      success: false,
      message: "No working user profile endpoint found"
    };
  }

  async logout(): Promise<APIResponse> {
    const token = localStorage.getItem('accessToken');

    const endpoints = [
      "/api/auth/logout",
      "/auth/logout",
      "/logout",
      "/api/logout"
    ];

    for (const endpoint of endpoints) {
      try {
        const response = await fetch(`${this.baseUrl}${endpoint}`, {
          method: "POST",
          headers: {
            ...(token ? { "Authorization": `Bearer ${token}` } : {}),
          },
          mode: "cors",
          credentials: "include"
        });

        if (response.ok) {
          const data = await response.json();
          return {
            success: true,
            data,
            message: "Logged out successfully"
          };
        }
      } catch (error) {
        console.log(`Endpoint ${endpoint} failed:`, error);
        continue;
      }
    }

    return {
      success: false,
      message: "Logout endpoint not found, clearing local storage"
    };
  }
}

export const authAPI = new AuthAPI();

