  const sendMessageMutation = useMutation({
    mutationFn: async (messageData: any) => {
      return apiRequest("/api/chat/send", "POST", messageData);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/chat/messages"] });
      setNewMessage("");
