import { useEffect, useState } from 'react';
import { useLocation } from 'wouter';
import { useAuth } from './useAuth';
import { apiRequest } from '@/lib/queryClient';

type AppLaunchState = 'loading' | 'login' | 'profile_setup' | 'dashboard';

export function useAppLaunch() {
  const [, setLocation] = useLocation();
  const { isAuthenticated, isLoading: authLoading, user } = useAuth();
  const [launchState, setLaunchState] = useState<AppLaunchState>('loading');

  useEffect(() => {
    const handleAppLaunch = async () => {
      console.log('🚀 App Launch Check:', { isAuthenticated, authLoading, user });

      // Wait for auth to finish loading
      if (authLoading) {
        setLaunchState('loading');
        return;
      }

      // If not authenticated, show login
      if (!isAuthenticated) {
        console.log('📱 User not authenticated, redirecting to onboarding');
        setLaunchState('login');
        setLocation('/mobile-onboarding');
        return;
      }

      // If authenticated, check profile completion
      try {
        console.log('✅ User authenticated, checking profile completion');

        // Check if user has selected a type
        if (!user?.userType) {
          console.log('👤 User has no type selected, showing type selection');
          setLaunchState('profile_setup');
          setLocation('/user-type-selection');
          return;
        }

        // Check if profile is complete
        const profileResponse = await apiRequest('/api/customers/profile', 'GET');

        if (profileResponse.ok) {
          const profileData = await profileResponse.json();

          // If profile exists and has required fields, go to dashboard
          if (profileData && profileData.name && profileData.address) {
            console.log('✅ Profile complete, redirecting to dashboard');
            setLaunchState('dashboard');
            setLocation('/customer');
          } else {
            console.log('📝 Profile incomplete, redirecting to profile setup');
            setLaunchState('profile_setup');
            setLocation('/profile-setup');
          }
        } else {
          // Profile doesn't exist, go to profile setup
          console.log('📝 No profile found, redirecting to profile setup');
          setLaunchState('profile_setup');
          setLocation('/profile-setup');
        }
      } catch (error) {
        console.error('❌ Error checking profile:', error);
        // On error, assume profile needs to be completed
        setLaunchState('profile_setup');
        setLocation('/profile-setup');
      }
    };

    handleAppLaunch();
  }, [isAuthenticated, authLoading, user, setLocation]);

  return {
    launchState,
    isReady: launchState !== 'loading'
  };
}

