import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { useLocation } from "wouter";
import { Loader2, Phone, Shield, User, MapPin } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { useAuth } from "@/hooks/useAuth";

import logoImage from "@assets/Flat vector logo with milk jug icon_1755535750764.png";

type OnboardingStep = "phone" | "otp" | "profile" | "dashboard";

export default function MobileOnboarding() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const { isAuthenticated, user } = useAuth();

  const [step, setStep] = useState<OnboardingStep>("phone");
  const [isLoading, setIsLoading] = useState(false);

  // Phone step
  const [phone, setPhone] = useState("");

  // OTP step
  const [otp, setOtp] = useState("");
  const [otpTimer, setOtpTimer] = useState(0);

  // Profile step
  const [profile, setProfile] = useState({
    name: "",
    address: "",
    city: "",
    pincode: ""
  });

  // Check if user is already authenticated and has profile
  useEffect(() => {
    if (isAuthenticated && user?.userType) {
      console.log('✅ User already authenticated with profile, redirecting to dashboard');
      setLocation('/customer');
    }
  }, [isAuthenticated, user, setLocation]);

  // OTP timer countdown
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (step === "otp" && otpTimer > 0) {
      interval = setInterval(() => {
        setOtpTimer((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [step, otpTimer]);

  const formatPhoneNumber = (value: string) => {
    const cleaned = value.replace(/\D/g, '');
    if (cleaned.length <= 5) {
      return cleaned;
    } else if (cleaned.length <= 10) {
      return `${cleaned.slice(0, 5)} ${cleaned.slice(5)}`;
    } else {
      return `${cleaned.slice(0, 5)} ${cleaned.slice(5, 10)}`;
    }
  };

  const handleSendOTP = async () => {
    if (!phone || phone.replace(/\s/g, '').length !== 10) {
      toast({
        title: "Invalid Phone Number",
        description: "Please enter a valid 10-digit phone number",
        variant: "destructive",
      });
      return;
    }

    setIsLoading(true);
    try {
      const cleanPhone = phone.replace(/\s/g, '');
      const response = await fetch('/api/auth/send-otp', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ phone: cleanPhone }),
      });

      const data = await response.json();

      if (data.success) {
        toast({
          title: "OTP Sent",
          description: "Enter the verification code sent to your mobile number",
        });
        setStep("otp");
        setOtpTimer(300); // 5 minutes
      } else {
        throw new Error(data.message || 'Failed to send OTP');
      }
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message || "Failed to send OTP. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleVerifyOTP = async () => {
    if (!otp || otp.length !== 6) {
      toast({
        title: "Invalid OTP",
        description: "Please enter the 6-digit verification code",
        variant: "destructive",
      });
      return;
    }

    setIsLoading(true);
    try {
      const cleanPhone = phone.replace(/\s/g, '');
      const response = await fetch('/api/auth/verify-otp', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ phone: cleanPhone, otp }),
      });

      const data = await response.json();

      if (data.success) {
        // Store JWT token
        if (data.tokens?.accessToken) {
          localStorage.setItem('accessToken', data.tokens.accessToken);
          localStorage.setItem('refreshToken', data.tokens.refreshToken);
        }

        toast({
          title: "Verification Successful",
          description: "Now complete your profile to get started",
        });
        setStep("profile");
      } else {
        throw new Error(data.message || 'Invalid OTP');
      }
    } catch (error: any) {
      toast({
        title: "Verification Failed",
        description: error.message || "Invalid OTP. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleCompleteProfile = async () => {
    if (!profile.name || !profile.address || !profile.city || !profile.pincode) {
      toast({
        title: "Incomplete Profile",
        description: "Please fill in all required fields",
        variant: "destructive",
      });
      return;
    }

    setIsLoading(true);
    try {
      // Create customer profile
      await apiRequest('/api/customers', 'POST', {
        name: profile.name,
        address: `${profile.address}, ${profile.city} - ${profile.pincode}`,
        addressDetails: {
          streetAddress: profile.address,
          city: profile.city,
          pincode: profile.pincode
        }
      });

      toast({
        title: "Profile Created",
        description: "Welcome to Doodhwala! Your account is ready.",
      });

      // Redirect to dashboard
      setTimeout(() => {
        setLocation('/customer');
      }, 1500);

    } catch (error: any) {
      toast({
        title: "Profile Creation Failed",
        description: error.message || "Failed to create profile. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const renderPhoneStep = () => (
    <Card className="w-full max-w-md mx-auto">
      <CardHeader className="text-center">
        <div className="mx-auto mb-4 w-16 h-16 rounded-full bg-blue-100 flex items-center justify-center">
          <Phone className="w-8 h-8 text-blue-600" />
        </div>
        <CardTitle className="text-2xl font-bold">Enter Mobile Number</CardTitle>
        <p className="text-gray-600">We'll send you a verification code</p>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="space-y-2">
          <Label htmlFor="phone">Mobile Number</Label>
          <div className="flex">
            <div className="flex items-center px-3 bg-gray-100 border border-r-0 rounded-l-md">
              <span className="text-sm text-gray-600">+91</span>
            </div>
            <Input
              id="phone"
              type="tel"
              placeholder="98765 43210"
              value={phone}
              onChange={(e) => setPhone(formatPhoneNumber(e.target.value))}
              className="rounded-l-none"
              maxLength={11}
            />
          </div>
        </div>
        <Button 
          onClick={handleSendOTP} 
          disabled={isLoading || !phone || phone.replace(/\s/g, '').length !== 10}
          className="w-full"
        >
          {isLoading ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              Sending OTP...
            </>
          ) : (
            'Send OTP'
          )}
        </Button>
        <p className="text-xs text-center text-gray-500">
          For testing, use any valid 10-digit number. OTP will be sent via SMS.
        </p>
      </CardContent>
    </Card>
  );

  const renderOTPStep = () => (
    <Card className="w-full max-w-md mx-auto">
      <CardHeader className="text-center">
        <div className="mx-auto mb-4 w-16 h-16 rounded-full bg-green-100 flex items-center justify-center">
          <Shield className="w-8 h-8 text-green-600" />
        </div>
        <CardTitle className="text-2xl font-bold">Enter Verification Code</CardTitle>
        <p className="text-gray-600">Code sent to +91 {phone}</p>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="space-y-2">
          <Label htmlFor="otp">6-Digit Code</Label>
          <Input
            id="otp"
            type="text"
            placeholder="123456"
            value={otp}
            onChange={(e) => setOtp(e.target.value.replace(/\D/g, '').slice(0, 6))}
            className="text-center text-lg tracking-widest"
            maxLength={6}
          />
        </div>
        <Button 
          onClick={handleVerifyOTP} 
          disabled={isLoading || otp.length !== 6}
          className="w-full"
        >
          {isLoading ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              Verifying...
            </>
          ) : (
            'Verify OTP'
          )}
        </Button>

        {otpTimer > 0 ? (
          <p className="text-center text-sm text-gray-500">
            Resend OTP in {Math.floor(otpTimer / 60)}:{(otpTimer % 60).toString().padStart(2, '0')}
          </p>
        ) : (
          <Button variant="outline" onClick={handleSendOTP} className="w-full" disabled={isLoading}>
            Resend OTP
          </Button>
        )}

        <div className="bg-blue-50 p-3 rounded-md">
          <p className="text-xs text-blue-800 font-medium">For Testing:</p>
          <p className="text-xs text-blue-600">Use OTP: <strong>1234</strong></p>
        </div>

        <Button variant="ghost" onClick={() => setStep("phone")} className="w-full">
          Change Phone Number
        </Button>
      </CardContent>
    </Card>
  );

  const renderProfileStep = () => (
    <Card className="w-full max-w-md mx-auto">
      <CardHeader className="text-center">
        <div className="mx-auto mb-4 w-16 h-16 rounded-full bg-purple-100 flex items-center justify-center">
          <User className="w-8 h-8 text-purple-600" />
        </div>
        <CardTitle className="text-2xl font-bold">Complete Your Profile</CardTitle>
        <p className="text-gray-600">Help us serve you better</p>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="space-y-2">
          <Label htmlFor="name">Full Name *</Label>
          <Input
            id="name"
            placeholder="Enter your full name"
            value={profile.name}
            onChange={(e) => setProfile(prev => ({ ...prev, name: e.target.value }))}
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="address">Street Address *</Label>
          <Textarea
            id="address"
            placeholder="House/Flat No., Building Name, Street"
            value={profile.address}
            onChange={(e) => setProfile(prev => ({ ...prev, address: e.target.value }))}
            rows={2}
          />
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-2">
            <Label htmlFor="city">City *</Label>
            <Input
              id="city"
              placeholder="City"
              value={profile.city}
              onChange={(e) => setProfile(prev => ({ ...prev, city: e.target.value }))}
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="pincode">Pincode *</Label>
            <Input
              id="pincode"
              placeholder="400001"
              value={profile.pincode}
              onChange={(e) => setProfile(prev => ({ ...prev, pincode: e.target.value.replace(/\D/g, '').slice(0, 6) }))}
            />
          </div>
        </div>

        <Button 
          onClick={handleCompleteProfile} 
          disabled={isLoading || !profile.name || !profile.address || !profile.city || !profile.pincode}
          className="w-full"
        >
          {isLoading ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              Creating Profile...
            </>
          ) : (
            'Complete Setup'
          )}
        </Button>
      </CardContent>
    </Card>
  );

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex flex-col items-center justify-center p-4">
      {/* Header */}
      <div className="text-center mb-8">
        <img src={logoImage} alt="Doodhwala" className="w-20 h-20 mx-auto mb-4" />
        <h1 className="text-3xl font-bold text-gray-900 mb-2">Welcome to Doodhwala</h1>
        <p className="text-gray-600">Fresh milk delivered to your doorstep</p>
      </div>

      {/* Progress Indicator */}
      <div className="flex items-center space-x-2 mb-8">
        <div className={`w-3 h-3 rounded-full ${step === "phone" ? "bg-blue-600" : "bg-blue-300"}`}></div>
        <div className={`w-8 h-1 ${step !== "phone" ? "bg-blue-600" : "bg-gray-300"}`}></div>
        <div className={`w-3 h-3 rounded-full ${step === "otp" ? "bg-blue-600" : step === "profile" ? "bg-blue-300" : "bg-gray-300"}`}></div>
        <div className={`w-8 h-1 ${step === "profile" ? "bg-blue-600" : "bg-gray-300"}`}></div>
        <div className={`w-3 h-3 rounded-full ${step === "profile" ? "bg-blue-600" : "bg-gray-300"}`}></div>
      </div>

      {/* Onboarding Steps */}
      {step === "phone" && renderPhoneStep()}
      {step === "otp" && renderOTPStep()}
      {step === "profile" && renderProfileStep()}
    </div>
  );
}

client/src/pages/milkman-profile-setup.t.content:
import React, { useState, useEffect } from "react";
import { useLocation } from "wouter";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { 
  MapPin, 
  Plus, 
  X, 
  Clock, 
  Trash2, 
  IndianRupee,
  Loader2 
} from "lucide-react";
import { Navbar } from "@/components/navbar";
import newLogoImage from "@assets/Flat vector logo with milk jug icon_1756714038327.png";

// Types
interface AddressDetails {
  houseNumber: string;
  buildingName: string;
  streetName: string;
  area: string;
  landmark: string;
  city: string;
  state: string;
  pincode: string;
  country: string;
}

interface DairyItem {
  name: string;
  unit: string;
  price: string;
  isCustom?: boolean;
}

interface DeliverySlot {
  id: string;
  name: string;
  startTime: string;
  endTime: string;
  isActive: boolean;
}

export default function MilkmanProfileSetup() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGettingLocation, setIsGettingLocation] = useState(false);
  const [serviceAddress, setServiceAddress] = useState("");
  const [showCustomItemForm, setShowCustomItemForm] = useState(false);
  const [showSlotForm, setShowSlotForm] = useState(false);
  const [editingSlot, setEditingSlot] = useState<number | null>(null);

  // Address details state
  const [addressDetails, setAddressDetails] = useState<AddressDetails>({
    houseNumber: "",
    buildingName: "",
    streetName: "",
    area: "",
    landmark: "",
    city: "",
    state: "",
    pincode: "",
    country: "India"
  });

  // Dairy items state
  const [dairyItems, setDairyItems] = useState<DairyItem[]>([
    { name: "Fresh Milk", unit: "per litre", price: "" },
    { name: "Buffalo Milk", unit: "per litre", price: "" },
    { name: "Toned Milk", unit: "per litre", price: "" },
    { name: "Double Toned Milk", unit: "per litre", price: "" },
    { name: "Skimmed Milk", unit: "per litre", price: "" }
  ]);

  const [newCustomItem, setNewCustomItem] = useState({
    name: "",
    unit: "",
    price: ""
  });

  // Delivery slots state
  const [deliverySlots, setDeliverySlots] = useState<DeliverySlot[]>([
    { id: "1", name: "Morning", startTime: "06:00", endTime: "09:00", isActive: true },
    { id: "2", name: "Evening", startTime: "17:00", endTime: "20:00", isActive: true }
  ]);

  const [newSlot, setNewSlot] = useState({
    name: "",
    startTime: "06:00",
    endTime: "09:00"
  });

  // Auto-generate complete address when details change
  useEffect(() => {
    const parts = [
      addressDetails.houseNumber,
      addressDetails.buildingName,
      addressDetails.streetName,
      addressDetails.area,
      addressDetails.landmark,
      addressDetails.city,
      addressDetails.state,
      addressDetails.pincode,
      addressDetails.country
    ].filter(part => part.trim());

    setServiceAddress(parts.join(", "));
  }, [addressDetails]);

  const getCurrentLocation = async () => {
    setIsGettingLocation(true);
    try {
      if (!navigator.geolocation) {
        throw new Error("Geolocation is not supported by this browser");
      }

      const position = await new Promise<GeolocationPosition>((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, {
          enableHighAccuracy: true,
          timeout: 10000,
          maximumAge: 0
        });
      });

      const { latitude, longitude } = position.coords;

      // Reverse geocoding using Nominatim API
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&addressdetails=1`
      );

      if (!response.ok) {
        throw new Error("Failed to get address from coordinates");
      }

      const data = await response.json();
      const address = data.address || {};

      setAddressDetails({
        houseNumber: address.house_number || "",
        buildingName: address.building || "",
        streetName: address.road || "",
        area: address.suburb || address.neighbourhood || "",
        landmark: address.amenity || "",
        city: address.city || address.town || address.village || "",
        state: address.state || "",
        pincode: address.postcode || "",
        country: address.country || "India"
      });

      toast({
        title: "Location detected",
        description: "Address details have been filled automatically"
      });
    } catch (error) {
      console.error("Error getting location:", error);
      toast({
        title: "Location Error",
        description: "Could not get your current location. Please enter manually.",
        variant: "destructive"
      });
    } finally {
      setIsGettingLocation(false);
    }
  };

  const addCustomItem = () => {
    if (newCustomItem.name.trim() && newCustomItem.unit.trim()) {
      setDairyItems([...dairyItems, { 
        ...newCustomItem, 
        isCustom: true 
      }]);
      setNewCustomItem({ name: "", unit: "", price: "" });
      setShowCustomItemForm(false);
      toast({
        title: "Product added",
        description: `${newCustomItem.name} has been added to your product list`
      });
    }
  };

  const removeCustomItem = (index: number) => {
    const updatedItems = dairyItems.filter((_, i) => i !== index);
    setDairyItems(updatedItems);
    toast({
      title: "Product removed",
      description: "Custom product has been removed from your list"
    });
  };

  const updateDairyItemPrice = (index: number, price: string) => {
    const updatedItems = [...dairyItems];
    updatedItems[index].price = price;
    setDairyItems(updatedItems);
  };

  const addDeliverySlot = () => {
    if (newSlot.name.trim()) {
      const newId = (deliverySlots.length + 1).toString();
      setDeliverySlots([...deliverySlots, {
        id: newId,
        ...newSlot,
        isActive: true
      }]);
      setNewSlot({ name: "", startTime: "06:00", endTime: "09:00" });
      setShowSlotForm(false);
      setEditingSlot(null);
      toast({
        title: "Delivery slot added",
        description: `${newSlot.name} slot has been added to your schedule`
      });
    }
  };

  const editDeliverySlot = (slot: DeliverySlot) => {
    setNewSlot({
      name: slot.name,
      startTime: slot.startTime,
      endTime: slot.endTime
    });
    setEditingSlot(parseInt(slot.id));
    setShowSlotForm(true);
  };

  const updateDeliverySlot = () => {
    if (editingSlot !== null && newSlot.name.trim()) {
      const updatedSlots = deliverySlots.map(slot => 
        slot.id === editingSlot.toString() 
          ? { ...slot, ...newSlot }
          : slot
      );
      setDeliverySlots(updatedSlots);
      setNewSlot({ name: "", startTime: "06:00", endTime: "09:00" });
      setShowSlotForm(false);
      setEditingSlot(null);
      toast({
        title: "Delivery slot updated",
        description: "Your delivery slot has been updated successfully"
      });
    }
  };

  const removeDeliverySlot = (id: string) => {
    const updatedSlots = deliverySlots.filter(slot => slot.id !== id);
    setDeliverySlots(updatedSlots);
    toast({
      title: "Delivery slot removed",
      description: "The delivery slot has been removed from your schedule"
